const API_BASE_URL = "http://localhost:5000/api";
// const API_BASE_URL = "https://focusformsbackend.onrender.com/api";

interface ApiResponse<T> {
  success: boolean;
  message?: string;
  data?: T;
  errors?: string[];
}

class ApiError extends Error {
  constructor(public status: number, public response: any, message?: string) {
    super(message || "API Error");
    this.name = "ApiError";
  }
}

class ApiClient {
  private baseUrl: string;
  private token: string | null = null;

  constructor(baseUrl: string = API_BASE_URL) {
    this.baseUrl = baseUrl;
    this.token = localStorage.getItem("auth_token");
  }

  setToken(token: string) {
    this.token = token;
    localStorage.setItem("auth_token", token);
  }

  clearToken() {
    this.token = null;
    localStorage.removeItem("auth_token");
  }

  private async request<T>(
    endpoint: string,
    options: RequestInit = {}
  ): Promise<T> {
    const url = `${this.baseUrl}${endpoint}`;

    const headers: Record<string, string> = {
      "Content-Type": "application/json",
      ...(options.headers as Record<string, string>),
    };

    if (this.token) {
      headers.Authorization = `Bearer ${this.token}`;
    }

    const config: RequestInit = {
      ...options,
      headers,
    };

    try {
      const response = await fetch(url, config);
      const data: ApiResponse<T> = await response.json();

      if (!response.ok) {
        // Enhanced error message for validation errors
        let errorMessage = data.message || "Request failed";
        if (data.errors && Array.isArray(data.errors)) {
          const errorDetails = data.errors
            .map((err: any) =>
              typeof err === "string" ? err : `${err.field}: ${err.message}`
            )
            .join(", ");
          errorMessage = `${errorMessage}: ${errorDetails}`;
        }
        throw new ApiError(response.status, data, errorMessage);
      }

      if (!data.success) {
        let errorMessage = data.message || "Request failed";
        if (data.errors && Array.isArray(data.errors)) {
          const errorDetails = data.errors
            .map((err: any) =>
              typeof err === "string" ? err : `${err.field}: ${err.message}`
            )
            .join(", ");
          errorMessage = `${errorMessage}: ${errorDetails}`;
        }
        throw new ApiError(response.status, data, errorMessage);
      }

      return data.data as T;
    } catch (error) {
      if (error instanceof ApiError) {
        throw error;
      }
      throw new ApiError(500, null, "Network error or server unavailable");
    }
  }

  // Authentication
  async login(credentials: {
    email: string;
    password: string;
    tenantSlug?: string;
  }) {
    const data = await this.request<{ user: any; token: string; tenant?: any }>(
      "/auth/login",
      {
        method: "POST",
        body: JSON.stringify(credentials),
      }
    );

    this.setToken(data.token);
    return data;
  }

  async logout() {
    this.clearToken();
  }

  async getProfile() {
    return this.request<{ user: any }>("/auth/profile");
  }

  async changePassword(passwords: {
    currentPassword: string;
    newPassword: string;
  }) {
    return this.request("/auth/change-password", {
      method: "PUT",
      body: JSON.stringify(passwords),
    });
  }

  // Users
  async getUsers() {
    return this.request<{ users: any[]; total: number }>("/users");
  }

  async createUser(userData: any) {
    return this.request<{ user: any }>("/users", {
      method: "POST",
      body: JSON.stringify(userData),
    });
  }

  async updateUser(id: string, userData: any) {
    return this.request<{ user: any }>(`/users/${id}`, {
      method: "PUT",
      body: JSON.stringify(userData),
    });
  }

  async deleteUser(id: string) {
    return this.request(`/users/${id}`, {
      method: "DELETE",
    });
  }

  async resetUserPassword(id: string, newPassword: string) {
    return this.request(`/users/${id}/reset-password`, {
      method: "PUT",
      body: JSON.stringify({ newPassword }),
    });
  }

  // Forms
  async getForms() {
    return this.request<{ forms: any[] }>("/forms");
  }

  async getPublicForms(tenantSlug?: string) {
    const endpoint = tenantSlug
      ? `/forms/public/${tenantSlug}`
      : "/forms/public";
    return this.request<{ forms: any[] }>(endpoint);
  }

  async getForm(id: string) {
    return this.request<{ form: any }>(`/forms/${id}`);
  }

  async getFormById(id: string) {
    return this.request<{ form: any }>(`/forms/${id}`);
  }

  async getPublicForm(id: string, tenantSlug?: string) {
    const endpoint = tenantSlug
      ? `/forms/${id}/public/${tenantSlug}`
      : `/forms/${id}/public`;
    const url = `${this.baseUrl}${endpoint}`;

    const response = await fetch(url);
    const data: ApiResponse<{ form: any }> = await response.json();

    if (!response.ok) {
      throw new ApiError(response.status, data, data.message);
    }

    if (!data.success) {
      throw new ApiError(response.status, data, data.message);
    }

    return data.data;
  }

  async createForm(formData: any) {
    return this.request<{ form: any }>("/forms", {
      method: "POST",
      body: JSON.stringify(formData),
    });
  }

  async updateForm(id: string, formData: any) {
    return this.request<{ form: any }>(`/forms/${id}`, {
      method: "PUT",
      body: JSON.stringify(formData),
    });
  }

  async deleteForm(id: string) {
    return this.request(`/forms/${id}`, {
      method: "DELETE",
    });
  }

  async updateFormVisibility(id: string, isVisible: boolean) {
    return this.request(`/forms/${id}/visibility`, {
      method: "PATCH",
      body: JSON.stringify({ isVisible }),
    });
  }

  async updateFormActiveStatus(id: string, isActive: boolean) {
    return this.request(`/forms/${id}/active`, {
      method: "PATCH",
      body: JSON.stringify({ isActive }),
    });
  }

  async duplicateForm(id: string) {
    return this.request<{ form: any }>(`/forms/${id}/duplicate`, {
      method: "POST",
    });
  }

  // Child Form Management (Parent-Child Relationships)
  async linkChildForm(parentFormId: string, childFormId: string) {
    return this.request<{ parentForm: any; childForm: any }>(
      `/forms/${parentFormId}/child-forms`,
      {
        method: "POST",
        body: JSON.stringify({ childFormId }),
      }
    );
  }

  async unlinkChildForm(parentFormId: string, childFormId: string) {
    return this.request(`/forms/${parentFormId}/child-forms/${childFormId}`, {
      method: "DELETE",
    });
  }

  async getChildForms(parentFormId: string) {
    return this.request<{
      parentFormId: string;
      parentFormTitle: string;
      childForms: any[];
    }>(`/forms/${parentFormId}/child-forms`);
  }

  async reorderChildForms(parentFormId: string, childFormOrder: string[]) {
    return this.request(`/forms/${parentFormId}/child-forms/reorder`, {
      method: "PUT",
      body: JSON.stringify({ childFormOrder }),
    });
  }

  // Responses
  async getResponses() {
    return this.request<{ responses: any[]; pagination?: any }>(
      "/responses?limit=1000"
    );
  }

  async getFormResponses(formId: string) {
    return this.request<{ responses: any[] }>(`/responses/form/${formId}`);
  }

  async getResponse(id: string) {
    return this.request<{ response: any }>(`/responses/${id}`);
  }

  async createResponse(responseData: any) {
    return this.request<{ response: any }>("/responses", {
      method: "POST",
      body: JSON.stringify(responseData),
    });
  }

  async submitResponse(formId: string, responseData: any) {
    return this.request<{ response: any }>(`/responses/${formId}`, {
      method: "POST",
      body: JSON.stringify(responseData),
    });
  }

  async updateResponse(id: string, responseData: any) {
    return this.request<{ response: any }>(`/responses/${id}`, {
      method: "PUT",
      body: JSON.stringify(responseData),
    });
  }

  async deleteResponse(id: string) {
    return this.request(`/responses/${id}`, {
      method: "DELETE",
    });
  }

  async assignResponse(id: string, assignedTo: string) {
    return this.request(`/responses/${id}/assign`, {
      method: "PATCH",
      body: JSON.stringify({ assignedTo }),
    });
  }

  async exportFormResponses(formId: string, format: "excel" | "csv" = "excel") {
    const response = await fetch(
      `${this.baseUrl}/responses/form/${formId}/export?format=${format}`,
      {
        headers: {
          Authorization: `Bearer ${this.token}`,
        },
      }
    );

    if (!response.ok) {
      throw new ApiError(response.status, null, "Export failed");
    }

    return response.blob();
  }

  // Analytics
  async getDashboardAnalytics() {
    return this.request<any>("/analytics/dashboard");
  }

  async getFormAnalytics(formId: string) {
    return this.request<any>(`/analytics/form/${formId}`);
  }

  async getUserAnalytics() {
    return this.request<any>("/analytics/users");
  }

  // Roles
  async getRoles() {
    return this.request<{ roles: any[] }>("/roles");
  }

  async createRole(roleData: any) {
    return this.request<{ role: any }>("/roles", {
      method: "POST",
      body: JSON.stringify(roleData),
    });
  }

  async updateRole(id: string, roleData: any) {
    return this.request<{ role: any }>(`/roles/${id}`, {
      method: "PUT",
      body: JSON.stringify(roleData),
    });
  }

  async deleteRole(id: string) {
    return this.request(`/roles/${id}`, {
      method: "DELETE",
    });
  }

  async getAvailablePermissions() {
    return this.request<{ permissions: string[] }>("/roles/permissions");
  }

  async assignRole(userId: string, roleId: string) {
    return this.request("/roles/assign", {
      method: "POST",
      body: JSON.stringify({ userId, roleId }),
    });
  }

  async getUsersByRole(roleId: string) {
    return this.request<{ users: any[]; role: any; pagination: any }>(
      `/roles/${roleId}/users`
    );
  }

  // Files
  async uploadFile(file: File, category: string = "general") {
    const formData = new FormData();
    formData.append("file", file);
    formData.append("category", category);

    const response = await fetch(`${this.baseUrl}/files/upload`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${this.token}`,
      },
      body: formData,
    });

    const data: ApiResponse<any> = await response.json();

    if (!response.ok || !data.success) {
      throw new ApiError(response.status, data, data.message);
    }

    return data.data;
  }

  async getUserFiles() {
    return this.request<{ files: any[] }>("/files");
  }

  async deleteFile(id: string) {
    return this.request(`/files/${id}`, {
      method: "DELETE",
    });
  }

  getFileUrl(filename: string) {
    return `${this.baseUrl}/files/${filename}`;
  }

  // Profile
  async getUserProfile() {
    return this.request<{ profile: any }>("/profile");
  }

  async updateUserProfile(profileData: any) {
    return this.request<{ profile: any }>("/profile", {
      method: "PUT",
      body: JSON.stringify(profileData),
    });
  }

  async updateProfileSettings(settings: any) {
    return this.request<{ profile: any }>("/profile/settings", {
      method: "PATCH",
      body: JSON.stringify(settings),
    });
  }

  async uploadAvatar(file: File) {
    const formData = new FormData();
    formData.append("avatar", file);

    const response = await fetch(`${this.baseUrl}/profile/avatar`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${this.token}`,
      },
      body: formData,
    });

    const data: ApiResponse<any> = await response.json();

    if (!response.ok || !data.success) {
      throw new ApiError(response.status, data, data.message);
    }

    return data.data;
  }

  // Tenants (SuperAdmin only)
  async getTenants(search: string = "", status: string = "all") {
    return this.request<{ tenants: any[]; total: number }>(
      `/tenants?search=${search}&status=${status}`
    );
  }

  async createTenant(tenantData: any) {
    return this.request<{ tenant: any; admin: any }>("/tenants", {
      method: "POST",
      body: JSON.stringify(tenantData),
    });
  }

  async updateTenant(tenantId: string, tenantData: any) {
    return this.request<{ tenant: any; admin?: any }>(`/tenants/${tenantId}`, {
      method: "PUT",
      body: JSON.stringify(tenantData),
    });
  }

  async deleteTenant(tenantId: string) {
    return this.request(`/tenants/${tenantId}`, {
      method: "DELETE",
    });
  }

  async getTenantStats(tenantId: string) {
    return this.request<{ stats: any }>(`/tenants/${tenantId}/stats`);
  }

  async toggleTenantStatus(tenantId: string) {
    return this.request<{ tenant: any }>(`/tenants/${tenantId}/toggle-status`, {
      method: "PATCH",
    });
  }
}

// Create and export a singleton instance
export const apiClient = new ApiClient();
export { ApiError };
export type { ApiResponse };

// API service for Form with Follow-up Questions

export interface FollowUpConfig {
  hasFollowUp: boolean;
  required: boolean;
}

export interface FormWithFollowUpData {
  title: string;
  description: string;
  logoUrl?: string;
  imageUrl?: string;
  options: string[];
  followUpConfig: Record<string, FollowUpConfig>;
}

export interface ApiResponse<T> {
  success: boolean;
  message: string;
  data: T;
}

class FormWithFollowUpService {
  private baseUrl = "/api/forms";

  private getAuthHeaders(): HeadersInit {
    const token = localStorage.getItem("token");
    return {
      "Content-Type": "application/json",
      ...(token && { Authorization: `Bearer ${token}` }),
    };
  }

  private async handleResponse<T>(response: Response): Promise<ApiResponse<T>> {
    if (!response.ok) {
      const errorData = await response
        .json()
        .catch(() => ({ message: "Network error" }));
      throw new Error(
        errorData.message || `HTTP error! status: ${response.status}`
      );
    }
    return response.json();
  }

  /**
   * Create a new form with follow-up questions
   */
  async createFormWithFollowUp(
    formData: FormWithFollowUpData
  ): Promise<ApiResponse<any>> {
    const response = await fetch(`${this.baseUrl}/with-followup`, {
      method: "POST",
      headers: this.getAuthHeaders(),
      body: JSON.stringify(formData),
    });

    return this.handleResponse(response);
  }

  /**
   * Get form by ID
   */
  async getForm(id: string): Promise<ApiResponse<any>> {
    const response = await fetch(`${this.baseUrl}/${id}`, {
      headers: this.getAuthHeaders(),
    });

    return this.handleResponse(response);
  }

  /**
   * Get public form (no auth required)
   */
  async getPublicForm(id: string): Promise<ApiResponse<any>> {
    const response = await fetch(`${this.baseUrl}/${id}/public`);
    return this.handleResponse(response);
  }

  /**
   * Get follow-up configuration for a form
   */
  async getFollowUpConfig(formId: string): Promise<
    ApiResponse<{
      formId: string;
      title: string;
      followUpConfig: Record<string, FollowUpConfig>;
    }>
  > {
    const response = await fetch(`${this.baseUrl}/${formId}/followup-config`, {
      headers: this.getAuthHeaders(),
    });

    return this.handleResponse(response);
  }

  /**
   * Update follow-up configuration for a form
   */
  async updateFollowUpConfig(
    formId: string,
    followUpConfig: Record<string, FollowUpConfig>
  ): Promise<ApiResponse<any>> {
    const response = await fetch(`${this.baseUrl}/${formId}/followup-config`, {
      method: "PUT",
      headers: this.getAuthHeaders(),
      body: JSON.stringify({ followUpConfig }),
    });

    return this.handleResponse(response);
  }

  /**
   * Submit form response
   */
  async submitResponse(responseData: {
    questionId: string;
    answers: Record<string, any>;
    timestamp: string;
    parentResponseId?: string;
  }): Promise<ApiResponse<any>> {
    const response = await fetch("/api/responses", {
      method: "POST",
      headers: this.getAuthHeaders(),
      body: JSON.stringify(responseData),
    });

    return this.handleResponse(response);
  }

  /**
   * Get all forms (with pagination)
   */
  async getAllForms(params?: {
    page?: number;
    limit?: number;
    search?: string;
    isVisible?: boolean;
    createdBy?: string;
  }): Promise<ApiResponse<any>> {
    const searchParams = new URLSearchParams();

    if (params) {
      Object.entries(params).forEach(([key, value]) => {
        if (value !== undefined && value !== null) {
          searchParams.append(key, String(value));
        }
      });
    }

    const url = `${this.baseUrl}?${searchParams.toString()}`;
    const response = await fetch(url, {
      headers: this.getAuthHeaders(),
    });

    return this.handleResponse(response);
  }

  /**
   * Get public forms
   */
  async getPublicForms(): Promise<ApiResponse<any>> {
    const response = await fetch(`${this.baseUrl}/public`);
    return this.handleResponse(response);
  }

  /**
   * Update form
   */
  async updateForm(
    formId: string,
    updateData: Partial<FormWithFollowUpData>
  ): Promise<ApiResponse<any>> {
    const response = await fetch(`${this.baseUrl}/${formId}`, {
      method: "PUT",
      headers: this.getAuthHeaders(),
      body: JSON.stringify(updateData),
    });

    return this.handleResponse(response);
  }

  /**
   * Delete form
   */
  async deleteForm(formId: string): Promise<ApiResponse<any>> {
    const response = await fetch(`${this.baseUrl}/${formId}`, {
      method: "DELETE",
      headers: this.getAuthHeaders(),
    });

    return this.handleResponse(response);
  }

  /**
   * Update form visibility
   */
  async updateFormVisibility(
    formId: string,
    isVisible: boolean
  ): Promise<ApiResponse<any>> {
    const response = await fetch(`${this.baseUrl}/${formId}/visibility`, {
      method: "PATCH",
      headers: this.getAuthHeaders(),
      body: JSON.stringify({ isVisible }),
    });

    return this.handleResponse(response);
  }

  /**
   * Duplicate form
   */
  async duplicateForm(formId: string): Promise<ApiResponse<any>> {
    const response = await fetch(`${this.baseUrl}/${formId}/duplicate`, {
      method: "POST",
      headers: this.getAuthHeaders(),
    });

    return this.handleResponse(response);
  }

  /**
   * Get form analytics
   */
  async getFormAnalytics(
    formId: string,
    period: "7d" | "30d" | "90d" = "30d"
  ): Promise<ApiResponse<any>> {
    const response = await fetch(
      `${this.baseUrl}/${formId}/analytics?period=${period}`,
      {
        headers: this.getAuthHeaders(),
      }
    );

    return this.handleResponse(response);
  }

  /**
   * Get form responses
   */
  async getFormResponses(
    formId: string,
    params?: {
      page?: number;
      limit?: number;
      status?: "pending" | "verified" | "rejected";
      assignedTo?: string;
    }
  ): Promise<ApiResponse<any>> {
    const searchParams = new URLSearchParams();
    searchParams.append("questionId", formId);

    if (params) {
      Object.entries(params).forEach(([key, value]) => {
        if (value !== undefined && value !== null) {
          searchParams.append(key, String(value));
        }
      });
    }

    const response = await fetch(`/api/responses?${searchParams.toString()}`, {
      headers: this.getAuthHeaders(),
    });

    return this.handleResponse(response);
  }

  /**
   * Validate form data before submission
   */
  validateFormData(formData: FormWithFollowUpData): {
    isValid: boolean;
    errors: string[];
  } {
    const errors: string[] = [];

    if (!formData.title.trim()) {
      errors.push("Form title is required");
    }

    if (!formData.description.trim()) {
      errors.push("Form description is required");
    }

    if (formData.options.length < 2) {
      errors.push("Form must have at least 2 options");
    }

    if (formData.options.some((option) => !option.trim())) {
      errors.push("All options must have text");
    }

    // Check for duplicate options
    const optionSet = new Set(
      formData.options.map((opt) => opt.trim().toLowerCase())
    );
    if (optionSet.size !== formData.options.length) {
      errors.push("All options must be unique");
    }

    // Validate URLs if provided
    if (formData.logoUrl && !this.isValidUrl(formData.logoUrl)) {
      errors.push("Logo URL must be a valid URL");
    }

    if (formData.imageUrl && !this.isValidUrl(formData.imageUrl)) {
      errors.push("Image URL must be a valid URL");
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  /**
   * Helper function to validate URLs
   */
  private isValidUrl(string: string): boolean {
    try {
      new URL(string);
      return true;
    } catch (_) {
      return false;
    }
  }

  /**
   * Get follow-up question summary
   */
  getFollowUpSummary(followUpConfig: Record<string, FollowUpConfig>): {
    withFollowUp: string[];
    requiredFollowUp: string[];
    optionalFollowUp: string[];
    summary: string;
  } {
    const withFollowUp = Object.entries(followUpConfig)
      .filter(([_, config]) => config.hasFollowUp)
      .map(([option, _]) => option);

    const requiredFollowUp = Object.entries(followUpConfig)
      .filter(([_, config]) => config.hasFollowUp && config.required)
      .map(([option, _]) => option);

    const optionalFollowUp = Object.entries(followUpConfig)
      .filter(([_, config]) => config.hasFollowUp && !config.required)
      .map(([option, _]) => option);

    let summary = "No follow-up questions configured";

    if (withFollowUp.length > 0) {
      const parts = [];
      if (requiredFollowUp.length > 0) {
        parts.push(`Required: ${requiredFollowUp.join(", ")}`);
      }
      if (optionalFollowUp.length > 0) {
        parts.push(`Optional: ${optionalFollowUp.join(", ")}`);
      }
      summary = `Follow-up questions - ${parts.join("; ")}`;
    }

    return {
      withFollowUp,
      requiredFollowUp,
      optionalFollowUp,
      summary,
    };
  }
}

export const formWithFollowUpService = new FormWithFollowUpService();
export default formWithFollowUpService;

import type { Question, Response, Profile, StaffMember } from "../types";

const STORAGE_KEYS = {
  QUESTIONS: "form_questions",
  RESPONSES: "form_responses",
  PROFILE: "user_profile",
  SETTINGS: "user_settings",
  STAFF: "staff_members",
  FORM_VISIBILITY: "form_visibility",
  FORMS: "forms",
} as const;

// Questions API
export const questionsApi = {
  getAll: (): Question[] => {
    const data = localStorage.getItem(STORAGE_KEYS.QUESTIONS);
    return data ? JSON.parse(data) : [];
  },

  getById: (id: string): Question | undefined => {
    const questions = questionsApi.getAll();
    return questions.find((q) => q.id === id);
  },

  save: (question: Question): void => {
    const questions = questionsApi.getAll();
    const index = questions.findIndex((q) => q.id === question.id);

    if (index >= 0) {
      questions[index] = question;
    } else {
      questions.push(question);
    }

    localStorage.setItem(STORAGE_KEYS.QUESTIONS, JSON.stringify(questions));
  },

  delete: (id: string): void => {
    const questions = questionsApi.getAll();
    const updatedQuestions = questions.filter((q) => q.id !== id);
    localStorage.setItem(
      STORAGE_KEYS.QUESTIONS,
      JSON.stringify(updatedQuestions)
    );
  },

  deleteMany: (ids: string[]): void => {
    const questions = questionsApi.getAll();
    const updatedQuestions = questions.filter((q) => !ids.includes(q.id));
    localStorage.setItem(
      STORAGE_KEYS.QUESTIONS,
      JSON.stringify(updatedQuestions)
    );
  },
};

// Responses API
export const responsesApi = {
  getAll: (): Response[] => {
    const data = localStorage.getItem(STORAGE_KEYS.RESPONSES);
    return data ? JSON.parse(data) : [];
  },

  getByQuestionId: (questionId: string): Response[] => {
    const responses = responsesApi.getAll();
    return responses.filter((r) => r.questionId === questionId);
  },

  save: (response: Response): void => {
    const responses = responsesApi.getAll();
    const index = responses.findIndex((r) => r.id === response.id);

    if (index >= 0) {
      responses[index] = response;
    } else {
      responses.push(response);
    }

    localStorage.setItem(STORAGE_KEYS.RESPONSES, JSON.stringify(responses));
  },

  saveMany: (newResponses: Response[]): void => {
    const responses = responsesApi.getAll();

    newResponses.forEach((newResponse) => {
      const index = responses.findIndex((r) => r.id === newResponse.id);
      if (index >= 0) {
        responses[index] = newResponse;
      } else {
        responses.push(newResponse);
      }
    });

    localStorage.setItem(STORAGE_KEYS.RESPONSES, JSON.stringify(responses));
  },

  delete: (id: string): void => {
    const responses = responsesApi.getAll();
    const updatedResponses = responses.filter((r) => r.id !== id);
    localStorage.setItem(
      STORAGE_KEYS.RESPONSES,
      JSON.stringify(updatedResponses)
    );
  },

  deleteMany: (ids: string[]): void => {
    const responses = responsesApi.getAll();
    const updatedResponses = responses.filter((r) => !ids.includes(r.id));
    localStorage.setItem(
      STORAGE_KEYS.RESPONSES,
      JSON.stringify(updatedResponses)
    );
  },

  deleteByQuestionId: (questionId: string): void => {
    const responses = responsesApi.getAll();
    const updatedResponses = responses.filter(
      (r) => r.questionId !== questionId
    );
    localStorage.setItem(
      STORAGE_KEYS.RESPONSES,
      JSON.stringify(updatedResponses)
    );
  },
};

// Profile API
export const profileApi = {
  get: (): Profile | null => {
    const data = localStorage.getItem(STORAGE_KEYS.PROFILE);
    return data ? JSON.parse(data) : null;
  },

  save: (profile: Profile): void => {
    localStorage.setItem(STORAGE_KEYS.PROFILE, JSON.stringify(profile));
  },
};

// Settings API
export const settingsApi = {
  get: () => {
    const data = localStorage.getItem(STORAGE_KEYS.SETTINGS);
    return data
      ? JSON.parse(data)
      : {
          darkMode: false,
          notifications: true,
          emailUpdates: true,
          language: "en",
        };
  },

  save: (settings: any): void => {
    localStorage.setItem(STORAGE_KEYS.SETTINGS, JSON.stringify(settings));
  },
};

// Staff API
export const staffApi = {
  getAll: (): StaffMember[] => {
    const data = localStorage.getItem(STORAGE_KEYS.STAFF);
    return data ? JSON.parse(data) : [];
  },

  save: (member: StaffMember): void => {
    const staff = staffApi.getAll();
    const index = staff.findIndex((m) => m.id === member.id);

    if (index >= 0) {
      staff[index] = member;
    } else {
      staff.push(member);
    }

    localStorage.setItem(STORAGE_KEYS.STAFF, JSON.stringify(staff));
  },

  delete: (id: string): void => {
    const staff = staffApi.getAll();
    localStorage.setItem(
      STORAGE_KEYS.STAFF,
      JSON.stringify(staff.filter((m) => m.id !== id))
    );
  },
};

// Form Visibility API
export const formVisibilityApi = {
  getAll: (): Record<string, boolean> => {
    const data = localStorage.getItem(STORAGE_KEYS.FORM_VISIBILITY);
    return data ? JSON.parse(data) : {};
  },

  setVisibility: (formId: string, isVisible: boolean): void => {
    const visibilityData = formVisibilityApi.getAll();
    visibilityData[formId] = isVisible;
    localStorage.setItem(
      STORAGE_KEYS.FORM_VISIBILITY,
      JSON.stringify(visibilityData)
    );
  },

  isVisible: (formId: string): boolean => {
    const visibilityData = formVisibilityApi.getAll();
    return visibilityData[formId] ?? false;
  },
};

import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import {
  ArrowLeft,
  Settings,
  Link2,
  Eye,
  Save,
  Loader,
  AlertCircle,
} from "lucide-react";
import { apiClient } from "../api/client";
import { FormSectionLinkingSettings } from "./management/sections/FormSectionLinkingSettings";

interface FormData {
  _id: string;
  id: string;
  title: string;
  description: string;
  sections: any[];
  sectionFlowConfig?: any;
}

export const AdminFormDetail: React.FC = () => {
  const { formId } = useParams<{ formId: string }>();
  const navigate = useNavigate();
  const [form, setForm] = useState<FormData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<"edit" | "links" | "preview">(
    "links"
  );
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    loadForm();
  }, [formId]);

  const loadForm = async () => {
    if (!formId) return;

    try {
      setLoading(true);
      setError(null);
      const data = await apiClient.getFormById(formId);
      if (data.form) {
        setForm(data.form);
      }
    } catch (err) {
      console.error("Error loading form:", err);
      setError("Failed to load form details");
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gray-50">
        <Loader className="animate-spin h-8 w-8 text-blue-600" />
      </div>
    );
  }

  if (error || !form) {
    return (
      <div className="min-h-screen bg-gray-50 p-6">
        <div className="max-w-4xl mx-auto">
          <button
            onClick={() => navigate("/forms")}
            className="flex items-center gap-2 text-blue-600 hover:text-blue-700 mb-6 font-medium"
          >
            <ArrowLeft className="h-4 w-4" />
            Back to Forms
          </button>

          <div className="bg-white rounded-lg border border-red-200 p-8 text-center">
            <AlertCircle className="h-12 w-12 text-red-500 mx-auto mb-4" />
            <p className="text-red-700 text-lg">{error || "Form not found"}</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="bg-white border-b border-gray-200">
        <div className="max-w-7xl mx-auto px-6 py-4">
          <div className="flex items-center justify-between mb-4">
            <button
              onClick={() => navigate("/forms")}
              className="flex items-center gap-2 text-blue-600 hover:text-blue-700 font-medium"
            >
              <ArrowLeft className="h-4 w-4" />
              Back to Forms
            </button>
            <button
              onClick={() => window.location.reload()}
              className="px-4 py-2 bg-gray-200 text-gray-800 rounded-lg hover:bg-gray-300 font-medium"
            >
              Refresh
            </button>
          </div>

          <div>
            <h1 className="text-3xl font-bold text-gray-900">{form.title}</h1>
            <p className="text-gray-600 mt-2">{form.description}</p>

            <div className="mt-4 text-sm text-gray-600">
              <span className="font-medium">Sections:</span> {form.sections?.length || 0}
              <span className="mx-2">•</span>
              <span>
                <strong>Form ID:</strong> {form.id}
              </span>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-6">
        <div className="bg-white rounded-lg border border-gray-200">
          <div className="flex border-b border-gray-200">
            <button
              onClick={() => setActiveTab("links")}
              className={`flex-1 px-6 py-4 text-center font-medium transition-colors flex items-center justify-center gap-2 ${
                activeTab === "links"
                  ? "text-blue-600 border-b-2 border-blue-600"
                  : "text-gray-600 hover:text-gray-900"
              }`}
            >
              <Link2 className="h-4 w-4" />
              Section Linking
            </button>
            <button
              onClick={() => setActiveTab("edit")}
              className={`flex-1 px-6 py-4 text-center font-medium transition-colors flex items-center justify-center gap-2 ${
                activeTab === "edit"
                  ? "text-blue-600 border-b-2 border-blue-600"
                  : "text-gray-600 hover:text-gray-900"
              }`}
            >
              <Settings className="h-4 w-4" />
              Settings
            </button>
            <button
              onClick={() => setActiveTab("preview")}
              className={`flex-1 px-6 py-4 text-center font-medium transition-colors flex items-center justify-center gap-2 ${
                activeTab === "preview"
                  ? "text-blue-600 border-b-2 border-blue-600"
                  : "text-gray-600 hover:text-gray-900"
              }`}
            >
              <Eye className="h-4 w-4" />
              Preview
