                            className="inline-flex flex-col items-center gap-3 p-8 border-2 border-dashed border-blue-300 rounded-xl hover:border-blue-500 hover:bg-blue-50 transition-all cursor-pointer"
                            onClick={() => addQuestion(section.id)}
                          >
                            <div className="flex items-center justify-center w-16 h-16 rounded-full bg-gradient-to-r from-blue-500 to-blue-600 text-white shadow-lg">
                              <Plus className="w-8 h-8" />
                            </div>
                            <p className="text-lg font-semibold text-blue-700">
                              Add Your First Question
                            </p>
                            <p className="text-sm text-gray-600">
                              Click to start building your form
                            </p>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                );
              });
            })()}

            {/* Add Section Button */}
            <div className="mt-8">
              <button
                onClick={() => {
                  addSection();
                  // Switch to the new page
                  const pages = getPagesFromSections();
                  setCurrentPage(pages.length);
                }}
                className="w-full group relative overflow-hidden p-6 border-2 border-dashed border-blue-300 rounded-xl text-blue-700 hover:border-blue-500 hover:bg-gradient-to-r hover:from-blue-50 hover:to-blue-50 transition-all duration-200 shadow-sm hover:shadow-md"
              >
                <div className="flex items-center justify-center gap-3">
                  <div className="flex items-center justify-center w-10 h-10 rounded-full bg-blue-600 text-white shadow-md group-hover:scale-110 transition-transform">
                    <Plus className="w-6 h-6" />
                  </div>
                  <span className="text-lg font-bold">
                    Add New Page (Section)
                  </span>
                </div>
                <p className="text-sm text-gray-600 mt-2">
                  Create a new main section on a separate page
                </p>
              </button>

              {/* Child Forms Manager - Only show when editing existing form */}
              {id ? (
                <div className="mt-6">
                  <ChildFormsManager
                    parentFormId={id}
                    onUpdate={() => {
                      // Optionally refresh form data if needed
                      console.log("Child forms updated");
                    }}
                  />
                </div>
              ) : (
                <div className="mt-6 bg-blue-50 border-2 border-blue-200 rounded-xl p-6">
                  <div className="flex items-start space-x-3">
                    <LinkIcon className="w-6 h-6 text-blue-600 flex-shrink-0 mt-1" />
                    <div>
                      <h3 className="text-lg font-semibold text-blue-900 mb-2">
                        🔗 Create Follow-Up Forms (Child Forms)
                      </h3>
                      <p className="text-sm text-blue-800 mb-3">
                        Want to link follow-up forms that appear after users
                        complete this form?
                      </p>
                      <div className="bg-white border border-blue-200 rounded-lg p-4 text-sm text-blue-900">
                        <p className="font-medium mb-2">📝 How it works:</p>
                        <ol className="list-decimal list-inside space-y-1 text-blue-800">
                          <li>Save this form first</li>
                          <li>Come back to edit it</li>
                          <li>Link existing forms as "child forms"</li>
                          <li>
                            Child forms will appear to users after completing
                            this parent form
                          </li>
                        </ol>
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Sidebar */}
          <div className="w-full lg:w-80 flex-shrink-0 space-y-6">
            {/* Sticky Page Navigation */}
            {(() => {
              const pages = getPagesFromSections();
              if (pages.length > 1) {
                return (
                  <div className="sticky top-1/2 -translate-y-1/2 h-0">
                    <div className="bg-white rounded-lg border-2 border-blue-200 shadow-lg p-4 -translate-y-1/2">
                      <h3 className="text-sm font-bold text-blue-900 mb-3 text-center">
                        📄 Pages
                      </h3>
                      <div className="space-y-2">
                        {pages.map((page, pageIndex) => {
                          const isCurrent = currentPage === pageIndex;
                          const sectionLabel = String.fromCharCode(
                            65 + pageIndex
                          ); // A, B, C...
                          const mainSection = page.find((s) => !s.isSubsection);
                          const questionCount = page.reduce(
                            (total, s) => total + s.questions.length,
                            0
                          );

                          return (
                            <button
                              key={pageIndex}
                              type="button"
                              onClick={() => setCurrentPage(pageIndex)}
                              className={`
                                w-full p-3 rounded-lg text-left transition-all duration-200
                                ${
                                  isCurrent
                                    ? "bg-gradient-to-r from-blue-600 to-blue-700 text-white shadow-md scale-105"
                                    : "bg-blue-50 text-blue-700 hover:bg-blue-100 border border-blue-200"
                                }
                              `}
                              title={
                                mainSection?.title || `Page ${pageIndex + 1}`
                              }
                            >
                              <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                  <div
                                    className={`
                                    flex items-center justify-center w-8 h-8 rounded-full font-bold text-sm
                                    ${
                                      isCurrent
                                        ? "bg-white text-blue-600"
                                        : "bg-blue-600 text-white"
                                    }
                                  `}
                                  >
                                    {sectionLabel}
                                  </div>
                                  <div className="flex-1 min-w-0">
                                    <div
                                      className={`text-sm font-bold truncate ${
                                        isCurrent
                                          ? "text-white"
                                          : "text-blue-900"
                                      }`}
                                    >
                                      {mainSection?.title ||
                                        `Section ${pageIndex + 1}`}
                                    </div>
                                    <div
                                      className={`text-xs ${
                                        isCurrent
                                          ? "text-blue-100"
                                          : "text-blue-600"
                                      }`}
                                    >
                                      {questionCount}{" "}
                                      {questionCount === 1
                                        ? "question"
                                        : "questions"}
                                    </div>
                                  </div>
                                </div>
                              </div>
                            </button>
                          );
                        })}
                      </div>

                      {/* Progress indicator */}
                      <div className="mt-4 pt-4 border-t border-blue-200">
                        <div className="text-xs text-center text-blue-700 mb-2 font-medium">
                          Page {currentPage + 1} of {pages.length}
                        </div>
                        <div className="w-full bg-blue-100 rounded-full h-2">
                          <div
                            className="bg-gradient-to-r from-blue-600 to-blue-700 h-2 rounded-full transition-all duration-300"
                            style={{
                              width: `${
                                ((currentPage + 1) / pages.length) * 100
                              }%`,
                            }}
                          />
                        </div>
                      </div>
                    </div>
                  </div>
                );
              }
              return null;
            })()}

            <div className="bg-white rounded-lg border border-neutral-200 p-6">
              <h3 className="font-medium text-primary-800 mb-4">
                Form Preview
              </h3>
              <p className="text-sm text-primary-600 mb-4">
                See how your form will appear to users
              </p>
              <button
                className="w-full btn-secondary"
                onClick={() => setShowPreview(true)}
              >
                <Eye className="w-4 h-4 mr-2" />
                Preview Form
              </button>
            </div>

            <div className="bg-white rounded-lg border border-neutral-200 p-6">
              <h3 className="font-medium text-primary-800 mb-4">
                Form Statistics
              </h3>
              <div className="space-y-3 text-sm">
                <div className="flex justify-between">
                  <span className="text-primary-600">Sections:</span>
                  <span className="font-medium">{form.sections.length}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-primary-600">Questions:</span>
                  <span className="font-medium">
                    {form.sections.reduce(
                      (total, section) => total + section.questions.length,
                      0
                    )}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-primary-600">Follow-ups:</span>
                  <span className="font-medium">
                    {form.sections.reduce(
                      (total, section) =>
                        total +
                        section.questions.reduce(
                          (qTotal, q) =>
                            qTotal + (q.followUpQuestions?.length || 0),
                          0
                        ),
                      0
                    )}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-primary-600">Visibility:</span>
                  <span
                    className={`font-medium ${
                      form.isVisible ? "text-green-600" : "text-yellow-600"
                    }`}
                  >
                    {form.isVisible ? "Public" : "Private"}
                  </span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Preview Modal */}
      {showPreview && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg max-w-4xl w-full max-h-[90vh] overflow-auto">
            <div className="flex items-center justify-between p-6 border-b">
              <h2 className="text-2xl font-bold text-primary-900">
                Form Preview
              </h2>
              <button
                onClick={() => setShowPreview(false)}
                className="text-neutral-400 hover:text-neutral-600"
              >
                <X className="w-6 h-6" />
              </button>
            </div>
            <div className="p-6">
              <PreviewForm form={form} />
            </div>
          </div>
        </div>
      )}

      {/* Form Routing Configuration Modal */}
      {showFormRoutingConfig && formRoutingConfigQuestion && (
        <FormRoutingConfig
          questionId={formRoutingConfigQuestion.questionId}
          sectionId={formRoutingConfigQuestion.sectionId}
          options={formRoutingConfigQuestion.options}
          availableForms={forms.map((f) => ({
            id: f.id || f._id,
            title: f.title,
          }))}
          existingConfig={
            form.sections
              .find((s) => s.id === formRoutingConfigQuestion.sectionId)
              ?.questions.find(
                (q) => q.id === formRoutingConfigQuestion.questionId
              )?.followUpConfig || {}
          }
          onSave={handleSaveFormRoutingConfig}
          onClose={() => {
            setShowFormRoutingConfig(false);
            setFormRoutingConfigQuestion(null);
          }}
        />
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo, useCallback } from "react";
import { useParams, useNavigate } from "react-router-dom";
import {
  Eye,
  Calendar,
  FileText,
  User,
  X,
  ArrowLeft,
  Save,
  Download,
  Table,
  BarChart3,
  PieChart,
  Check,
  X as XIcon,
} from "lucide-react";
import { apiClient } from "../api/client";
import { formatTimestamp } from "../utils/dateUtils";
import { useNotification } from "../context/NotificationContext";
import { exportResponsesToExcel } from "../utils/exportUtils";
import { Bar, Pie } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement
);

interface Response {
  _id: string;
  id: string;
  questionId: string;
  answers: Record<string, any>;
  createdAt: string;
  updatedAt: string;
  assignedTo?: string;
  status?: string;
  parentResponseId?: string;
  childResponses?: Response[];
  score?: {
    correct: number;
    total: number;
  };
  submissionMetadata?: {
    ipAddress?: string;
    userAgent?: string;
    browser?: string;
    device?: string;
    os?: string;
    location?: {
      country?: string;
      countryCode?: string;
      region?: string;
      city?: string;
      latitude?: number;
      longitude?: number;
      timezone?: string;
      isp?: string;
    };
    capturedLocation?: {
      latitude?: number;
      longitude?: number;
      accuracy?: number;
      source?: "browser" | "ip" | "manual" | "unknown";
      capturedAt?: string;
    };
    submittedAt?: string;
  };
}

interface Question {
  id: string;
  text: string;
  type: string;
  correctAnswer?: any;
}

interface Section {
  id: string;
  title: string;
  questions: Question[];
}

interface Form {
  _id: string;
  id: string;
  title: string;
  description?: string;
  sections?: Section[];
  followUpQuestions?: Question[];
}

export default function FormResponses() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { showSuccess, showError } = useNotification();
  const [responses, setResponses] = useState<Response[]>([]);
  const [form, setForm] = useState<Form | null>(null);
  const [allQuestions, setAllQuestions] = useState<Question[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedResponse, setSelectedResponse] = useState<Response | null>(
    null
  );
  const [selectedStatus, setSelectedStatus] = useState<string>("");
  const [updating, setUpdating] = useState(false);
  const [showTableView, setShowTableView] = useState(false);
  const [chartType, setChartType] = useState<"bar" | "pie">("bar");

  const questionColumns = useMemo(() => {
    if (!form) return [] as Array<{ id: string; text: string }>;

    const sectionQuestions = (form.sections ?? []).flatMap(
      (section) => section.questions ?? []
    );
    const followUpQuestions = form.followUpQuestions ?? [];

    const uniqueQuestions = new Map<string, Question>();

    [...sectionQuestions, ...followUpQuestions].forEach((questionItem) => {
      if (questionItem && !uniqueQuestions.has(questionItem.id)) {
        uniqueQuestions.set(questionItem.id, questionItem);
      }
    });

    return Array.from(uniqueQuestions.values()).map(({ id, text }) => ({
      id,
      text,
    }));
  }, [form]);

  const quizQuestions = useMemo(() => {
    return allQuestions.filter((q) => q.correctAnswer !== undefined);
  }, [allQuestions]);

  const getQuestionDistribution = useCallback(
    (questionId: string) => {
      const distribution: Record<string, number> = {};
      responses.forEach((response) => {
        const answer = response.answers?.[questionId];
        const answerStr = Array.isArray(answer)
          ? answer.join(", ")
          : String(answer || "No Answer");
        distribution[answerStr] = (distribution[answerStr] || 0) + 1;
      });
      return distribution;
    },
    [responses]
  );

  const getAnswerDisplay = useCallback(
    (response: Response, questionId: string) => {
      const answer = response.answers?.[questionId];

      if (answer === undefined || answer === null || answer === "") {
        return "--";
      }

      if (Array.isArray(answer)) {
        return answer.join(", ");
      }

      if (typeof answer === "object") {
        try {
          return JSON.stringify(answer, null, 2);
        } catch (error) {
          return String(answer);
        }
      }

      return String(answer);
    },
    []
  );

  useEffect(() => {
    if (id) {
      fetchData();
    }
  }, [id]);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [responsesData, formData] = await Promise.all([
        apiClient.getResponses(),
        apiClient.getForm(id!),
      ]);

      // Set the form
      if (!formData.form) {
        setError("Form not found");
        return;
      }
      setForm(formData.form);

      // Collect all questions from sections and followUpQuestions
      const allQs: Question[] = [];
      if (formData.form.sections) {
        formData.form.sections.forEach((section) => {
          if (section.questions) allQs.push(...section.questions);
        });
      }
      if (formData.form.followUpQuestions)
        allQs.push(...formData.form.followUpQuestions);
      setAllQuestions(allQs);

      // Filter responses for this form
      const formResponses = responsesData.responses.filter(
        (response: Response) => response.questionId === id
      );

      setResponses(formResponses);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to load responses");
    } finally {
      setLoading(false);
    }
  };

  const getQuestionText = (questionId: string): string => {
    if (!form) return questionId;

    // Search in sections
    if (form.sections) {
      for (const section of form.sections) {
        const question = section.questions?.find((q) => q.id === questionId);
        if (question) return question.text;
      }
    }

    // Search in follow-up questions
    if (form.followUpQuestions) {
      const question = form.followUpQuestions.find((q) => q.id === questionId);
      if (question) return question.text;
    }

    return questionId;
  };

  const handleStatusUpdate = async () => {
    if (!selectedResponse || !selectedStatus) return;

    try {
      setUpdating(true);
      await apiClient.updateResponse(selectedResponse.id, {
        status: selectedStatus,
      });

      // Update local state
      setResponses((prev) =>
        prev.map((r) =>
          r.id === selectedResponse.id ? { ...r, status: selectedStatus } : r
        )
      );
      setSelectedResponse({ ...selectedResponse, status: selectedStatus });

      showSuccess("Status updated successfully!");
    } catch (err) {
      showError(err instanceof Error ? err.message : "Failed to update status");
    } finally {
      setUpdating(false);
    }
  };

  const groupResponsesByDate = (responses: Response[]) => {
    return responses.reduce((groups, response) => {
      const date = new Date(response.createdAt).toDateString();
      if (!groups[date]) {
        groups[date] = [];
      }
      groups[date].push(response);
      return groups;
    }, {} as Record<string, Response[]>);
  };

  const handleExport = (targetForm: Form) => {
    exportResponsesToExcel(responses, {
      id: targetForm.id,
      title: targetForm.title,
      description: targetForm.description,
      sections: targetForm.sections,
    } as any);
  };

  const groupedResponses = useMemo(
    () => groupResponsesByDate(responses),
    [responses]
  );

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-center py-16">
        <div className="text-red-600 mb-2">Error loading responses</div>
        <div className="text-primary-500">{error}</div>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto">
      {/* Page Header */}
      <div className="mb-8">
        <div className="flex items-center mb-4">
          <button
            onClick={() => navigate(-1)}
            className="flex items-center text-primary-600 hover:text-primary-700 mr-4"
          >
            <ArrowLeft className="w-5 h-5 mr-2" />
            Back
          </button>
          <div>
            <h1 className="text-2xl font-medium text-primary-600 mb-2">
              Customer Responses
            </h1>
            <p className="text-primary-500">Responses for: {form?.title}</p>
            {form?.description && (
              <p className="text-sm text-primary-400 mt-1">
                {form.description}
              </p>
            )}
          </div>
        </div>

        {/* Response Summary */}
        <div className="grid grid-cols-1 sm:grid-cols-5 gap-4">
          <div className="card p-4">
            <div className="text-center">
              <div className="text-2xl font-bold text-primary-600">
                {responses.length}
              </div>
              <div className="text-sm text-primary-500">Total Responses</div>
            </div>
          </div>
          <div className="card p-4">
            <div className="text-center">
              <div className="text-2xl font-bold text-primary-600">
                {responses.filter((r) => r.score).length}
              </div>
              <div className="text-sm text-primary-500">Scored Responses</div>
            </div>
          </div>
          <div className="card p-4">
            <div className="text-center">
              <div className="text-2xl font-bold text-green-600">
                {responses.filter((r) => r.status === "verified").length}
              </div>
              <div className="text-sm text-primary-500">Completed</div>
            </div>
          </div>
          <div className="card p-4">
            <div className="text-center">
              <div className="text-2xl font-bold text-yellow-600">
                {
                  responses.filter((r) => !r.status || r.status === "pending")
                    .length
                }
              </div>
              <div className="text-sm text-primary-500">Pending</div>
            </div>
          </div>
          <div className="card p-4">
            <div className="text-center">
              <div className="text-2xl font-bold text-blue-600">
                {(() => {
                  const scoredResponses = responses.filter((r) => r.score);
                  if (scoredResponses.length === 0) return "0%";
                  const totalScore = scoredResponses.reduce(
                    (sum, r) => sum + r.score.correct / r.score.total,
                    0
                  );
                  const average = Math.round(
                    (totalScore / scoredResponses.length) * 100
                  );
                  return `${average}%`;
                })()}
              </div>
              <div className="text-sm text-primary-500">Average Score</div>
            </div>
          </div>
          <div className="card p-4 sm:col-span-5">
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
              <div>
                <h2 className="text-lg font-semibold text-primary-600">
                  Export Responses
                </h2>
                <p className="text-sm text-primary-500">
                  Download a full Excel report of all responses for this form.
                </p>
              </div>
              <div className="flex flex-wrap gap-2">
                <button
                  onClick={() => form && handleExport(form)}
                  className="btn-secondary flex items-center"
                  disabled={!form || responses.length === 0}
                >
                  <Download className="w-4 h-4 mr-2" />
                  Export as Excel
                </button>
                <button
                  onClick={() => setShowTableView(true)}
                  className="btn-tertiary flex items-center"
                  disabled={responses.length === 0}
                >
                  <Table className="w-4 h-4 mr-2" />
                  View as Table
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Response Distribution by Question */}
      {/* {quizQuestions.length > 0 && (
        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-semibold text-primary-600">
              Response Distribution by Question
            </h2>
            <div className="flex gap-2">
              <button
                onClick={() => setChartType("bar")}
                className={`btn-secondary flex items-center ${
                  chartType === "bar" ? "bg-primary-600 text-white" : ""
                }`}
              >
                <BarChart3 className="w-4 h-4 mr-2" />
                Bar
              </button>
              <button
                onClick={() => setChartType("pie")}
                className={`btn-secondary flex items-center ${
                  chartType === "pie" ? "bg-primary-600 text-white" : ""
                }`}
              >
                <PieChart className="w-4 h-4 mr-2" />
                Pie
              </button>
            </div>
          </div>
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {quizQuestions.map((question) => {
              const distribution = getQuestionDistribution(question.id);
              const labels = Object.keys(distribution);
              const data = Object.values(distribution);
              const correctAnswerStr = Array.isArray(question.correctAnswer)
                ? question.correctAnswer.join(", ")
                : String(question.correctAnswer || "");
              const correctIndex = labels.findIndex(
                (label) =>
                  label.toLowerCase() === correctAnswerStr.toLowerCase()
              );

              const backgroundColors = labels.map((_, index) =>
                index === correctIndex ? "#10B981" : "#6B7280"
              );
              const borderColors = labels.map((_, index) =>
                index === correctIndex ? "#059669" : "#4B5563"
              );

              const chartData = {
                labels,
                datasets: [
                  {
                    label: "Responses",
                    data,
                    backgroundColor: backgroundColors,
                    borderColor: borderColors,
                    borderWidth: 1,
                  },
                ],
              };

              const options = {
                responsive: true,
                plugins: {
                  legend: {
                    position: "top" as const,
                  },
                  title: {
                    display: true,
                    text: question.text,
                  },
                },
              };

              return (
                <div key={question.id} className="card p-6">
                  <h3 className="text-lg font-medium text-primary-600 mb-2">
                    {question.text}
                  </h3>
                  <p className="text-sm text-green-600 font-medium mb-4">
                    Correct Answer: {correctAnswerStr}
                  </p>
                  <p className="text-sm text-primary-500 mb-4">
                    {responses.length} responses
                  </p>
                  <div className="h-64">
                    {chartType === "bar" ? (
                      <Bar data={chartData} options={options} />
                    ) : (
                      <Pie data={chartData} options={options} />
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )} */}

      {/* Responses by Date */}
      <div className="space-y-6">
        {Object.keys(groupedResponses)
          .sort((a, b) => new Date(b).getTime() - new Date(a).getTime())
