import React from "react";
import type { FollowUpQuestion } from "../types";
import { questionTypes } from "../utils/questionTypes";
import DateTimeInput from "./QuestionTypes/DateTimeInput";
import FileInput from "./QuestionTypes/FileInput";
import GridQuestion from "./QuestionTypes/GridQuestion";
import RadioImageQuestion from "./QuestionTypes/RadioImageQuestion";
import RatingQuestion from "./QuestionTypes/RatingQuestion";
import ScaleQuestion from "./QuestionTypes/ScaleQuestion";
import SearchSelect from "./QuestionTypes/SearchSelect";
import ParagraphInput from "./QuestionTypes/ParagraphInput";

interface QuestionRendererProps {
  question: FollowUpQuestion;
  value: any;
  onChange?: (value: any) => void;
  readOnly?: boolean;
}

export default function QuestionRenderer({
  question,
  value,
  onChange,
  readOnly = false,
}: QuestionRendererProps) {
  const renderInput = () => {
    switch (question.type) {
      case "paragraph":
        return (
          <ParagraphInput
            question={question}
            value={value}
            onChange={onChange}
            readOnly={readOnly}
          />
        );

      case "search-select":
        return (
          <SearchSelect
            options={
              question.options?.map((opt) => ({ value: opt, label: opt })) || []
            }
            value={value || ""}
            onChange={onChange}
            placeholder="Select an option..."
            required={question.required}
            readOnly={readOnly}
          />
        );

      case "radio":
      case "checkbox":
        return (
          <div className="space-y-2">
            {question.options?.map((option) => (
              <label
                key={option}
                className="flex items-center space-x-3 p-2 rounded-lg hover:bg-gray-50"
              >
                <input
                  type={question.type}
                  name={question.id}
                  value={option}
                  checked={
                    question.type === "checkbox"
                      ? Array.isArray(value) && value.includes(option)
                      : value === option
                  }
                  onChange={(e) => {
                    if (readOnly) return;
                    if (question.type === "checkbox") {
                      const newValue = Array.isArray(value) ? [...value] : [];
                      if (e.target.checked) {
                        newValue.push(option);
                      } else {
                        const index = newValue.indexOf(option);
                        if (index > -1) {
                          newValue.splice(index, 1);
                        }
                      }
                      onChange(newValue);
                    } else {
                      onChange(option);
                    }
                  }}
                  required={question.required && !value}
                  disabled={readOnly}
                  className={`h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 ${
                    readOnly ? "cursor-not-allowed" : ""
                  }`}
                />
                <span className="text-gray-700">{option}</span>
              </label>
            ))}
          </div>
        );

      case "radio-grid":
      case "checkbox-grid":
        return (
          <GridQuestion
            question={question}
            value={value || {}}
            onChange={onChange}
            type={question.type === "radio-grid" ? "radio" : "checkbox"}
            readOnly={readOnly}
          />
        );

      case "radio-image":
        return (
          <RadioImageQuestion
            question={question}
            value={value}
            onChange={onChange}
          />
        );

      case "rating":
        return (
          <RatingQuestion
            question={question}
            value={value}
            onChange={onChange}
          />
        );

      case "scale":
        return (
          <ScaleQuestion
            question={question}
            value={value}
            onChange={onChange}
          />
        );

      case "file":
        return (
          <FileInput
            question={question}
            value={value}
            onChange={onChange}
            readOnly={readOnly}
          />
        );

      case "date":
      case "time":
        return (
          <DateTimeInput
            question={question}
            value={value}
            onChange={onChange}
            readOnly={readOnly}
          />
        );

      default:
        return (
          <input
            type={question.type}
            value={value || ""}
            onChange={(e) => !readOnly && onChange(e.target.value)}
            required={question.required}
            disabled={readOnly}
            className={`w-full px-4 py-2 border border-gray-300 rounded-lg ${
              readOnly
                ? "bg-gray-100 cursor-not-allowed"
                : "bg-white focus:ring-2 focus:ring-blue-500"
            }`}
          />
        );
    }
  };

  return (
    <div className="space-y-2">
      <label className="block font-medium text-gray-700">
        {question.text}
        {question.required && <span className="text-red-500 ml-1">*</span>}
      </label>
      {question.description && (
        <p className="text-sm text-gray-500 mb-2">{question.description}</p>
      )}
      {renderInput()}
    </div>
  );
}

import React from 'react';
import type { FollowUpQuestion } from '../../types';
import { useQuestionLogic } from '../../hooks/useQuestionLogic';

interface ConditionalQuestionProps {
  question: FollowUpQuestion;
  parentAnswer: any;
  renderQuestion: (question: FollowUpQuestion) => React.ReactNode;
}

export default function ConditionalQuestion({
  question,
  parentAnswer,
  renderQuestion,
}: ConditionalQuestionProps) {
  const { evaluateCondition } = useQuestionLogic();

  if (!question.showWhen) return null;

  const shouldShow = evaluateCondition(parentAnswer, question.showWhen.value);

  if (!shouldShow) return null;

  return (
    <div className="ml-6 mt-4 pl-4 border-l-2 border-blue-200 dark:border-blue-800">
      {renderQuestion(question)}
    </div>
  );
}

import React, { useEffect } from "react";
import type { FollowUpQuestion } from "../../types";

interface GridQuestionProps {
  question: FollowUpQuestion;
  value: Record<string, string | string[]>;
  onChange: (value: Record<string, string | string[]>) => void;
  type: "radio" | "checkbox";
  readOnly?: boolean;
}

export default function GridQuestion({
  question,
  value,
  onChange,
  type,
  readOnly = false,
}: GridQuestionProps) {
  if (!question.gridOptions) return null;
  const { rows, columns } = question.gridOptions;

  // Initialize empty values for each row
  useEffect(() => {
    const initializedValue = { ...value };
    rows.forEach((row) => {
      if (!initializedValue[row]) {
        initializedValue[row] = type === "radio" ? "" : [];
      }
    });
    if (Object.keys(initializedValue).length > Object.keys(value).length) {
      onChange(initializedValue);
    }
  }, [rows, type, value, onChange]);

  const handleChange = (row: string, col: string, checked: boolean) => {
    if (readOnly) return;
    if (type === "radio") {
      onChange({ ...value, [row]: col });
    } else {
      const currentValues = (value[row] as string[]) || [];
      const newValues = checked
        ? [...currentValues, col]
        : currentValues.filter((v) => v !== col);
      onChange({ ...value, [row]: newValues });
    }
  };

  return (
    <div className="overflow-x-auto">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
          <tr>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
              {question.text}
            </th>
            {columns.map((col) => (
              <th
                key={col}
                className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider"
              >
                {col}
              </th>
            ))}
          </tr>
        </thead>
        <tbody className="bg-white divide-y divide-gray-200">
          {rows.map((row) => (
            <tr key={row} className="hover:bg-gray-50">
              <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                {row}
              </td>
              {columns.map((col) => (
                <td
                  key={col}
                  className="px-6 py-4 whitespace-nowrap text-center"
                >
                  <input
                    type={type}
                    name={`${question.id}-${row}`}
                    checked={
                      type === "radio"
                        ? value[row] === col
                        : (value[row] as string[])?.includes(col)
                    }
                    onChange={(e) => handleChange(row, col, e.target.checked)}
                    disabled={readOnly}
                    className={`h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 ${
                      readOnly ? "cursor-not-allowed" : ""
                    }`}
                    required={
                      question.required && type === "radio" && !value[row]
                    }
                  />
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

import React from "react";
import {
  MessageSquarePlus,
  ImagePlus,
  FileText,
  PlusSquare,
  Trash2,
  Copy,
} from "lucide-react";
import type { FollowUpQuestion, QuestionType } from "../types";
import OptionsInput from "./QuestionTypes/OptionsInput";
import GridOptionsInput from "./QuestionTypes/GridOptionsInput";

interface QuestionsListProps {
  questions: FollowUpQuestion[];
  onQuestionsChange: (questions: FollowUpQuestion[]) => void;
}

export default function QuestionsList({
  questions,
  onQuestionsChange,
}: QuestionsListProps) {
  const questionTypes: { value: QuestionType; label: string }[] = [
    { value: "text", label: "Text" },
    { value: "paragraph", label: "Paragraph" },
    { value: "radio", label: "Multiple Choice" },
    { value: "checkbox", label: "Checkboxes" },
    { value: "search-select", label: "Search/Filter Dropdown" },
    { value: "email", label: "Email" },
    { value: "url", label: "URL" },
    { value: "tel", label: "Phone Number" },
    { value: "date", label: "Date" },
    { value: "time", label: "Time" },
    { value: "file", label: "File Upload" },
    { value: "range", label: "Range" },
    { value: "rating", label: "Rating" },
    { value: "scale", label: "Linear Scale" },
    { value: "radio-image", label: "Image Choice" },
  ];

  const addQuestion = (parentId?: string) => {
    const newQuestion: FollowUpQuestion = {
      id: crypto.randomUUID(),
      text: "",
      type: "text",
      required: false,
      parentId,
      imageUrl: "",
      description: "",
      options: [],
    };
    onQuestionsChange([...questions, newQuestion]);
  };

  const copyQuestion = (question: FollowUpQuestion) => {
    const newQuestion: FollowUpQuestion = {
      ...question,
      id: crypto.randomUUID(),
      text: `${question.text} (Copy)`,
    };

    const currentIndex = questions.findIndex((q) => q.id === question.id);
    const updatedQuestions = [
      ...questions.slice(0, currentIndex + 1),
      newQuestion,
      ...questions.slice(currentIndex + 1),
    ];

    onQuestionsChange(updatedQuestions);
  };

  const addMiddleQuestion = (currentQuestion: FollowUpQuestion) => {
    const newQuestion: FollowUpQuestion = {
      id: crypto.randomUUID(),
      text: "",
      type: "text",
      required: false,
      imageUrl: "",
      description: "",
      options: [],
    };

    const currentIndex = questions.findIndex(
      (q) => q.id === currentQuestion.id
    );
    const updatedQuestions = [
      ...questions.slice(0, currentIndex + 1),
      newQuestion,
      ...questions.slice(currentIndex + 1),
    ];

    onQuestionsChange(updatedQuestions);
  };

  const addFollowUpQuestion = (parentQuestion: FollowUpQuestion) => {
    const newQuestion: FollowUpQuestion = {
      id: crypto.randomUUID(),
      text: "",
      type: "text",
      required: false,
      showWhen: {
        questionId: parentQuestion.id,
        value: parentQuestion.options?.[0] || "",
      },
      options: [],
    };
    onQuestionsChange([...questions, newQuestion]);
  };

  const removeQuestion = (id: string) => {
    onQuestionsChange(
      questions.filter((q) => q.id !== id && q.showWhen?.questionId !== id)
    );
  };

  const updateQuestion = (id: string, updates: Partial<FollowUpQuestion>) => {
    onQuestionsChange(
      questions.map((q) => (q.id === id ? { ...q, ...updates } : q))
    );
  };

  const handleImageUpload = async (
    id: string,
    e: React.ChangeEvent<HTMLInputElement>
  ) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const imageData = reader.result as string;
        updateQuestion(id, { imageUrl: imageData });
      };
      reader.readAsDataURL(file);
    }
  };

  const needsOptions = (type: QuestionType) => {
    return ["radio", "checkbox", "radio-image", "search-select"].includes(type);
  };

  const mainQuestions = questions.filter((q) => !q.showWhen);
  const getFollowUpQuestions = (questionId: string) =>
    questions.filter((q) => q.showWhen?.questionId === questionId);

  const renderQuestion = (
    q: FollowUpQuestion,
    index: number,
    isFollowUp = false
  ) => {
    const followUpQuestions = getFollowUpQuestions(q.id);

    return (
      <div
        key={q.id}
        className={`card p-6 bg-neutral-50 ${isFollowUp ? "ml-8 mt-4" : ""}`}
      >
        <div className="flex justify-between items-start mb-4">
          <h4 className="font-medium text-primary-600">
            {isFollowUp ? "Follow-up Question" : `Question ${index + 1}`}
          </h4>
          <div className="flex items-center space-x-2">
            <button
              type="button"
              onClick={() => copyQuestion(q)}
              className="p-2 text-primary-500 hover:text-primary-700 hover:bg-primary-50 rounded-lg transition-colors"
              title="Copy Question"
            >
              <Copy className="w-5 h-5" />
            </button>
            {needsOptions(q.type) && (
              <button
                type="button"
                onClick={() => addFollowUpQuestion(q)}
                className="p-2 text-green-500 hover:text-green-700 hover:bg-green-50 rounded-lg transition-colors"
                title="Add Follow-up Question"
              >
                <MessageSquarePlus className="w-5 h-5" />
              </button>
            )}
            <label
              className="flex items-center p-2 text-blue-500 hover:text-blue-700 hover:bg-blue-50 rounded-lg cursor-pointer transition-colors"
              title="Add Image"
            >
              <ImagePlus className="w-5 h-5" />
              <input
                type="file"
                accept="image/*"
                onChange={(e) => handleImageUpload(q.id, e)}
                className="hidden"
              />
            </label>
            <button
              type="button"
              onClick={() => {
                const description = prompt(
                  "Enter question description:",
                  q.description
                );
                if (description !== null) {
                  updateQuestion(q.id, { description });
                }
              }}
              className="p-2 text-purple-500 hover:text-purple-700 hover:bg-purple-50 rounded-lg transition-colors"
              title="Add Description"
            >
              <FileText className="w-5 h-5" />
            </button>
            {!isFollowUp && (
              <button
                type="button"
                onClick={() => addMiddleQuestion(q)}
                className="p-2 text-indigo-500 hover:text-indigo-700 hover:bg-indigo-50 rounded-lg transition-colors"
                title="Add Question After"
              >
                <PlusSquare className="w-5 h-5" />
              </button>
            )}
            <button
              type="button"
              onClick={() => removeQuestion(q.id)}
              className="p-2 text-red-500 hover:text-red-700 hover:bg-red-50 rounded-lg transition-colors"
              title="Remove Question"
            >
              <Trash2 className="w-5 h-5" />
            </button>
          </div>
        </div>

        <div className="space-y-4">
          {q.imageUrl && (
            <div className="mt-2">
              <img
                src={q.imageUrl}
                alt="Question"
                className="max-h-48 rounded-lg object-contain"
              />
            </div>
          )}

          {q.description && (
            <div className="mt-2 text-sm text-primary-500 bg-primary-50 p-3 rounded-lg">
              {q.description}
            </div>
          )}

          <input
            type="text"
            value={q.text}
            onChange={(e) => updateQuestion(q.id, { text: e.target.value })}
            placeholder="Question text"
            className="input-field"
          />

          <div className="flex space-x-4">
            <select
              value={q.type}
              onChange={(e) => {
                const type = e.target.value as QuestionType;
                updateQuestion(q.id, {
                  type,
                  options: needsOptions(type) ? [""] : undefined,
                });
              }}
              className="flex-1 input-field"
            >
              {questionTypes.map((type) => (
                <option key={`${q.id}-${type.value}`} value={type.value}>
                  {type.label}
                </option>
              ))}
            </select>

            <label className="flex items-center space-x-2">
              <input
                type="checkbox"
                checked={q.required}
                onChange={(e) =>
                  updateQuestion(q.id, { required: e.target.checked })
                }
                className="text-blue-600 focus:ring-blue-500 dark:bg-gray-700"
              />
              <span className="text-sm text-primary-600">Required</span>
            </label>
          </div>

          {needsOptions(q.type) && (
            <div className="mt-4">
              <label className="block text-sm font-medium text-primary-600 mb-2">
                Options
              </label>
              <OptionsInput
                options={q.options || []}
                onChange={(options) => updateQuestion(q.id, { options })}
              />

              {/* Correct Answer Selection for Quiz Questions */}
              {q.options && q.options.length > 0 && (
                <div className="mt-4">
                  <label className="block text-sm font-medium text-primary-600 mb-2">
                    Correct Answer (Optional - for quiz mode)
                  </label>
                  <select
                    value={q.correctAnswer || ""}
                    onChange={(e) => {
                      console.log("Correct answer changed:", {
                        questionId: q.id,
                        questionText: q.text,
                        oldValue: q.correctAnswer,
                        newValue: e.target.value,
                        options: q.options,
                      });
                      updateQuestion(q.id, {
                        correctAnswer: e.target.value || undefined,
                      });
                    }}
                    className="input-field"
                  >
                    <option value="">-- No correct answer --</option>
                    {q.options
                      .filter((opt) => opt && opt.trim() !== "")
                      .map((option) => (
                        <option
                          key={`${q.id}-correct-${option}`}
                          value={option}
                        >
                          {option}
                        </option>
                      ))}
                  </select>
                  <p className="text-xs text-gray-500 mt-1">
                    Select the correct answer if this is a quiz question. Leave
                    empty for regular questions.
                  </p>
                  {/* Debug info */}
                  <p className="text-xs text-blue-600 mt-1">
                    Current value: "{q.correctAnswer || "(empty)"}"
                  </p>
                </div>
              )}
            </div>
          )}

          {["range", "scale"].includes(q.type) && (
            <div className="grid grid-cols-3 gap-4">
              <div>
                <label className="block text-sm font-medium text-primary-600 mb-1">
                  Min
                </label>
                <input
                  type="number"
                  value={q.min || 0}
                  onChange={(e) =>
                    updateQuestion(q.id, { min: parseInt(e.target.value) })
                  }
                  className="input-field"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-primary-600 mb-1">
                  Max
                </label>
                <input
                  type="number"
                  value={q.max || 10}
                  onChange={(e) =>
                    updateQuestion(q.id, { max: parseInt(e.target.value) })
                  }
                  className="input-field"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-primary-600 mb-1">
                  Step
                </label>
                <input
                  type="number"
                  value={q.step || 1}
                  onChange={(e) =>
                    updateQuestion(q.id, { step: parseInt(e.target.value) })
                  }
                  className="input-field"
                />
              </div>
            </div>
          )}
        </div>

        {isFollowUp &&
          q.showWhen &&
          needsOptions(
            questions.find((pq) => pq.id === q.showWhen?.questionId)?.type ||
              "text"
          ) && (
            <div className="mt-4">
              <label className="block text-sm font-medium text-primary-600 mb-2">
                Show when parent answer is
              </label>
              <select
                value={q.showWhen.value as string}
                onChange={(e) =>
                  updateQuestion(q.id, {
                    showWhen: { ...q.showWhen, value: e.target.value },
                  })
                }
                className="input-field"
              >
                {questions
                  .find((pq) => pq.id === q.showWhen?.questionId)
                  ?.options?.map((option) => (
                    <option key={`${q.id}-option-${option}`} value={option}>
                      {option}
                    </option>
                  ))}
              </select>
            </div>
          )}

        {followUpQuestions.map((followUp, i) =>
          renderQuestion(followUp, i, true)
        )}
      </div>
    );
  };

  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h3 className="text-lg font-medium text-primary-600">Questions</h3>
        <button
          type="button"
          onClick={() => addQuestion()}
          className="btn-primary flex items-center"
        >
          <PlusSquare className="w-4 h-4 mr-2" />
          Add Question
        </button>
      </div>

      <div className="space-y-4">
        {mainQuestions.map((q, index) => renderQuestion(q, index))}
      </div>
    </div>
  );
}

import React from "react";
import { X, Mail } from "lucide-react";
import type { Question, Response } from "../types";
import { formatTimestamp } from "../utils/dateUtils";
import FilePreview from "./FilePreview";
import SubmissionMetadata from "./SubmissionMetadata";
import { useNotification } from "../context/NotificationContext";

interface ResponseDetailsProps {
  response: Response;
  question: Question;
  onClose: () => void;
}

export default function ResponseDetails({
  response,
  question,
  onClose,
}: ResponseDetailsProps) {
  const { showInfo } = useNotification();

  const handleSendToMail = () => {
    showInfo("This feature is coming soon!", "Coming Soon");
  };

  const renderAnswer = (questionType: string, answer: any) => {
    if (questionType === "file" || questionType === "radio-image") {
      return <FilePreview data={answer as string} />;
    }

    if (Array.isArray(answer)) {
      return (
        <ul className="list-disc list-inside">
          {answer.map((item, index) => (
            <li key={index} className="text-gray-700 dark:text-gray-300">
              {item}
            </li>
          ))}
        </ul>
      );
    }

    if (typeof answer === "object") {
      return (
        <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
          <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
            {Object.entries(answer).map(([key, value]) => (
              <tr key={key}>
                <td className="py-2 pr-4 font-medium text-gray-700 dark:text-gray-300">
                  {key}:
                </td>
                <td className="py-2 text-gray-600 dark:text-gray-400">
                  {String(value)}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      );
    }

    return <p className="text-gray-700 dark:text-gray-300">{String(answer)}</p>;
  };

  // Get all questions from sections or fallback to followUpQuestions
  const allQuestions =
    question.sections.length > 0
      ? question.sections.flatMap((section) => section.questions)
      : question.followUpQuestions;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow-xl max-w-2xl w-full max-h-[90vh] overflow-y-auto m-4">
        <div className="sticky top-0 bg-white dark:bg-gray-800 border-b dark:border-gray-700 px-6 py-4 flex justify-between items-center">
          <div>
            <h3 className="text-xl font-semibold text-gray-900 dark:text-white">
              Response Details
            </h3>
            <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
              Submitted on {formatTimestamp(response.timestamp)}
            </p>
          </div>
          <div className="flex items-center space-x-2">
            <button
              onClick={handleSendToMail}
              className="flex items-center px-3 py-2 text-gray-700 dark:text-gray-300 bg-blue-50 dark:bg-blue-900/30 rounded-lg hover:bg-blue-100 dark:hover:bg-blue-900/50 transition-colors"
            >
              <Mail className="w-4 h-4 mr-2" />
              Send to Mail
            </button>
            <button
              onClick={onClose}
              className="text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-300"
            >
              <X className="w-6 h-6" />
            </button>
          </div>
        </div>

        <div className="px-6 py-4">
          {/* Submission Metadata */}
          {response.submissionMetadata && (
            <div className="mb-6">
              <SubmissionMetadata metadata={response.submissionMetadata} />
            </div>
          )}

          <div className="space-y-6">
            {allQuestions.map((q) => {
              const answer = response.answers[q.id];
              if (!answer) return null;

              return (
                <div key={q.id} className="border-b dark:border-gray-700 pb-4">
                  <h4 className="font-medium text-gray-900 dark:text-white mb-2">
                    {q.text}
                  </h4>
                  <div className="text-gray-700 dark:text-gray-300">
                    {renderAnswer(q.type, answer)}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from "react";
