  const allFormSections =
    question.sections && question.sections.length > 0
      ? question.sections
      : [
          {
            id: "default",
            title: question.title,
            description: question.description,
            questions: [],
          },
        ];

  const getAvailableSections = () => {
    if (!allFormSections || !Array.isArray(allFormSections)) {
      return [];
    }

    const baseSections: typeof allFormSections = [];
    const linkedSections: typeof allFormSections = [];

    for (const section of allFormSections) {
      if (!section) continue;

      if (!section.linkedToOption && !section.linkedToQuestionId) {
        baseSections.push(section);
      } else {
        const allQuestions = allFormSections
          .flatMap((s) => s?.questions || [])
          .filter((q) => q && !q.showWhen);

        for (const question of allQuestions) {
          const answer = answers[question.id];
          if (answer && question.followUpConfig?.[answer]?.linkedSectionId === section.id) {
            linkedSections.push(section);
            break;
          }
        }
      }
    }

    const result: typeof allFormSections = [];
    const addedSectionIds = new Set<string>();

    for (const baseSection of baseSections) {
      result.push(baseSection);
      addedSectionIds.add(baseSection.id);

      const questionsInSection = (baseSection.questions || []).filter(
        (q) => q && !q.showWhen
      );

      for (const question of questionsInSection) {
        const answer = answers[question.id];
        if (answer && question.followUpConfig?.[answer]?.linkedSectionId) {
          const linkedSectionId = question.followUpConfig[answer].linkedSectionId;
          const linkedSection = linkedSections.find(
            (s) => s && s.id === linkedSectionId && !addedSectionIds.has(s.id)
          );
          if (linkedSection) {
            result.push(linkedSection);
            addedSectionIds.add(linkedSection.id);
          }
        }
      }
    }

    for (const linkedSection of linkedSections) {
      if (!addedSectionIds.has(linkedSection.id)) {
        result.push(linkedSection);
        addedSectionIds.add(linkedSection.id);
      }
    }

    return result;
  };

  const formSections = getAvailableSections();

  console.log("All form sections:", allFormSections);
  console.log("Available sections:", formSections);
  console.log("Current answers:", answers);

  // Debug: Log all questions in current section
  if (formSections[currentSectionIndex]) {
    console.log(
      "Current section questions:",
      formSections[currentSectionIndex].questions
    );
    console.log(
      "Questions with showWhen:",
      formSections[currentSectionIndex].questions.filter((q) => q.showWhen)
    );
  }

  if (submitted) {
    return <ThankYouMessage />;
  }

  if (isChildForm && !selectedParentResponse) {
    if (parentResponses.length === 0) {
      return (
        <div className="max-w-4xl mx-auto p-6 bg-white dark:bg-gray-800 rounded-lg shadow-lg">
          <div className="flex items-center space-x-2 text-amber-600 dark:text-amber-500 mb-4">
            <AlertCircle className="w-5 h-5" />
            <h2 className="text-xl font-semibold">
              Parent Form Response Required
            </h2>
          </div>
          <p className="text-gray-600 dark:text-gray-400 mb-6">
            This is a follow-up form that requires a response to "
            {parentForm?.title}" first. Please complete the parent form before
            proceeding.
          </p>
          <button
            onClick={() => navigate(`/forms/${question.parentFormId}/respond`)}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
          >
            Respond to Parent Form
          </button>
        </div>
      );
    }

    return (
      <div className="max-w-4xl mx-auto p-6 bg-white dark:bg-gray-800 rounded-lg shadow-lg">
        <button
          onClick={() => navigate(-1)}
          className="flex items-center text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200 mb-6"
        >
          <ArrowLeft className="w-5 h-5 mr-2" />
          Back
        </button>

        <h2 className="text-2xl font-bold mb-6 text-gray-900 dark:text-white">
          Select Parent Response
        </h2>

        <ParentResponseSelector
          parentForm={parentForm!}
          responses={parentResponses}
          onSelect={setSelectedParentResponse}
        />
      </div>
    );
  }

  const findLinkedFormInAnswers = (): string | null => {
    const checkQuestionRecursively = (
      q: any,
      answers: Record<string, any>
    ): string | null => {
      const answer = answers[q.id];
      
      if (answer && q.followUpConfig?.[answer]?.linkedFormId) {
        return q.followUpConfig[answer].linkedFormId;
      }

      if (
        q.followUpQuestions &&
        Array.isArray(q.followUpQuestions) &&
        answer
      ) {
        for (const followUp of q.followUpQuestions) {
          if (
            followUp.showWhen?.questionId === q.id &&
            followUp.showWhen?.value === answer
          ) {
            const result = checkQuestionRecursively(followUp, answers);
            if (result) return result;
          }
        }
      }

      return null;
    };

    for (const section of allFormSections) {
      for (const q of section.questions) {
        if (!q.showWhen) {
          const result = checkQuestionRecursively(q, answers);
          if (result) return result;
        }
      }
    }
    return null;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    let isValid = true;
    formSections.forEach((section) => {
      const visibleQuestions = getOrderedVisibleQuestions(
        section.questions,
        answers
      );
      const hasRequiredAnswers = visibleQuestions.every(
        (q) => !q.required || answers[q.id]
      );
      if (!hasRequiredAnswers) {
        isValid = false;
      }
    });

    if (!isValid) {
      alert(
        "Please fill in all required fields in all sections before submitting."
      );
      return;
    }

    const response: Response = {
      id: crypto.randomUUID(),
      questionId: question.id,
      answers,
      timestamp: new Date().toISOString(),
      parentResponseId: selectedParentResponse?.id,
    };

    try {
      // Save response to backend
      await apiClient.submitResponse(question.id, response);

      // Also save to local storage for backward compatibility
      responsesApi.save(response);

      // Check if there's a follow-up form linked to any selected option
      const linkedFormId = findLinkedFormInAnswers();
      if (linkedFormId) {
        setTimeout(() => {
          navigate(`/forms/${linkedFormId}/respond?parentResponse=${response.id}`);
        }, 500);
        return;
      }

      if (onSubmit) {
        onSubmit(response);
      }
      setSubmitted(true);
    } catch (err: any) {
      console.error("Error submitting response:", err);
      alert("Failed to submit response. Please try again.");
    }
  };

  const handleAnswerChange = (questionId: string, value: any) => {
    setAnswers((prev) => ({
      ...prev,
      [questionId]: value,
    }));
  };

  const handleNext = () => {
    const currentSection = formSections[currentSectionIndex];
    if (!currentSection) return;

    const visibleQuestions = getOrderedVisibleQuestions(
      currentSection.questions,
      answers
    );
    const hasRequiredAnswers = visibleQuestions.every(
      (q) => !q.required || answers[q.id]
    );

    if (!hasRequiredAnswers) {
      alert(
        "Please fill in all required fields in this section before proceeding."
      );
      return;
    }

    if (currentSectionIndex + 1 < formSections.length) {
      setCurrentSectionIndex((prev) => prev + 1);
      window.scrollTo({ top: 0, behavior: "smooth" });
    }
  };

  const handlePrevious = () => {
    if (currentSectionIndex > 0) {
      setCurrentSectionIndex((prev) => prev - 1);
      window.scrollTo({ top: 0, behavior: "smooth" });
    }
  };

  useEffect(() => {
    if (currentSectionIndex >= formSections.length && formSections.length > 0) {
      setCurrentSectionIndex(formSections.length - 1);
    }
  }, [formSections.length]);

  const currentSection = formSections[currentSectionIndex];
  const isLastSection = currentSectionIndex === formSections.length - 1;
  const isFirstSection = currentSectionIndex === 0;

  return (
    <div className="min-h-screen bg-gradient-to-br from-primary-50 via-white to-primary-50 py-12 px-4">
      <div className="max-w-4xl mx-auto">
        {/* Back Button */}
        <button
          onClick={() => navigate(-1)}
          className="flex items-center text-primary-600 hover:text-primary-800 mb-6 transition-colors font-medium"
        >
          <ArrowLeft className="w-5 h-5 mr-2" />
          Back to Forms
        </button>

        {/* Main Form Card */}
        <div className="bg-white rounded-2xl shadow-xl border border-neutral-200 overflow-hidden">
          {/* Form Header */}
          <div className="bg-gradient-to-r from-primary-600 to-primary-700 px-8 py-10 text-white">
            <h1 className="text-3xl font-bold mb-3">{question.title}</h1>
            {question.description && (
              <p className="text-primary-100 text-lg leading-relaxed">
                {question.description}
              </p>
            )}
          </div>

          {question.imageUrl && (
            <div className="relative h-64 overflow-hidden">
              <img
                src={question.imageUrl}
                alt="Form header"
                className="w-full h-full object-cover"
              />
            </div>
          )}

          {/* Parent Response Info */}
          {isChildForm && selectedParentResponse && parentForm && (
            <div className="mx-8 mt-8 p-6 bg-primary-50 border border-primary-200 rounded-xl">
              <h2 className="text-lg font-semibold text-primary-800 mb-4 flex items-center">
                <AlertCircle className="w-5 h-5 mr-2" />
                Parent Form Response
              </h2>
              <div className="space-y-3">
                {parentForm.followUpQuestions.map((q) => (
                  <div key={q.id} className="flex flex-col">
                    <span className="font-medium text-primary-700 text-sm mb-1">
                      {q.text}
                    </span>
                    <span className="text-primary-600 bg-white px-3 py-2 rounded-lg border border-primary-200">
                      {Array.isArray(selectedParentResponse.answers[q.id])
                        ? selectedParentResponse.answers[q.id].join(", ")
                        : selectedParentResponse.answers[q.id]}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Form Content */}
          <form onSubmit={handleSubmit} className="px-8 py-8">
            {/* Progress Indicator */}
            {formSections.length > 1 && (
              <div className="mb-8 pb-6 border-b border-neutral-200">
                <div className="flex items-center justify-between mb-4">
                  <span className="text-sm font-medium text-primary-700">
                    Section {currentSectionIndex + 1} of {formSections.length}
                  </span>
                  <span className="text-sm text-primary-500">
                    {Math.round(
                      ((currentSectionIndex + 1) / formSections.length) * 100
                    )}
                    % Complete
                  </span>
                </div>
                <div className="flex items-center space-x-2">
                  {formSections.map((_, index) => (
                    <div
                      key={index}
                      className="flex-1 h-2 rounded-full overflow-hidden bg-neutral-200"
                    >
                      <div
                        className={`h-full transition-all duration-300 ${
                          index === currentSectionIndex
                            ? "bg-primary-600"
                            : index < currentSectionIndex
                            ? "bg-green-500"
                            : "bg-transparent"
                        }`}
                      />
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Section Header */}
            {currentSection.title !== question.title && (
              <div className="mb-8 pb-6 border-b border-neutral-200">
                <h2 className="text-2xl font-bold text-primary-800 mb-2">
                  {currentSection.title}
                </h2>
                {currentSection.description && (
                  <p className="text-primary-600 leading-relaxed">
                    {currentSection.description}
                  </p>
                )}
              </div>
            )}

            {/* Questions */}
            <div className="space-y-8">
              {getOrderedVisibleQuestions(
                currentSection.questions,
                answers
              ).map((q) => (
                <div
                  key={q.id}
                  className={`${
                    q.showWhen
                      ? "ml-6 pl-6 border-l-4 border-primary-200 bg-primary-50/30 py-4 rounded-r-lg"
                      : ""
                  }`}
                >
                  <QuestionRenderer
                    question={q}
                    value={answers[q.id]}
                    onChange={(value) => handleAnswerChange(q.id, value)}
                  />
                </div>
              ))}
            </div>

            {/* Navigation Buttons */}
            <div className="flex justify-between items-center pt-8 mt-8 border-t border-neutral-200">
              {!isFirstSection ? (
                <button
                  type="button"
                  onClick={handlePrevious}
                  className="flex items-center px-6 py-3 bg-neutral-100 text-primary-700 rounded-lg hover:bg-neutral-200 transition-colors font-medium border border-neutral-300"
                >
                  <ArrowLeft className="w-5 h-5 mr-2" />
                  Previous
                </button>
              ) : (
                <div></div>
              )}

              {!isLastSection ? (
                <button
                  type="button"
                  onClick={handleNext}
                  className="flex items-center px-6 py-3 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors font-medium shadow-lg shadow-primary-600/30"
                >
                  Next Section
                  <ArrowLeft className="w-5 h-5 ml-2 rotate-180" />
                </button>
              ) : (
                <button
                  type="submit"
                  className="flex items-center px-8 py-3 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors font-medium shadow-lg shadow-green-600/30"
                >
                  <Send className="w-5 h-5 mr-2" />
                  Submit Response
                </button>
              )}
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

import React from "react";
import { X } from "lucide-react";
import type { Question, Response, Section } from "../types";
import { formatTimestamp } from "../utils/dateUtils";
import FormHeader from "./preview/FormHeader";
import SectionContent from "./preview/SectionContent";

interface ResponseFormViewProps {
  response: Response;
  question: Question;
  onClose: () => void;
}

export default function ResponseFormView({
  response,
  question,
  onClose,
}: ResponseFormViewProps) {
  // Initialize sections if they don't exist
  const sections: Section[] =
    question.sections?.length > 0
      ? question.sections
      : [
          {
            id: "default",
            title: question.title,
            description: question.description,
            questions: question.followUpQuestions,
          },
        ];

  // No-op for read-only
  const handleAnswerChange = () => {};

  return (
    <div className="fixed inset-0 bg-white flex items-center justify-center z-50">
      <div className="bg-white rounded-lg shadow-xl w-full max-w-4xl m-4 max-h-[90vh] overflow-hidden flex flex-col">
        <div className="sticky top-0 bg-white border-b border-gray-200 px-6 py-4 flex justify-between items-center">
          <div>
            <h3 className="text-xl font-semibold text-gray-900">
              Response View
            </h3>
            <p className="text-sm text-gray-500 mt-1">
              Submitted on {formatTimestamp(response.timestamp)}
            </p>
          </div>
          <button
            onClick={onClose}
            className="text-gray-500 hover:text-gray-700"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">
          <FormHeader
            title={question.title}
            description={question.description}
            imageUrl={question.imageUrl}
          />

          <form className="space-y-8">
            {sections.length > 1 && (
              <div className="text-center text-sm text-gray-500">
                Section Progress: Viewing Response
              </div>
            )}

            {sections.map((section, index) => (
              <SectionContent
                key={section.id}
                section={section}
                formTitle={question.title}
                answers={response.answers}
                onAnswerChange={handleAnswerChange}
                readOnly={true}
              />
            ))}
          </form>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from "react";
import {
  Download,
  Edit2,
  Eye,
  UserPlus,
  ChevronRight,
  MessageSquarePlus,
  ArrowUpRight,
  Trash2,
} from "lucide-react";
import { useParams, useNavigate } from "react-router-dom";
import type { Question, Response } from "../types";
import { exportResponsesToExcel } from "../utils/exportUtils";
import ResponseEdit from "./ResponseEdit";
import ResponseDetails from "./ResponseDetails";
import StaffAssignment from "./staff/StaffAssignment";
import { responsesApi, questionsApi } from "../api/storage";
import FollowUpModal from "./settings/forms/FollowUpModal";
import ResponsePreview from "./responses/ResponsePreview";
import { apiClient } from "../api/client";
import { useAuth } from "../context/AuthContext";
import { useNotification } from "../context/NotificationContext";

export default function ResponseList() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const { showSuccess, showError, showConfirm } = useNotification();
  const [editingResponse, setEditingResponse] = useState<Response | null>(null);
  const [viewingResponse, setViewingResponse] = useState<Response | null>(null);
  const [assigningResponse, setAssigningResponse] = useState<Response | null>(
    null
  );
  const [localResponses, setLocalResponses] = useState<Response[]>([]);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [expandedForms, setExpandedForms] = useState<Set<string>>(new Set());
  const [showFollowUpModal, setShowFollowUpModal] = useState(false);
  const [selectedParentForm, setSelectedParentForm] = useState<Question | null>(
    null
  );
  const [selectedResponse, setSelectedResponse] = useState<Response | null>(
    null
  );
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      if (!id) return;

      try {
        setLoading(true);
        setError(null);

        // Fetch form data and responses in parallel
        const [formResult, responsesResult, allFormsResult] = await Promise.all(
          [
            apiClient.getForm(id),
            apiClient.getFormResponses(id),
            apiClient.getForms(),
          ]
        );

        // Transform responses to match expected format
        const transformedResponses = responsesResult.responses.map(
          (response: any) => ({
            id: response._id,
            questionId: response.formId,
            answers: response.answers,
            timestamp: response.createdAt,
            assignedTo: response.assignedTo,
            assignedAt: response.assignedAt,
            parentResponseId: response.parentResponseId,
          })
        );

        // Transform forms to match expected format
        const transformedForms = allFormsResult.forms.map((form: any) => ({
          id: form._id,
          title: form.title,
          description: form.description,
          sections: form.sections,
          followUpQuestions: form.followUpQuestions,
          parentFormId: form.parentFormId,
          createdAt: form.createdAt,
          updatedAt: form.updatedAt,
        }));

        // Include the specific form if it's not in allForms (in case of filtering or timing issues)
        const specificForm = {
          id: formResult.form._id,
          title: formResult.form.title,
          description: formResult.form.description,
          sections: formResult.form.sections,
          followUpQuestions: formResult.form.followUpQuestions,
          parentFormId: formResult.form.parentFormId,
          createdAt: formResult.form.createdAt,
          updatedAt: formResult.form.updatedAt,
        };

        const allForms = transformedForms.some((f) => f.id === specificForm.id)
          ? transformedForms
          : [...transformedForms, specificForm];

        setQuestions(allForms);
        setLocalResponses(transformedResponses);
      } catch (err) {
        console.error("Error fetching data:", err);
        setError("Failed to load responses. Please try again.");
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [id]);

  const mainForm = questions.find((q) => q.id === id);
  const allChildForms = questions.filter((q) => {
    let currentId = q.parentFormId;
    while (currentId) {
      if (currentId === id) return true;
      const parentForm = questions.find((pf) => pf.id === currentId);
      currentId = parentForm?.parentFormId;
    }
    return false;
  });

  const toggleFormExpansion = (formId: string) => {
    setExpandedForms((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(formId)) {
        newSet.delete(formId);
      } else {
        newSet.add(formId);
      }
      return newSet;
    });
  };

  const handleExport = (form: Question) => {
    const formResponses = localResponses.filter(
      (r) => r.questionId === form.id
    );
    exportResponsesToExcel(formResponses, form);
  };

  const handleEdit = (response: Response) => {
    setEditingResponse(response);
  };

  const handleView = (response: Response) => {
    const form = questions.find((q) => q.id === response.questionId);
    if (form) {
      setViewingResponse({ ...response, questionId: form.id });
    }
  };

  const handleAssignStaff = (response: Response) => {
    setAssigningResponse(response);
  };

  const handleCreateChildForm = (parentForm: Question) => {
    setSelectedParentForm(parentForm);
    setShowFollowUpModal(true);
  };

  const handleFollowUpForm = (response: Response) => {
    const followUpForms = questions.filter(
      (q) => q.parentFormId === response.questionId
    );
    setSelectedResponse(response);

    if (followUpForms.length === 1) {
      navigate(
        `/forms/${followUpForms[0].id}/respond?parentResponse=${response.id}`
      );
    } else if (followUpForms.length > 1) {
      navigate(`/forms?parentResponse=${response.id}`);
    } else {
      alert("No follow-up forms available for this response.");
    }
  };

  const handleViewParentResponse = (response: Response) => {
    const parentResponse = localResponses.find(
      (r) => r.id === response.parentResponseId
    );
    if (parentResponse) {
      const parentForm = questions.find(
        (q) => q.id === parentResponse.questionId
      );
      if (parentForm) {
        setViewingResponse({ ...parentResponse, questionId: parentForm.id });
      }
    }
  };

  const handleDelete = async (response: Response) => {
    showConfirm(
      "Are you sure you want to delete this response? This action cannot be undone.",
      async () => {
        try {
          await apiClient.deleteResponse(response.id);
          setLocalResponses((prevResponses) =>
            prevResponses.filter((r) => r.id !== response.id)
          );
          showSuccess("Response deleted successfully", "Success");
        } catch (err) {
          console.error("Error deleting response:", err);
          showError("Failed to delete response. Please try again.", "Error");
        }
      },
      "Delete Response",
      "Delete",
      "Cancel"
    );
  };

  const handleSaveEdit = async (updatedResponse: Response) => {
    try {
      await apiClient.updateResponse(updatedResponse.id, updatedResponse);
      setLocalResponses((prevResponses) =>
        prevResponses.map((r) =>
          r.id === updatedResponse.id ? updatedResponse : r
        )
      );
      setEditingResponse(null);
    } catch (err) {
      console.error("Error updating response:", err);
      alert("Failed to update response. Please try again.");
    }
  };

  const handleAssignmentComplete = async (
    responseId: string,
    staffId: string
  ) => {
    try {
      await apiClient.assignResponse(responseId, staffId);
      const updatedResponse = localResponses.find((r) => r.id === responseId);
      if (updatedResponse) {
        const newResponse = {
          ...updatedResponse,
          assignedTo: staffId,
          assignedAt: new Date().toISOString(),
        };
        setLocalResponses((prevResponses) =>
          prevResponses.map((r) => (r.id === responseId ? newResponse : r))
        );
      }
      setAssigningResponse(null);
    } catch (err) {
      console.error("Error assigning response:", err);
      alert("Failed to assign response. Please try again.");
    }
  };

  const handleFollowUpSave = async (newQuestion: Question) => {
    try {
      const formData = {
        ...newQuestion,
        ...(user?.tenantId && { tenantId: user.tenantId }),
      };
      await apiClient.createForm(formData);
      setShowFollowUpModal(false);
      setSelectedParentForm(null);
      navigate(`/forms/${newQuestion.id}/edit`);
    } catch (err) {
      console.error("Error creating follow-up form:", err);
      alert("Failed to create follow-up form. Please try again.");
    }
  };

  const hasFollowUpResponse = (parentResponseId: string) => {
    return localResponses.some((r) => r.parentResponseId === parentResponseId);
  };

  const renderFormResponses = (form: Question | undefined, level = 0) => {
    if (!form) return null;

    const formResponses = localResponses.filter(
      (r) => r.questionId === form.id
    );
    const isExpanded = expandedForms.has(form.id);
    const hasFollowUpForms = questions.some((q) => q.parentFormId === form.id);
    const childForms = questions.filter((q) => q.parentFormId === form.id);

    const allQuestions =
      form.sections && form.sections.length > 0
        ? form.sections.flatMap((section) => section.questions)
        : form.followUpQuestions || [];

    return (
      <div
        key={form.id}
        className={`mb-8 ${
          level > 0
            ? "ml-8 border-l-2 border-blue-200 dark:border-blue-800 pl-4"
            : ""
        }`}
      >
        <div className="flex justify-between items-center mb-4">
          <div className="flex items-center">
            <button
              onClick={() => toggleFormExpansion(form.id)}
              className="mr-2 transform transition-transform"
            >
              <ChevronRight
                className={`w-5 h-5 transition-transform ${
                  isExpanded ? "transform rotate-90" : ""
                }`}
              />
            </button>
            <h3 className="text-xl font-semibold text-gray-900 dark:text-white">
              {form.title}
            </h3>
          </div>
          <div className="flex items-center space-x-2">
            <button
              onClick={() => handleExport(form)}
              className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700"
            >
              <Download className="w-5 h-5 mr-2" />
              Export to Excel
            </button>
          </div>
        </div>

        {isExpanded && (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
              <thead className="bg-gray-50 dark:bg-gray-700">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">
                    Timestamp
                  </th>
                  {allQuestions.map((q) => (
                    <th
                      key={q.id}
                      className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider"
                    >
                      {q.text}
                    </th>
                  ))}
                  <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
                {formResponses.map((response) => (
                  <tr
                    key={response.id}
                    className={`${
                      hasFollowUpResponse(response.id)
                        ? "bg-blue-50 dark:bg-blue-900/20"
                        : ""
                    }`}
                  >
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                      {new Date(response.timestamp).toLocaleString()}
                    </td>
                    {allQuestions.map((q) => (
                      <td
                        key={q.id}
                        className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 dark:text-gray-100"
                      >
                        {Array.isArray(response.answers[q.id])
                          ? (response.answers[q.id] as string[]).join(", ")
                          : (response.answers[q.id] as string)}
                      </td>
                    ))}
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm space-x-2">
                      <button
                        onClick={() => handleView(response)}
                        className="inline-flex items-center text-purple-600 hover:text-purple-800"
                      >
                        <Eye className="w-4 h-4 mr-1" />
                        View
                      </button>
                      <button
                        onClick={() => handleEdit(response)}
                        className="inline-flex items-center text-blue-600 hover:text-blue-800 ml-2"
                      >
                        <Edit2 className="w-4 h-4 mr-1" />
                        Edit
                      </button>
                      {hasFollowUpForms && (
                        <button
                          onClick={() => handleFollowUpForm(response)}
                          className="inline-flex items-center text-green-600 hover:text-green-800 ml-2"
                        >
                          <MessageSquarePlus className="w-4 h-4 mr-1" />
                          Follow-up
                        </button>
                      )}
                      {response.parentResponseId && (
                        <button
                          onClick={() => handleViewParentResponse(response)}
                          className="inline-flex items-center text-indigo-600 hover:text-indigo-800 ml-2"
                        >
                          <ArrowUpRight className="w-4 h-4 mr-1" />
                          Parent
                        </button>
                      )}
                      <button
                        onClick={() => handleAssignStaff(response)}
                        className="inline-flex items-center text-green-600 hover:text-green-800 ml-2"
                      >
                        <UserPlus className="w-4 h-4 mr-1" />
                        Assign
                      </button>
                      <button
                        onClick={() => handleDelete(response)}
                        className="inline-flex items-center text-red-600 hover:text-red-800 ml-2"
                      >
                        <Trash2 className="w-4 h-4 mr-1" />
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>

            {formResponses.length === 0 && (
              <p className="text-center text-gray-500 dark:text-gray-400 py-8">
                No responses yet
              </p>
            )}
          </div>
        )}

        {/* Render child forms recursively */}
        {isExpanded &&
          childForms.map((childForm) =>
            renderFormResponses(childForm, level + 1)
          )}
      </div>
    );
  };

  // Loading state
  if (loading) {
    return (
      <div className="max-w-6xl mx-auto p-6 bg-white dark:bg-gray-800 rounded-lg shadow-lg">
        <div className="flex items-center justify-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-600"></div>
          <span className="ml-3 text-gray-600 dark:text-gray-400">
            Loading responses...
          </span>
        </div>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div className="max-w-4xl mx-auto p-6 bg-white dark:bg-gray-800 rounded-lg shadow-lg">
        <h2 className="text-2xl font-bold text-red-600 mb-4">Error</h2>
        <p className="text-gray-600 dark:text-gray-400 mb-4">{error}</p>
        <button
          onClick={() => window.location.reload()}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
        >
          Try Again
        </button>
      </div>
    );
  }

  if (!mainForm) {
    return (
      <div className="max-w-4xl mx-auto p-6 bg-white dark:bg-gray-800 rounded-lg shadow-lg">
        <h2 className="text-2xl font-bold text-red-600 mb-4">Form Not Found</h2>
        <p className="text-gray-600 dark:text-gray-400 mb-4">
          The form you're looking for doesn't exist or has been deleted.
        </p>
        <button
          onClick={() => navigate("/forms")}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
        >
          Return to Forms
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto p-6 bg-white dark:bg-gray-800 rounded-lg shadow-lg">
      {/* Render main form and its responses */}
      {renderFormResponses(mainForm)}

      {/* Render all child forms and their responses */}
      {allChildForms.map((childForm) => renderFormResponses(childForm, 1))}

      {editingResponse && (
        <ResponseEdit
          response={editingResponse}
          question={questions.find((q) => q.id === editingResponse.questionId)!}
          onSave={handleSaveEdit}
          onCancel={() => setEditingResponse(null)}
        />
      )}

      {viewingResponse && (
        <ResponseDetails
          response={viewingResponse}
          question={questions.find((q) => q.id === viewingResponse.questionId)!}
          onClose={() => setViewingResponse(null)}
        />
      )}

      {assigningResponse && (
        <StaffAssignment
          responseId={assigningResponse.id}
          onAssign={handleAssignmentComplete}
          onCancel={() => setAssigningResponse(null)}
        />
      )}

      {showFollowUpModal && selectedParentForm && (
        <FollowUpModal
          question={selectedParentForm}
          onClose={() => {
            setShowFollowUpModal(false);
            setSelectedParentForm(null);
          }}
          onSave={handleFollowUpSave}
        />
      )}

      {selectedResponse && (
        <ResponsePreview
          response={selectedResponse}
          question={
            questions.find((q) => q.id === selectedResponse.questionId)!
          }
          onClose={() => setSelectedResponse(null)}
        />
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { Save, X, UserCircle, Settings as SettingsIcon, FileText } from 'lucide-react';
import { useTheme } from '../context/ThemeContext';
import SettingsGeneral from './settings/SettingsGeneral';
import SettingsProfile from './settings/SettingsProfile';
import SettingsForms from './settings/SettingsForms';

interface SettingsProps {
  onClose: () => void;
}

type SettingsTab = 'general' | 'profile' | 'forms';

export default function Settings({ onClose }: SettingsProps) {
  const [activeTab, setActiveTab] = useState<SettingsTab>('general');

  const tabs = [
    { id: 'general', label: 'General', icon: SettingsIcon },
    { id: 'profile', label: 'Profile', icon: UserCircle },
    { id: 'forms', label: 'Forms', icon: FileText },
  ] as const;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50" onClick={(e) => {
      if (e.target === e.currentTarget) onClose();
    }}>
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-4xl m-4 flex flex-col" style={{ height: 'calc(100vh - 2rem)' }}>
        <div className="px-6 py-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center flex-shrink-0">
          <h3 className="text-xl font-semibold text-gray-900 dark:text-white">Settings</h3>
          <button
            onClick={onClose}
            className="text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-300"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="flex flex-1 min-h-0">
          <div className="w-64 border-r border-gray-200 dark:border-gray-700 flex-shrink-0 overflow-y-auto">
            <nav className="p-4 space-y-1">
              {tabs.map(({ id, label, icon: Icon }) => (
                <button
                  key={id}
                  onClick={() => setActiveTab(id as SettingsTab)}
                  className={`w-full flex items-center px-4 py-2 rounded-lg text-left ${
                    activeTab === id
                      ? 'bg-blue-50 text-blue-700 dark:bg-blue-900 dark:text-blue-200'
                      : 'text-gray-700 hover:bg-gray-50 dark:text-gray-300 dark:hover:bg-gray-700'
                  }`}
                >
                  <Icon className="w-5 h-5 mr-3" />
                  {label}
                </button>
              ))}
            </nav>
          </div>

          <div className="flex-1 overflow-y-auto">
            <div className="p-6">
              {activeTab === 'general' && <SettingsGeneral onClose={onClose} />}
              {activeTab === 'profile' && <SettingsProfile onClose={onClose} />}
              {activeTab === 'forms' && <SettingsForms />}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from "react";
import { useParams, useNavigate } from "react-router-dom";
import {
  Users,
  CheckCircle,
  Clock,
  XCircle,
  BarChart3,
  Calendar,
  FileText,
  ArrowLeft,
  TrendingUp,
  PieChart,
} from "lucide-react";
import { apiClient } from "../../api/client";
import ResponseQuestion from "./ResponseQuestion";

interface Response {
  id: string;
  questionId: string;
  answers: Record<string, any>;
  timestamp?: string;
  createdAt?: string; // MongoDB timestamp field
  parentResponseId?: string;
  assignedTo?: string;
  assignedAt?: string;
  verifiedBy?: string;
  verifiedAt?: string;
  status?: "pending" | "verified" | "rejected";
  notes?: string;
}

// Helper function to get the timestamp from response (handles both timestamp and createdAt)
const getResponseTimestamp = (response: Response): string | undefined => {
  return response.timestamp || response.createdAt;
};

interface Section {
  id: string;
  title: string;
  description?: string;
  questions: FollowUpQuestion[];
}

interface FollowUpQuestion {
  id: string;
  text: string;
  type: string;
  required?: boolean;
  options?: string[];
  description?: string;
  followUpQuestions?: FollowUpQuestion[];
}

interface Form {
  _id: string;
  id?: string;
  title: string;
  description?: string;
  createdAt?: string;
  isVisible?: boolean;
  logoUrl?: string;
  imageUrl?: string;
  sections?: Section[];
  followUpQuestions?: FollowUpQuestion[];
  parentFormId?: string;
  parentFormTitle?: string;
}

export default function FormAnalyticsDashboard() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [responses, setResponses] = useState<Response[]>([]);
  const [form, setForm] = useState<Form | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      if (!id) return;

      try {
        setLoading(true);
        setError(null);

        // Fetch form details
        const formData = await apiClient.getForm(id);
        setForm(formData.form);

        // Fetch responses for this form
        const responsesData = await apiClient.getFormResponses(id);
        setResponses(responsesData.responses || []);
      } catch (err) {
        console.error("Error fetching analytics data:", err);
        setError(
          err instanceof Error ? err.message : "Failed to load analytics"
        );
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [id]);

  const analytics = useMemo(() => {
    const total = responses.length;
    const pending = responses.filter(
      (r) => r.status === "pending" || !r.status
    ).length;
    const verified = responses.filter((r) => r.status === "verified").length;
    const rejected = responses.filter((r) => r.status === "rejected").length;

    const recentResponses = responses
      .filter((r) => getResponseTimestamp(r)) // Filter out responses without timestamps
      .sort((a, b) => {
        const timestampA = getResponseTimestamp(a);
        const timestampB = getResponseTimestamp(b);
        const dateA = timestampA ? new Date(timestampA).getTime() : 0;
        const dateB = timestampB ? new Date(timestampB).getTime() : 0;
        // Handle invalid dates
        if (isNaN(dateA) && isNaN(dateB)) return 0;
        if (isNaN(dateA)) return 1;
        if (isNaN(dateB)) return -1;
        return dateB - dateA;
      })
      .slice(0, 5);

    const responseTrend = responses.reduce(
      (acc: Record<string, number>, response) => {
        // Validate timestamp before processing
        const timestamp = getResponseTimestamp(response);
        if (timestamp) {
          const dateObj = new Date(timestamp);
          // Check if date is valid
          if (!isNaN(dateObj.getTime())) {
            const date = dateObj.toISOString().split("T")[0];
            acc[date] = (acc[date] || 0) + 1;
          }
        }
        return acc;
      },
      {}
    );

    const last7Days = Array.from({ length: 7 }, (_, i) => {
      const date = new Date();
      date.setDate(date.getDate() - i);
      return date.toISOString().split("T")[0];
    }).reverse();

    return {
      total,
      pending,
      verified,
      rejected,
      recentResponses,
      responseTrend,
      last7Days,
    };
  }, [responses]);

  if (loading) {
    return (
      <div className="p-6">
        <div className="text-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-600 mx-auto"></div>
          <p className="mt-4 text-primary-600">Loading analytics...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-6">
        <div className="text-center py-12">
          <p className="text-red-600">Error loading analytics: {error}</p>
          <button onClick={() => navigate(-1)} className="mt-4 btn-primary">
            Go Back
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <button
            onClick={() => navigate(-1)}
            className="p-2 text-primary-600 hover:bg-primary-50 rounded-lg transition-colors"
            title="Go back"
          >
            <ArrowLeft className="w-5 h-5" />
          </button>
          <div>
            <h1 className="text-2xl font-bold text-primary-800">
              Form Analytics
            </h1>
            <p className="text-primary-600">
              {form?.title || "Form"} - Response Analytics
            </p>
          </div>
        </div>
        <div className="text-sm text-primary-500">
          Last updated: {new Date().toLocaleString()}
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="card p-6">
          <div className="flex items-center">
            <div className="p-3 bg-blue-50 rounded-lg mr-4">
              <Users className="w-6 h-6 text-blue-600" />
            </div>
            <div>
              <div className="text-2xl font-bold text-primary-600">
                {analytics.total}
              </div>
              <div className="text-sm text-primary-500">Total Responses</div>
            </div>
          </div>
        </div>

        <div className="card p-6">
          <div className="flex items-center">
            <div className="p-3 bg-yellow-50 rounded-lg mr-4">
              <Clock className="w-6 h-6 text-yellow-600" />
            </div>
            <div>
              <div className="text-2xl font-bold text-primary-600">
                {analytics.pending}
              </div>
              <div className="text-sm text-primary-500">Pending</div>
            </div>
          </div>
        </div>

        <div className="card p-6">
          <div className="flex items-center">
            <div className="p-3 bg-green-50 rounded-lg mr-4">
              <CheckCircle className="w-6 h-6 text-green-600" />
            </div>
            <div>
              <div className="text-2xl font-bold text-primary-600">
                {analytics.verified}
              </div>
              <div className="text-sm text-primary-500">Completed</div>
            </div>
          </div>
        </div>

        <div className="card p-6">
          <div className="flex items-center">
            <div className="p-3 bg-red-50 rounded-lg mr-4">
              <XCircle className="w-6 h-6 text-red-600" />
            </div>
            <div>
              <div className="text-2xl font-bold text-primary-600">
                {analytics.rejected}
              </div>
              <div className="text-sm text-primary-500">Closed</div>
            </div>
          </div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Status Distribution Pie Chart */}
        <div className="card p-6">
          <h3 className="text-lg font-semibold text-primary-800 mb-4 flex items-center">
            <PieChart className="w-5 h-5 mr-2" />
            Response Status Distribution
          </h3>
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center">
                <div className="w-4 h-4 bg-yellow-500 rounded mr-3"></div>
                <span className="text-sm text-primary-600">Pending</span>
              </div>
              <span className="font-medium">{analytics.pending}</span>
            </div>
            <div className="flex items-center justify-between">
              <div className="flex items-center">
                <div className="w-4 h-4 bg-green-500 rounded mr-3"></div>
                <span className="text-sm text-primary-600">Completed</span>
              </div>
              <span className="font-medium">{analytics.verified}</span>
            </div>
            <div className="flex items-center justify-between">
              <div className="flex items-center">
                <div className="w-4 h-4 bg-red-500 rounded mr-3"></div>
                <span className="text-sm text-primary-600">Closed</span>
              </div>
              <span className="font-medium">{analytics.rejected}</span>
            </div>
          </div>
        </div>

        {/* Recent Activity */}
        <div className="card p-6">
          <h3 className="text-lg font-semibold text-primary-800 mb-4 flex items-center">
            <TrendingUp className="w-5 h-5 mr-2" />
            Recent Activity
          </h3>
          <div className="space-y-3">
            {analytics.recentResponses.length === 0 ? (
              <p className="text-primary-500 text-sm">No responses yet</p>
            ) : (
              analytics.recentResponses.map((response) => (
                <div
                  key={response.id}
                  className="flex items-center justify-between py-2 border-b border-neutral-100 last:border-b-0"
                >
                  <div className="flex items-center">
                    <div
                      className={`w-2 h-2 rounded-full mr-3 ${
                        response.status === "verified"
                          ? "bg-green-500"
                          : response.status === "rejected"
                          ? "bg-red-500"
                          : "bg-yellow-500"
                      }`}
                    ></div>
                    <div>
                      <p className="text-sm font-medium text-primary-800">
                        Response #{response.id.slice(-6)}
                      </p>
                      <p className="text-xs text-primary-500">
                        {getResponseTimestamp(response)
                          ? new Date(
                              getResponseTimestamp(response)!
                            ).toLocaleString()
                          : "No date"}
                      </p>
                    </div>
                  </div>
                  <span
                    className={`text-xs px-2 py-1 rounded-full ${
                      response.status === "verified"
                        ? "bg-green-100 text-green-800"
                        : response.status === "rejected"
                        ? "bg-red-100 text-red-800"
                        : "bg-yellow-100 text-yellow-800"
                    }`}
                  >
                    {response.status || "pending"}
                  </span>
                </div>
              ))
            )}
          </div>
        </div>
      </div>

      {/* Response Trend Chart */}
      <div className="card p-6">
        <h3 className="text-lg font-semibold text-primary-800 mb-4 flex items-center">
          <BarChart3 className="w-5 h-5 mr-2" />
          Response Trend (Last 7 Days)
        </h3>
        <div className="flex items-end space-x-2 h-32">
          {analytics.last7Days.map((date) => {
            const count = analytics.responseTrend[date] || 0;
            const maxCount = Math.max(
              ...Object.values(analytics.responseTrend)
            );
            const height = maxCount > 0 ? (count / maxCount) * 100 : 0;

            return (
              <div key={date} className="flex-1 flex flex-col items-center">
                <div
                  className="w-full bg-primary-500 rounded-t transition-all duration-300 hover:bg-primary-600"
                  style={{ height: `${Math.max(height, 5)}%` }}
                  title={`${count} responses on ${new Date(
                    date
                  ).toLocaleDateString()}`}
                ></div>
                <span className="text-xs text-primary-500 mt-2 transform -rotate-45 origin-top">
                  {new Date(date).toLocaleDateString("en-US", {
                    month: "short",
                    day: "numeric",
                  })}
                </span>
              </div>
            );
          })}
        </div>
      </div>

      {/* Question-wise Analytics */}
      {form && (
        <div className="card p-6">
          <ResponseQuestion question={form} responses={responses} />
        </div>
      )}

      {/* Form Details */}
      {form && (
        <div className="card p-6">
          <h3 className="text-lg font-semibold text-primary-800 mb-4 flex items-center">
            <FileText className="w-5 h-5 mr-2" />
            Form Details
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <h4 className="font-medium text-primary-800 mb-2">
                Form Information
              </h4>
              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-primary-600">Title:</span>
                  <span className="font-medium">{form.title}</span>
                </div>
                {form.description && (
                  <div className="flex justify-between">
                    <span className="text-primary-600">Description:</span>
                    <span className="font-medium">{form.description}</span>
                  </div>
                )}
                <div className="flex justify-between">
                  <span className="text-primary-600">Status:</span>
                  <span
                    className={`font-medium ${
                      form.isVisible ? "text-green-600" : "text-yellow-600"
                    }`}
                  >
                    {form.isVisible ? "Public" : "Private"}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-primary-600">Created:</span>
                  <span className="font-medium">
                    {form.createdAt
                      ? new Date(form.createdAt).toLocaleDateString()
                      : "Unknown"}
                  </span>
                </div>
              </div>
            </div>
            <div>
              <h4 className="font-medium text-primary-800 mb-2">
                Response Summary
              </h4>
              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-primary-600">Total Responses:</span>
                  <span className="font-medium">{analytics.total}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-primary-600">Completion Rate:</span>
                  <span className="font-medium">
                    {analytics.total > 0
                      ? Math.round((analytics.verified / analytics.total) * 100)
                      : 0}
                    %
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-primary-600">Average per Day:</span>
                  <span className="font-medium">
                    {analytics.total > 0
                      ? (analytics.total / 7).toFixed(1)
                      : "0"}
                  </span>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useMemo, useRef, useEffect, ChangeEvent } from "react";
import { useNavigate } from "react-router-dom";
import {
  FileText,
  Eye,
  Users,
  Calendar,
  Layers,
  ChevronRight,
  Trash2,
  Edit2,
  PlusCircle,
  Search,
  Copy,
  BarChart3,
  List,
  MoreVertical,
  Link2,
  Share2,
  Check,
  Upload,
  Download,
} from "lucide-react";
import { useForms, useResponses, useMutation } from "../../hooks/useApi";
import { apiClient } from "../../api/client";
import { useNotification } from "../../context/NotificationContext";
import { parseFormWorkbook, downloadFormImportTemplate } from "../../utils/exportUtils";
import type { Question as FormQuestion } from "../../types";

interface FormItem {
  _id: string;
  id?: string;
  title: string;
  description?: string;
  isVisible?: boolean;
  isActive?: boolean;
  sections?: any[];
  questions?: any[];
  createdAt?: string;
  createdBy?: any;
  responseCount?: number;
  parentFormId?: string | null;
  childForms?: Array<{
    formId: string;
    formTitle?: string;
    order?: number;
  }>;
}

interface ResponseData {
  responses: any[];
}

export default function FormsAnalytics() {
  const navigate = useNavigate();
  const { showSuccess, showError, showConfirm } = useNotification();
  const [searchTerm, setSearchTerm] = useState("");
  const [openMenuId, setOpenMenuId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  const { data: formsData, loading, error, execute: refetchForms } = useForms();

  const { data: responsesData, loading: responsesLoading } = useResponses();

  const deleteMutation = useMutation((id: string) => apiClient.deleteForm(id), {
    onSuccess: () => {
      refetchForms();
    },
  });

  const duplicateMutation = useMutation(
    (id: string) => apiClient.duplicateForm(id),
    {
      onSuccess: () => {
        refetchForms();
      },
    }
  );

  const visibilityMutation = useMutation(
    ({ id, isVisible }: { id: string; isVisible: boolean }) =>
      apiClient.updateFormVisibility(id, isVisible),
    {
      onSuccess: () => {
        refetchForms();
      },
    }
  );

  const forms = formsData?.forms || [];
  const parentForms = forms.filter((form: FormItem) => !form.parentFormId);
  const totalForms = parentForms.length;
  const activeFormsCount = parentForms.filter(
    (form: FormItem) => form.isActive === true
  ).length;
  const inactiveFormsCount = parentForms.filter(
    (form: FormItem) => form.isActive === false
  ).length;

  const formsMap = useMemo(() => {
    const map = new Map<string, FormItem>();
    forms.forEach((form) => {
      if (form._id) {
        map.set(form._id, form);
      }
      if (form.id) {
        map.set(form.id, form);
      }
    });
    return map;
  }, [forms]);

  const filteredForms = forms.filter((form: FormItem) => {
    const titleMatch = form.title
      ?.toLowerCase()
      .includes(searchTerm.toLowerCase());
    const descriptionMatch = form.description
      ?.toLowerCase()
      .includes(searchTerm.toLowerCase());
    return titleMatch || descriptionMatch;
  });

  const responseCounts = useMemo(() => {
    const allResponses =
      (responsesData as ResponseData | undefined)?.responses || [];
    return allResponses.reduce<Record<string, number>>((acc, response: any) => {
      if (response.questionId) {
        acc[response.questionId] = (acc[response.questionId] || 0) + 1;
      }
      return acc;
    }, {});
  }, [responsesData]);

  const groupedForms = useMemo(() => {
    const result = filteredForms.reduce(
      (acc, form) => {
        const key = form.parentFormId || form.id || form._id;
        if (!key) {
          return acc;
        }

        if (!acc[key]) {
          acc[key] = {
            parent: form.parentFormId ? null : form,
            children: [],
          };
        }

        if (form.parentFormId) {
          const parentKey = form.parentFormId;
          acc[parentKey] = acc[parentKey] || {
            parent: null,
            children: [],
          };
          acc[parentKey].children.push(form);
        } else {
          acc[key].parent = form;
        }

        return acc;
      },
      {} as Record<string, { parent: FormItem | null; children: FormItem[] }>
    );

    Object.values(result).forEach((group) => {
      const parent = group.parent;
      if (!parent) {
        return;
      }

      const childRefs = [...(parent.childForms || [])].sort(
        (a, b) => (a.order ?? 0) - (b.order ?? 0)
      );

      if (childRefs.length === 0) {
        return;
      }

      const existingChildrenMap = new Map<string, FormItem>();
      group.children.forEach((child) => {
        const childKey = child.id || child._id;
        if (childKey) {
          existingChildrenMap.set(childKey, child);
        }
      });

      const orderedChildren: FormItem[] = [];
      const usedChildIds = new Set<string>();

      childRefs.forEach((childRef, index) => {
        const childId = childRef.formId;
        if (!childId || usedChildIds.has(childId)) {
          return;
        }

        usedChildIds.add(childId);

        let child = existingChildrenMap.get(childId) || formsMap.get(childId);
        if (!child) {
          child = {
            _id: childId,
            id: childId,
            title: childRef.formTitle || "Linked Form",
            parentFormId: parent.id || parent._id || null,
          } as FormItem;
        }

        orderedChildren.push(child);
      });

      group.children.forEach((child) => {
        const childId = child.id || child._id;
        if (!childId || usedChildIds.has(childId)) {
          return;
        }
        orderedChildren.push(child);
      });

      group.children = orderedChildren;
    });

    return result;
  }, [filteredForms, formsMap]);

  const allForms = filteredForms.length;
  const totalResponses = filteredForms.reduce((sum, form) => {
    const formId = form.id || form._id;
    return sum + (responseCounts[formId] || form.responseCount || 0);
  }, 0);

  const handleDelete = async (id: string, title: string) => {
    showConfirm(
      `Are you sure you want to delete "${title}"? This action cannot be undone.`,
      async () => {
        await deleteMutation.mutate(id);
        showSuccess("Form deleted successfully", "Success");
      },
      "Delete Form",
      "Delete",
      "Cancel"
    );
  };

  const handleDuplicate = async (id: string) => {
    await duplicateMutation.mutate(id);
  };

  const handleToggleVisibility = async (
    id: string,
    currentVisibility: boolean | undefined
  ) => {
    await visibilityMutation.mutate({
      id,
      isVisible: !currentVisibility,
    });
  };

  const handleExportTemplate = () => {
    downloadFormImportTemplate();
  };

  const handleFileInputChange = async (event: ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) {
      return;
    }
    const isValidType =
      file.type ===
        "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" ||
      file.name.toLowerCase().endsWith(".xlsx");
    if (!isValidType) {
      showError("Please select a valid .xlsx file", "Invalid File");
      return;
    }

    setIsImporting(true);

    try {
      const parsed = await parseFormWorkbook(file);
      const formPayload = {
        ...parsed,
        isVisible: parsed.isVisible ?? true,
        followUpQuestions: parsed.followUpQuestions || [],
      } as FormQuestion;
      const created = await apiClient.createForm(formPayload);
      showSuccess("Form imported successfully", "Import Complete");
      if (created?.form?._id) {
        navigate(`/forms/${created.form._id}/edit`);
      }
      refetchForms();
    } catch (error: any) {
      showError(error?.message || "Failed to import form", "Import Failed");
    } finally {
      setIsImporting(false);
      if (fileInputRef.current) {
        fileInputRef.current.value = "";
      }
    }
  };

  const handleImportClick = () => {
    if (isImporting) {
      return;
    }
    fileInputRef.current?.click();
  };

  const toggleMenu = (formId: string) => {
    setOpenMenuId(openMenuId === formId ? null : formId);
  };

  const handleManageChildForms = (formId: string) => {
    // Navigate to edit page where ChildFormsManager is available
    navigate(`/forms/${formId}/edit`);
    setOpenMenuId(null);
    // Optionally scroll to child forms section after a short delay
    setTimeout(() => {
      const childFormsSection = document.querySelector(
        '[data-section="child-forms"]'
      );
      if (childFormsSection) {
        childFormsSection.scrollIntoView({
          behavior: "smooth",
          block: "start",
        });
      }
    }, 500);
  };

  const handleLinkToParent = (formId: string) => {
    // Navigate to edit page where user can manage parent-child relationships
    navigate(`/forms/${formId}/edit`);
    setOpenMenuId(null);
    setTimeout(() => {
      const childFormsSection = document.querySelector(
        '[data-section="child-forms"]'
      );
      if (childFormsSection) {
        childFormsSection.scrollIntoView({
          behavior: "smooth",
          block: "start",
        });
      }
    }, 500);
  };

  const handleCopyShareLink = (formId: string, tenantSlug?: string) => {
    const baseUrl = window.location.origin;
    const shareLink = tenantSlug
      ? `${baseUrl}/${tenantSlug}/form/${formId}`
      : `${baseUrl}/form/${formId}`;

    navigator.clipboard.writeText(shareLink).then(() => {
      setCopiedId(formId);
      setTimeout(() => setCopiedId(null), 2000);
    });
    setOpenMenuId(null);
  };

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setOpenMenuId(null);
      }
    };

    if (openMenuId) {
      document.addEventListener("mousedown", handleClickOutside);
    }

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [openMenuId]);

  if (loading || responsesLoading) {
    return (
      <div className="p-6">
        <div className="text-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-600 mx-auto"></div>
          <p className="mt-4 text-primary-600">Loading forms...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-6">
        <div className="text-center py-12">
          <p className="text-red-600">Error loading forms: {error}</p>
          <button onClick={() => refetchForms()} className="mt-4 btn-primary">
            Try Again
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      <input
        ref={fileInputRef}
        type="file"
        accept=".xlsx,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
        className="hidden"
        onChange={handleFileInputChange}
      />
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-primary-800">
            Service Analytics
          </h1>
          <p className="text-primary-600">
            Create, edit, and analyze service request forms
          </p>
        </div>
        <div className="flex flex-col sm:flex-row sm:items-center gap-2 w-full sm:w-auto">
          <button
            onClick={handleExportTemplate}
            className="btn-secondary flex items-center justify-center"
          >
            <Download className="w-4 h-4 mr-2" />
            Download Import Template
          </button>
          <button
            onClick={handleImportClick}
            className="btn-secondary flex items-center justify-center"
            disabled={isImporting}
          >
            <Upload className="w-4 h-4 mr-2" />
            {isImporting ? "Importing..." : "Import Form (Excel)"}
          </button>
          <button
            onClick={() =>
              navigate("/forms/create", { state: { mode: "create" } })
            }
            className="btn-primary flex items-center justify-center"
          >
            <PlusCircle className="w-4 h-4 mr-2" />
            Create New Service Form
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
        <div className="card p-6">
          <div className="flex items-center">
            <div className="p-3 bg-primary-50 rounded-lg mr-4">
              <FileText className="w-6 h-6 text-primary-600" />
            </div>
            <div>
              <div className="text-2xl font-medium text-primary-600">
                {totalForms}
              </div>
              <div className="text-sm text-primary-500">Total Forms</div>
              {/* <div className="mt-2 text-xs text-primary-500 space-x-2">
                <span className="inline-flex items-center px-2 py-1 bg-green-50 text-green-700 rounded-full">
                  Active: {activeFormsCount}
                </span>
                <span className="inline-flex items-center px-2 py-1 bg-red-50 text-red-700 rounded-full">
                  Inactive: {inactiveFormsCount}
                </span>
              </div> */}
            </div>
          </div>
        </div>
        <div className="card p-6">
          <div className="flex items-center">
            <div className="p-3 bg-primary-50 rounded-lg mr-4">
              <Users className="w-6 h-6 text-primary-600" />
            </div>
            <div>
              <div className="text-2xl font-medium text-primary-600">
                {totalResponses}
              </div>
              <div className="text-sm text-primary-500">Total Responses</div>
            </div>
          </div>
        </div>
        <div className="card p-6">
          <div className="flex items-center">
            <div className="p-3 bg-primary-50 rounded-lg mr-4">
              <Layers className="w-6 h-6 text-primary-600" />
            </div>
            <div>
              <div className="text-2xl font-medium text-primary-600">
                {Object.keys(groupedForms).length}
              </div>
              <div className="text-sm text-primary-500">Form Groups</div>
            </div>
          </div>
        </div>
      </div>

      <div className="relative">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-primary-400 w-4 h-4" />
        <input
          type="text"
          placeholder="Search service forms..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="pl-10 input-field"
        />
      </div>

      {filteredForms.length === 0 ? (
        <div className="text-center py-12 bg-white rounded-lg border border-neutral-200">
          <FileText className="w-12 h-12 text-primary-300 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-primary-600 mb-2">
            {searchTerm
              ? "No service forms found"
              : "No service forms created yet"}
          </h3>
          <p className="text-primary-500 mb-6">
            {searchTerm
              ? "Try adjusting your search criteria"
              : "Create your first service form to get started"}
          </p>
          {!searchTerm && (
            <button
              onClick={() => navigate("/forms/create")}
              className="btn-primary"
            >
              <PlusCircle className="w-4 h-4 mr-2" />
              Create Your First Form
            </button>
          )}
        </div>
      ) : (
        <div className="space-y-6">
          {Object.values(groupedForms).map(({ parent, children }) => {
            if (!parent) return null;

            const formId = parent.id || parent._id;
            const responseCount = responseCounts[formId] || 0;

            return (
              <div
                key={formId}
                className="card p-6 hover:border-primary-300 transition-colors duration-200"
              >
                <div className="flex items-start justify-between mb-4">
                  <div className="flex-1">
                    <h3 className="font-medium text-primary-800 mb-2 line-clamp-2">
                      {parent.title}
                    </h3>
                    <p className="text-sm text-primary-600 line-clamp-2">
                      {parent.description}
                    </p>
                  </div>
                </div>

                <div className="flex items-center justify-between text-xs text-primary-500 mb-4">
                  <div className="flex items-center">
                    <Users className="w-3 h-3 mr-1" />
                    {responseCount} responses
                  </div>
                  <div className="flex items-center gap-3">
                    {/* 3-dot menu */}
                    <div
                      className="relative"
                      ref={openMenuId === formId ? menuRef : null}
                    >
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          toggleMenu(formId);
                        }}
                        className="p-1.5 rounded-lg hover:bg-primary-100 transition-colors group"
                        title="More options"
                      >
                        <MoreVertical className="w-4 h-4 text-primary-500 group-hover:text-primary-700" />
                      </button>

                      {/* Dropdown menu */}
                      {openMenuId === formId && (
                        <div className="absolute right-0 top-8 w-56 bg-white rounded-lg shadow-xl border border-primary-200 py-2 z-50 animate-fadeIn">
                          <button
                            onClick={() => handleManageChildForms(formId)}
                            className="w-full flex items-center gap-3 px-4 py-2.5 text-sm text-primary-700 hover:bg-primary-50 transition-colors"
                          >
                            <div className="p-1.5 bg-gradient-to-br from-primary-100 to-purple-100 rounded-lg">
                              <Layers className="w-4 h-4 text-primary-600" />
                            </div>
                            <div className="text-left">
                              <div className="font-medium">
                                Manage Child Forms
                              </div>
                              <div className="text-xs text-primary-500">
                                Link & organize
                              </div>
                            </div>
                            {children.length > 0 && (
                              <span className="ml-auto px-2 py-0.5 bg-primary-600 text-white text-xs rounded-full">
                                {children.length}
                              </span>
                            )}
                          </button>

                          <button
                            onClick={() => handleLinkToParent(formId)}
                            className="w-full flex items-center gap-3 px-4 py-2.5 text-sm text-primary-700 hover:bg-primary-50 transition-colors"
                          >
                            <div className="p-1.5 bg-gradient-to-br from-blue-100 to-cyan-100 rounded-lg">
                              <Link2 className="w-4 h-4 text-blue-600" />
                            </div>
                            <div className="text-left">
                              <div className="font-medium">Link to Parent</div>
                              <div className="text-xs text-primary-500">
                                Connect forms
                              </div>
                            </div>
                          </button>

                          <div className="border-t border-primary-100 my-1"></div>

                          <button
                            onClick={() => handleCopyShareLink(formId)}
                            className="w-full flex items-center gap-3 px-4 py-2.5 text-sm text-primary-700 hover:bg-primary-50 transition-colors"
                          >
                            <div className="p-1.5 bg-gradient-to-br from-green-100 to-emerald-100 rounded-lg">
                              {copiedId === formId ? (
                                <Check className="w-4 h-4 text-green-600" />
                              ) : (
                                <Share2 className="w-4 h-4 text-green-600" />
                              )}
                            </div>
                            <div className="text-left">
                              <div className="font-medium">
                                {copiedId === formId
                                  ? "Link Copied!"
                                  : "Copy Share Link"}
                              </div>
                              <div className="text-xs text-primary-500">
                                {copiedId === formId
                                  ? "Ready to share"
                                  : "Share with others"}
                              </div>
                            </div>
                          </button>
                        </div>
                      )}
                    </div>

                    <div className="flex items-center">
                      <Calendar className="w-3 h-3 mr-1" />
                      {parent.createdAt
                        ? new Date(parent.createdAt).toLocaleDateString()
                        : "Unknown"}
                    </div>
                  </div>
                </div>

                <div className="flex items-center justify-between mb-4">
                  <span
                    className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${
                      parent.isVisible
                        ? "bg-green-100 text-green-800"
                        : "bg-yellow-100 text-yellow-800"
                    }`}
                  >
                    {parent.isVisible ? "Public" : "Private"}
                  </span>
                  <button
                    onClick={() =>
                      handleToggleVisibility(formId, parent.isVisible)
                    }
                    disabled={visibilityMutation.loading}
                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 ${
                      parent.isVisible
                        ? "bg-green-500 focus:ring-green-500"
                        : "bg-red-500 focus:ring-red-500"
                    } ${
                      visibilityMutation.loading
                        ? "opacity-50 cursor-not-allowed"
                        : "cursor-pointer"
                    }`}
                    title={
                      parent.isVisible
                        ? "Active - Click to deactivate"
                        : "Inactive - Click to activate"
                    }
                  >
                    <span
                      className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                        parent.isVisible ? "translate-x-6" : "translate-x-1"
                      }`}
                    />
                  </button>
                </div>

                <div className="flex items-center justify-between">
                  <div className="flex space-x-2">
                    <button
                      onClick={() => navigate(`/forms/${formId}/preview`)}
                      className="px-3 py-2 text-sm font-medium text-white bg-primary-600 rounded-lg transition-colors hover:bg-primary-700"
                    >
                      View
                    </button>
                    <button
                      onClick={() => navigate(`/forms/${formId}/edit`)}
                      className="p-2 text-white bg-primary-600 rounded-lg transition-colors hover:bg-primary-700"
                      title="Edit form"
                    >
                      <Edit2 className="w-4 h-4" />
                    </button>
                    <button
                      onClick={() => navigate(`/forms/${formId}/analytics`)}
                      className="p-2 text-white bg-primary-600 rounded-lg transition-colors hover:bg-primary-700"
                      title="View analytics"
                    >
                      <BarChart3 className="w-4 h-4" />
                    </button>
                    <button
                      onClick={() => navigate(`/forms/${formId}/responses`)}
                      className="p-2 text-white bg-primary-600 rounded-lg transition-colors hover:bg-primary-700"
                      title="View responses"
                    >
                      <List className="w-4 h-4" />
                    </button>
                  </div>
                  <div className="flex space-x-2">
                    <button
                      onClick={() => handleDuplicate(formId)}
                      className="p-2 text-white bg-primary-600 rounded-lg transition-colors hover:bg-primary-700"
                      title="Duplicate form"
                      disabled={duplicateMutation.loading}
                    >
                      <Copy className="w-4 h-4" />
                    </button>
                    <button
                      onClick={() => handleDelete(formId, parent.title)}
                      className="p-2 text-white bg-red-600 rounded-lg transition-colors hover:bg-red-700"
                      title="Delete form"
                      disabled={deleteMutation.loading}
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>

                {children.length > 0 && (
                  <div className="border-t border-neutral-200 pt-6 mt-6 bg-gradient-to-r from-primary-50/30 to-purple-50/30 -mx-6 px-6 pb-6 rounded-b-lg">
                    <div className="flex items-center justify-between mb-5">
