import React, { useState } from 'react';
import { Plus, Save } from 'lucide-react';
import type { FollowUpQuestion, Response } from '../../types';
import QuestionEditor from './QuestionEditor';
import AnswerEditor from './AnswerEditor';

interface FollowUpFormProps {
  response: Response;
  onSave: (updatedResponse: Response) => void;
}

export default function FollowUpForm({ response, onSave }: FollowUpFormProps) {
  const [questions, setQuestions] = useState<FollowUpQuestion[]>([]);
  const [answers, setAnswers] = useState<Record<string, any>>(response.answers);

  const handleAddQuestion = () => {
    const newQuestion: FollowUpQuestion = {
      id: crypto.randomUUID(),
      text: '',
      type: 'text',
      required: false,
    };
    setQuestions([...questions, newQuestion]);
  };

  const handleUpdateQuestion = (questionId: string, updates: Partial<FollowUpQuestion>) => {
    setQuestions(questions.map(q => 
      q.id === questionId ? { ...q, ...updates } : q
    ));
  };

  const handleRemoveQuestion = (questionId: string) => {
    setQuestions(questions.filter(q => q.id !== questionId));
    const { [questionId]: _, ...remainingAnswers } = answers;
    setAnswers(remainingAnswers);
  };

  const handleAnswerChange = (questionId: string, value: any) => {
    setAnswers(prev => ({
      ...prev,
      [questionId]: value
    }));
  };

  const handleSubmit = () => {
    const updatedResponse: Response = {
      ...response,
      answers: {
        ...response.answers,
        ...answers
      }
    };
    onSave(updatedResponse);
  };

  return (
    <div className="space-y-6 bg-white dark:bg-gray-800 rounded-lg shadow-sm p-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-semibold text-gray-900 dark:text-white">
          Follow-up Questions
        </h2>
        <button
          onClick={handleAddQuestion}
          className="flex items-center px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
        >
          <Plus className="w-4 h-4 mr-2" />
          Add Question
        </button>
      </div>

      <div className="space-y-6">
        {questions.map((question) => (
          <div key={question.id} className="border dark:border-gray-700 rounded-lg p-4 space-y-4">
            <QuestionEditor
              question={question}
              onUpdate={(updates) => handleUpdateQuestion(question.id, updates)}
              onRemove={() => handleRemoveQuestion(question.id)}
            />
            <AnswerEditor
              question={question}
              value={answers[question.id]}
              onChange={(value) => handleAnswerChange(question.id, value)}
            />
          </div>
        ))}
      </div>

      {questions.length > 0 && (
        <div className="flex justify-end">
          <button
            onClick={handleSubmit}
            className="flex items-center px-6 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700"
          >
            <Save className="w-4 h-4 mr-2" />
            Save Follow-ups
          </button>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from "react";
import {
  Plus,
  X,
  GripVertical,
  Link,
  Unlink,
  ChevronDown,
  ChevronUp,
} from "lucide-react";
import { apiClient } from "../../api/client";

interface ChildForm {
  id: string;
  _id: string;
  title: string;
  description: string;
  isVisible: boolean;
  isActive: boolean;
  order: number;
}

interface ChildFormsManagerProps {
  parentFormId: string;
  onUpdate?: () => void;
}

export default function ChildFormsManager({
  parentFormId,
  onUpdate,
}: ChildFormsManagerProps) {
  const [childForms, setChildForms] = useState<ChildForm[]>([]);
  const [availableForms, setAvailableForms] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [selectedFormId, setSelectedFormId] = useState("");
  const [isExpanded, setIsExpanded] = useState(true);

  useEffect(() => {
    fetchData();
  }, [parentFormId]);

  const fetchData = async () => {
    try {
      setLoading(true);
      // Fetch child forms
      const childData = await apiClient.getChildForms(parentFormId);
      setChildForms(childData.childForms || []);

      // Fetch all available forms
      const allForms = await apiClient.getForms();
      // Filter out the parent form and already linked forms
      const linkedIds = (childData.childForms || []).map(
        (cf: ChildForm) => cf.id
      );
      const available = allForms.forms.filter(
        (f: any) => f.id !== parentFormId && !linkedIds.includes(f.id)
      );
      setAvailableForms(available);
    } catch (error) {
      console.error("Error fetching forms:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleLinkForm = async () => {
    if (!selectedFormId) return;

    try {
      await apiClient.linkChildForm(parentFormId, selectedFormId);
      setShowAddModal(false);
      setSelectedFormId("");
      await fetchData();
      onUpdate?.();
    } catch (error: any) {
      alert(error.message || "Failed to link child form");
    }
  };

  const handleUnlinkForm = async (childFormId: string) => {
    if (!confirm("Are you sure you want to unlink this child form?")) return;

    try {
      await apiClient.unlinkChildForm(parentFormId, childFormId);
      await fetchData();
      onUpdate?.();
    } catch (error: any) {
      alert(error.message || "Failed to unlink child form");
    }
  };

  const handleReorder = async (index: number, direction: "up" | "down") => {
    const newForms = [...childForms];
    const targetIndex = direction === "up" ? index - 1 : index + 1;

    if (targetIndex < 0 || targetIndex >= newForms.length) return;

    // Swap
    [newForms[index], newForms[targetIndex]] = [
      newForms[targetIndex],
      newForms[index],
    ];

    // Update order property
    newForms.forEach((form, i) => {
      form.order = i;
    });

    setChildForms(newForms);

    try {
      const formOrder = newForms.map((f) => f.id);
      await apiClient.reorderChildForms(parentFormId, formOrder);
      onUpdate?.();
    } catch (error: any) {
      alert(error.message || "Failed to reorder child forms");
      fetchData(); // Revert on error
    }
  };

  if (loading) {
    return (
      <div className="bg-white rounded-lg shadow p-6">
        <div className="animate-pulse">
