import React, { useState, useEffect } from "react";
import {
  AlertCircle,
  CheckCircle,
  Loader,
  Eye,
  ChevronRight,
} from "lucide-react";
import { apiClient } from "../../api/client";
import { FormWithSectionLinksResponder } from "./FormWithSectionLinksResponder";
import type { SectionFlowConfig } from "../../types/forms";

interface CustomerFormViewProps {
  formId: string;
  tenantSlug?: string;
  onSubmitted?: (response: any) => void;
  onError?: (error: string) => void;
}

export const CustomerFormView: React.FC<CustomerFormViewProps> = ({
  formId,
  tenantSlug,
  onSubmitted,
  onError,
}) => {
  const [form, setForm] = useState<any>(null);
  const [flowConfig, setFlowConfig] = useState<SectionFlowConfig | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [showFlowInfo, setShowFlowInfo] = useState(true);

  useEffect(() => {
    loadForm();
  }, [formId, tenantSlug]);

  const loadForm = async () => {
    try {
      setLoading(true);
      setError(null);

      const formData = tenantSlug
        ? await apiClient.getPublicForm(formId, tenantSlug)
        : await apiClient.getFormById(formId);

      if (formData.form) {
        setForm(formData.form);

        if (formData.form.sectionFlowConfig) {
          setFlowConfig(formData.form.sectionFlowConfig);
        }
      }
    } catch (err) {
      const errorMessage = "Failed to load form";
      setError(errorMessage);
      if (onError) onError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const hasFlowConfig = flowConfig && flowConfig.sectionLinks && flowConfig.sectionLinks.length > 0;

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-center">
          <Loader className="animate-spin h-12 w-12 text-blue-600 mx-auto mb-4" />
          <p className="text-gray-600 text-lg">Loading form...</p>
        </div>
      </div>
    );
  }

  if (error || !form) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
        <div className="max-w-md w-full bg-white rounded-lg shadow-lg p-8 text-center">
          <AlertCircle className="h-12 w-12 text-red-500 mx-auto mb-4" />
          <h2 className="text-xl font-bold text-gray-900 mb-2">
            Form Not Found
          </h2>
          <p className="text-gray-600 mb-6">
            {error || "The form you're looking for doesn't exist."}
          </p>
          <a
            href="/"
            className="inline-flex items-center justify-center px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 font-medium"
          >
            Return Home
          </a>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {hasFlowConfig && showFlowInfo && (
        <div className="bg-blue-50 border-b border-blue-200">
          <div className="max-w-4xl mx-auto px-6 py-4">
            <div className="flex items-start justify-between gap-4">
              <div className="flex items-start gap-3">
                <Eye className="h-5 w-5 text-blue-600 mt-0.5 flex-shrink-0" />
                <div>
                  <p className="text-sm font-medium text-blue-900">
                    {flowConfig.linkedOnlyMode
                      ? "Adaptive Form"
                      : "Multi-Path Form"}
                  </p>
                  <p className="text-sm text-blue-700 mt-1">
                    {flowConfig.linkedOnlyMode
                      ? "This form shows different sections based on your answers."
                      : "This form has conditional sections that may appear based on your selections."}
                  </p>
                </div>
              </div>
              <button
                onClick={() => setShowFlowInfo(false)}
                className="text-blue-600 hover:text-blue-800 font-medium text-sm"
              >
                Dismiss
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="max-w-4xl mx-auto p-6">
        <FormWithSectionLinksResponder
          formId={formId}
          onSubmitted={(response) => {
            if (onSubmitted) onSubmitted(response);
          }}
          onError={(error) => {
            setError(error);
            if (onError) onError(error);
          }}
        />
      </div>
    </div>
  );
};

import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import {
  AlertCircle,
  Loader,
  CheckCircle,
} from "lucide-react";
import { apiClient } from "../../api/client";
import { FormWithSectionLinksResponder } from "./FormWithSectionLinksResponder";

export const CustomerFormViewerWithSectionLinks: React.FC = () => {
  const { tenantSlug, formId } = useParams<{
    tenantSlug: string;
    formId: string;
  }>();
  const navigate = useNavigate();

  const [form, setForm] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [submitted, setSubmitted] = useState(false);
  const [submittedMessage, setSubmittedMessage] = useState<string | null>(null);

  useEffect(() => {
    loadForm();
  }, [formId, tenantSlug]);

  const loadForm = async () => {
    try {
      setLoading(true);
      if (!formId || !tenantSlug) throw new Error("Form ID and tenant slug are required");

      const data = await apiClient.getPublicForm(formId, tenantSlug);
      setForm(data.form);
      setError(null);
    } catch (err) {
      console.error("Error loading form:", err);
      setError(
        err instanceof Error
          ? err.message
          : "Failed to load form. Please try again later."
      );
    } finally {
      setLoading(false);
    }
  };

  const handleFormSubmitted = (response: any) => {
    setSubmitted(true);
    setSubmittedMessage(`Thank you for your response!`);
    
    setTimeout(() => {
      window.location.reload();
    }, 3000);
  };

  const handleFormError = (errorMessage: string) => {
    setError(errorMessage);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 via-white to-blue-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-xl border border-gray-200 p-12 max-w-md w-full text-center">
          <Loader className="h-12 w-12 animate-spin text-blue-600 mx-auto mb-4" />
          <p className="text-gray-600 font-medium">Loading form...</p>
        </div>
      </div>
    );
  }

  if (error || !form) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-red-50 via-white to-red-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-xl border border-red-200 p-12 max-w-md w-full">
          <div className="flex items-center justify-center h-16 w-16 mx-auto bg-red-100 rounded-full mb-6">
            <AlertCircle className="h-8 w-8 text-red-600" />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 text-center mb-2">
            Form Not Found
          </h2>
          <p className="text-gray-600 text-center mb-6">
            {error ||
              "The form you're looking for doesn't exist or is no longer available."}
          </p>
          <button
            onClick={() => window.history.back()}
            className="w-full px-4 py-2 bg-gray-200 text-gray-800 rounded-lg hover:bg-gray-300 font-medium transition-colors"
          >
            ← Go Back
          </button>
        </div>
      </div>
    );
  }

  if (submitted) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-green-50 via-white to-green-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-xl border border-green-200 p-12 max-w-md w-full text-center">
          <div className="flex items-center justify-center h-16 w-16 mx-auto bg-green-100 rounded-full mb-6">
            <CheckCircle className="h-8 w-8 text-green-600" />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">
            Thank You!
          </h2>
          <p className="text-gray-600 mb-6">
            {submittedMessage || "Your response has been submitted successfully."}
          </p>
          <p className="text-sm text-gray-500">
            Redirecting in a moment...
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Form with Section Linking Responder */}
      <FormWithSectionLinksResponder
        formId={formId!}
        onSubmitted={handleFormSubmitted}
        onError={handleFormError}
      />
    </div>
  );
};

