export default FollowUpFormDemo;

import React, { useState, useEffect } from "react";
import {
  Plus,
  Eye,
  Edit,
  Trash2,
  Settings,
  BarChart3,
  Copy,
  ToggleLeft,
  ToggleRight,
  Search,
  Filter,
  FileText,
  AlertCircle,
  CheckCircle,
  Users,
} from "lucide-react";
import { FormWithFollowUpCreator } from "./FormWithFollowUpCreator";
import { FormWithFollowUpResponder } from "./FormWithFollowUpResponder";
import { SectionFollowUpCreator } from "./SectionFollowUpCreator";
import formWithFollowUpService, {
  FollowUpConfig,
} from "../../api/formWithFollowUpService";
import { useNotification } from "../../context/NotificationContext";

interface Form {
  id: string;
  title: string;
  description: string;
  logoUrl?: string;
  imageUrl?: string;
  isVisible: boolean;
  createdAt: string;
  updatedAt: string;
  createdBy: {
    username: string;
    firstName?: string;
    lastName?: string;
    email: string;
  };
  permissions: {
    canRespond: string[];
    canViewResponses: string[];
    canEdit: string[];
    canAddFollowUp: string[];
    canDelete: string[];
  };
}

interface FormListItem extends Form {
  responseCount?: number;
  followUpConfig?: Record<string, FollowUpConfig>;
}

type ViewMode =
  | "list"
  | "create"
  | "edit"
  | "respond"
  | "analytics"
  | "config"
  | "create-sections";

interface FollowUpFormManagerProps {
  initialView?: ViewMode;
  onFormCreated?: (form: Form) => void;
  onFormUpdated?: (form: Form) => void;
  onFormDeleted?: (formId: string) => void;
}

export const FollowUpFormManager: React.FC<FollowUpFormManagerProps> = ({
  initialView = "list",
  onFormCreated,
  onFormUpdated,
  onFormDeleted,
}) => {
  const { showSuccess, showError, showConfirm } = useNotification();
  const [currentView, setCurrentView] = useState<ViewMode>(initialView);
  const [forms, setForms] = useState<FormListItem[]>([]);
  const [selectedForm, setSelectedForm] = useState<FormListItem | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  // Filters and search
  const [searchTerm, setSearchTerm] = useState("");
  const [visibilityFilter, setVisibilityFilter] = useState<
    "all" | "visible" | "hidden"
  >("all");
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);

  useEffect(() => {
    loadForms();
  }, [currentPage, searchTerm, visibilityFilter]);

  const loadForms = async () => {
    setLoading(true);
    try {
      const result = await formWithFollowUpService.getAllForms({
        page: currentPage,
        limit: 10,
        search: searchTerm || undefined,
        isVisible:
          visibilityFilter === "all"
            ? undefined
            : visibilityFilter === "visible",
      });

      setForms(result.data.forms);
      setTotalPages(result.data.pagination.totalPages);

      // Load follow-up configs for each form
      await loadFollowUpConfigs(result.data.forms);
    } catch (error) {
      console.error("Error loading forms:", error);
      setError(error instanceof Error ? error.message : "Failed to load forms");
    } finally {
      setLoading(false);
    }
  };

  const loadFollowUpConfigs = async (formList: Form[]) => {
    try {
      const configPromises = formList.map(async (form) => {
        try {
          const result = await formWithFollowUpService.getFollowUpConfig(
            form.id
          );
          return { formId: form.id, config: result.data.followUpConfig };
        } catch (error) {
          return { formId: form.id, config: {} };
        }
      });

      const configs = await Promise.all(configPromises);

      setForms((prevForms) =>
        prevForms.map((form) => {
          const config = configs.find((c) => c.formId === form.id);
          return {
            ...form,
            followUpConfig: config?.config || {},
          };
        })
      );
    } catch (error) {
      console.error("Error loading follow-up configs:", error);
    }
  };

  const handleCreateForm = (form: Form) => {
    setForms((prev) => [form, ...prev]);
    setCurrentView("list");
    setSuccess("Form created successfully!");
    setTimeout(() => setSuccess(null), 3000);

    if (onFormCreated) {
      onFormCreated(form);
    }
  };

  const handleEditForm = (form: FormListItem) => {
    setSelectedForm(form);
    setCurrentView("edit");
  };

  const handleViewForm = (form: FormListItem) => {
    setSelectedForm(form);
    setCurrentView("respond");
  };

  const handleConfigureFollowUp = (form: FormListItem) => {
    setSelectedForm(form);
    setCurrentView("config");
  };

  const handleToggleVisibility = async (form: FormListItem) => {
    try {
      await formWithFollowUpService.updateFormVisibility(
        form.id,
        !form.isVisible
      );

      setForms((prev) =>
        prev.map((f) =>
          f.id === form.id ? { ...f, isVisible: !f.isVisible } : f
        )
      );

      setSuccess(
        `Form ${!form.isVisible ? "published" : "unpublished"} successfully!`
      );
      setTimeout(() => setSuccess(null), 3000);
    } catch (error) {
      setError(
        error instanceof Error
          ? error.message
          : "Failed to update form visibility"
      );
      setTimeout(() => setError(null), 3000);
    }
  };

  const handleDuplicateForm = async (form: FormListItem) => {
    try {
      const result = await formWithFollowUpService.duplicateForm(form.id);
      await loadForms(); // Reload to show the new form

      setSuccess("Form duplicated successfully!");
      setTimeout(() => setSuccess(null), 3000);
    } catch (error) {
      setError(
        error instanceof Error ? error.message : "Failed to duplicate form"
      );
      setTimeout(() => setError(null), 3000);
    }
  };

  const handleDeleteForm = async (form: FormListItem) => {
    showConfirm(
      `Are you sure you want to delete "${form.title}"? This action cannot be undone.`,
      async () => {
        try {
          await formWithFollowUpService.deleteForm(form.id);

          setForms((prev) => prev.filter((f) => f.id !== form.id));
          showSuccess("Form deleted successfully!", "Success");

          if (onFormDeleted) {
            onFormDeleted(form.id);
          }
        } catch (error) {
          const errorMsg =
            error instanceof Error ? error.message : "Failed to delete form";
          showError(errorMsg, "Error");
        }
      },
      "Delete Form",
      "Delete",
      "Cancel"
    );
  };

  const getFollowUpSummary = (
    followUpConfig?: Record<string, FollowUpConfig>
  ) => {
    if (!followUpConfig) return "No follow-up configuration";

    return formWithFollowUpService.getFollowUpSummary(followUpConfig).summary;
  };

  const renderFormsList = () => (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-800">
            Forms with Follow-up Questions
          </h1>
          <p className="text-gray-600">
            Create and manage forms with configurable follow-up questions
          </p>
        </div>

        <div className="flex gap-2">
          <button
            onClick={() => setCurrentView("create")}
            className="flex items-center px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            <Plus className="h-4 w-4 mr-2" />
            Create New Form
          </button>
          <button
            onClick={() => setCurrentView("create-sections")}
            className="flex items-center px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors"
          >
            <Plus className="h-4 w-4 mr-2" />
            Create Sections Form
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center">
        <div className="flex-1 relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
          <input
            type="text"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            placeholder="Search forms..."
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>

        <select
          value={visibilityFilter}
          onChange={(e) => setVisibilityFilter(e.target.value as any)}
          className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
        >
          <option value="all">All Forms</option>
          <option value="visible">Published</option>
          <option value="hidden">Unpublished</option>
        </select>
      </div>

      {/* Messages */}
      {error && (
        <div className="p-4 bg-red-50 border border-red-200 rounded-lg flex items-center">
          <AlertCircle className="h-5 w-5 text-red-500 mr-2" />
          <span className="text-red-700">{error}</span>
        </div>
      )}

      {success && (
        <div className="p-4 bg-green-50 border border-green-200 rounded-lg flex items-center">
          <CheckCircle className="h-5 w-5 text-green-500 mr-2" />
          <span className="text-green-700">{success}</span>
        </div>
      )}

      {/* Forms List */}
      {loading ? (
        <div className="flex items-center justify-center p-8">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
          <span className="ml-2 text-gray-600">Loading forms...</span>
        </div>
      ) : forms.length === 0 ? (
        <div className="text-center p-8 bg-gray-50 rounded-lg">
          <FileText className="h-12 w-12 text-gray-400 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-800 mb-2">
            No forms found
          </h3>
          <p className="text-gray-600 mb-4">
            {searchTerm
              ? "Try adjusting your search criteria"
              : "Get started by creating your first form with follow-up questions"}
          </p>
          <button
            onClick={() => setCurrentView("create")}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            Create New Form
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-6">
          {forms.map((form) => (
            <div
              key={form.id}
              className="bg-white border border-gray-200 rounded-lg p-6 hover:shadow-lg transition-shadow"
            >
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-2">
                    <h3 className="text-lg font-semibold text-gray-800">
                      {form.title}
                    </h3>
                    {form.isVisible ? (
                      <span className="px-2 py-1 bg-green-100 text-green-800 text-xs font-medium rounded-full">
                        Published
                      </span>
                    ) : (
                      <span className="px-2 py-1 bg-gray-100 text-gray-800 text-xs font-medium rounded-full">
                        Draft
                      </span>
                    )}
                  </div>

                  <p className="text-gray-600 mb-3">{form.description}</p>

                  <div className="text-sm text-gray-500 mb-3">
                    <div>
                      Created by{" "}
                      {form.createdBy.firstName || form.createdBy.username} on{" "}
                      {new Date(form.createdAt).toLocaleDateString()}
                    </div>
                    <div className="mt-1">
                      {getFollowUpSummary(form.followUpConfig)}
                    </div>
                  </div>
                </div>

                <div className="flex items-center space-x-2 ml-4">
                  <button
                    onClick={() => handleViewForm(form)}
                    className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                    title="View/Respond"
                  >
                    <Eye className="h-4 w-4" />
                  </button>

                  <button
                    onClick={() => handleEditForm(form)}
                    className="p-2 text-gray-600 hover:bg-gray-50 rounded-lg transition-colors"
                    title="Edit"
                  >
                    <Edit className="h-4 w-4" />
                  </button>

                  <button
                    onClick={() => handleConfigureFollowUp(form)}
                    className="p-2 text-purple-600 hover:bg-purple-50 rounded-lg transition-colors"
                    title="Configure Follow-up Questions"
                  >
                    <Settings className="h-4 w-4" />
                  </button>

                  <button
                    onClick={() => handleToggleVisibility(form)}
                    className={`p-2 rounded-lg transition-colors ${
                      form.isVisible
                        ? "text-green-600 hover:bg-green-50"
                        : "text-gray-600 hover:bg-gray-50"
                    }`}
                    title={form.isVisible ? "Unpublish" : "Publish"}
                  >
                    {form.isVisible ? (
                      <ToggleRight className="h-4 w-4" />
                    ) : (
                      <ToggleLeft className="h-4 w-4" />
                    )}
                  </button>

                  <button
                    onClick={() => handleDuplicateForm(form)}
                    className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                    title="Duplicate"
                  >
                    <Copy className="h-4 w-4" />
                  </button>

                  <button
                    onClick={() => handleDeleteForm(form)}
                    className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                    title="Delete"
                  >
                    <Trash2 className="h-4 w-4" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex justify-center space-x-2">
          <button
            onClick={() => setCurrentPage(Math.max(1, currentPage - 1))}
            disabled={currentPage === 1}
            className="px-3 py-2 border border-gray-300 rounded-lg hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            Previous
          </button>

          <span className="px-3 py-2 text-gray-600">
            Page {currentPage} of {totalPages}
          </span>

          <button
            onClick={() =>
              setCurrentPage(Math.min(totalPages, currentPage + 1))
            }
            disabled={currentPage === totalPages}
            className="px-3 py-2 border border-gray-300 rounded-lg hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            Next
          </button>
        </div>
      )}
    </div>
  );

  const renderView = () => {
    switch (currentView) {
      case "create":
        return (
          <div>
            <div className="mb-6">
              <button
                onClick={() => setCurrentView("list")}
                className="flex items-center text-blue-600 hover:text-blue-800"
              >
                ← Back to Forms
              </button>
            </div>
            <FormWithFollowUpCreator onFormCreated={handleCreateForm} />
          </div>
        );

      case "edit":
        return selectedForm ? (
          <div>
            <div className="mb-6">
              <button
                onClick={() => setCurrentView("list")}
                className="flex items-center text-blue-600 hover:text-blue-800"
              >
                ← Back to Forms
              </button>
            </div>
            <FormWithFollowUpCreator
              initialData={{
                title: selectedForm.title,
                description: selectedForm.description,
                logoUrl: selectedForm.logoUrl,
                imageUrl: selectedForm.imageUrl,
                // Note: Would need to extract options from form data
                options: ["Option A", "Option B", "Option C", "Option D"],
                followUpConfig: selectedForm.followUpConfig || {},
              }}
              onFormCreated={(form) => {
                setCurrentView("list");
                loadForms(); // Reload forms
              }}
            />
          </div>
        ) : null;

      case "respond":
        return selectedForm ? (
          <div>
            <div className="mb-6">
              <button
                onClick={() => setCurrentView("list")}
                className="flex items-center text-blue-600 hover:text-blue-800"
              >
                ← Back to Forms
              </button>
            </div>
            <FormWithFollowUpResponder
              formId={selectedForm.id}
              onSubmitted={() => {
                setCurrentView("list");
                setSuccess("Form response submitted successfully!");
                setTimeout(() => setSuccess(null), 3000);
              }}
              onError={(error) => {
                setError(error);
                setTimeout(() => setError(null), 5000);
              }}
            />
          </div>
        ) : null;

      case "create-sections":
        return (
          <div>
            <div className="mb-6">
              <button
                onClick={() => setCurrentView("list")}
                className="flex items-center text-blue-600 hover:text-blue-800"
              >
                ← Back to Forms
              </button>
            </div>
            <SectionFollowUpCreator />
          </div>
        );

      case "config":
        return selectedForm ? (
          <div>
            <div className="mb-6">
              <button
                onClick={() => setCurrentView("list")}
                className="flex items-center text-blue-600 hover:text-blue-800"
              >
                ← Back to Forms
              </button>
            </div>
            <FollowUpConfigEditor
              form={selectedForm}
              onConfigUpdated={() => {
                setCurrentView("list");
                loadForms();
                setSuccess("Follow-up configuration updated successfully!");
                setTimeout(() => setSuccess(null), 3000);
              }}
            />
          </div>
        ) : null;

      default:
        return renderFormsList();
    }
  };

  return <div className="max-w-7xl mx-auto p-6">{renderView()}</div>;
};

// Follow-up Configuration Editor Component
interface FollowUpConfigEditorProps {
  form: FormListItem;
  onConfigUpdated: () => void;
}

const FollowUpConfigEditor: React.FC<FollowUpConfigEditorProps> = ({
  form,
  onConfigUpdated,
}) => {
  const [config, setConfig] = useState<Record<string, FollowUpConfig>>(
    form.followUpConfig || {}
  );
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Default options (would be extracted from actual form data in real implementation)
  const options = ["Option A", "Option B", "Option C", "Option D"];

  const handleConfigChange = (option: string, newConfig: FollowUpConfig) => {
    setConfig((prev) => ({
      ...prev,
      [option]: newConfig,
    }));
  };

  const handleSave = async () => {
    setLoading(true);
    setError(null);

    try {
      await formWithFollowUpService.updateFollowUpConfig(form.id, config);
      onConfigUpdated();
    } catch (error) {
      setError(
        error instanceof Error
          ? error.message
          : "Failed to update configuration"
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto bg-white rounded-lg shadow-lg p-6">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-gray-800 mb-2">
          Configure Follow-up Questions
        </h2>
        <p className="text-gray-600">
          Configure which options trigger follow-up questions for:{" "}
          <strong>{form.title}</strong>
        </p>
      </div>

      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg flex items-center">
          <AlertCircle className="h-5 w-5 text-red-500 mr-2" />
          <span className="text-red-700">{error}</span>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
        {options.map((option, index) => (
          <div key={option} className="border border-gray-200 rounded-lg p-4">
            <div className="flex items-center justify-between mb-4">
              <h3 className="font-semibold text-gray-800">{option}</h3>
              <span className="text-xs px-2 py-1 bg-gray-100 text-gray-600 rounded-full">
                {String.fromCharCode(65 + index)}
              </span>
            </div>

            <div className="space-y-3">
              <label className="flex items-center">
                <input
                  type="checkbox"
                  checked={config[option]?.hasFollowUp || false}
                  onChange={(e) =>
                    handleConfigChange(option, {
                      hasFollowUp: e.target.checked,
                      required: config[option]?.required || false,
                    })
                  }
                  className="mr-3 h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 rounded"
                />
                <span className="text-sm text-gray-700">
                  Enable follow-up question
                </span>
              </label>

              {config[option]?.hasFollowUp && (
                <label className="flex items-center ml-7">
                  <input
                    type="checkbox"
                    checked={config[option]?.required || false}
                    onChange={(e) =>
                      handleConfigChange(option, {
                        hasFollowUp: true,
                        required: e.target.checked,
                      })
                    }
                    className="mr-3 h-4 w-4 text-red-600 focus:ring-red-500 border-gray-300 rounded"
                  />
                  <span className="text-sm text-red-700">
                    Make follow-up required
                  </span>
                </label>
              )}
            </div>
          </div>
        ))}
      </div>

      <div className="flex justify-end space-x-4">
        <button
          onClick={onConfigUpdated}
          className="px-6 py-2 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
        >
          Cancel
        </button>

        <button
          onClick={handleSave}
          disabled={loading}
          className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {loading ? "Saving..." : "Save Configuration"}
        </button>
      </div>
    </div>
  );
};

export default FollowUpFormManager;

import React, { useState, useEffect } from 'react';
import { Link2, X, AlertCircle, CheckCircle, Loader, Trash2 } from 'lucide-react';

interface Form {
  id: string;
  title: string;
  description: string;
}

interface FormChainingLinkerProps {
  currentFormId: string;
  onFormLinked?: (nextFormId: string) => void;
}

export const FormChainingLinker: React.FC<FormChainingLinkerProps> = ({
  currentFormId,
  onFormLinked
}) => {
  const [availableForms, setAvailableForms] = useState<Form[]>([]);
  const [linkedForm, setLinkedForm] = useState<Form | null>(null);
  const [selectedFormId, setSelectedFormId] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [linking, setLinking] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [showSelector, setShowSelector] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    loadAvailableForms();
    loadCurrentLink();
  }, [currentFormId]);

  const loadAvailableForms = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem('token');
      const response = await fetch('/api/forms', {
        headers: {
          Authorization: `Bearer ${token}`
        }
      });

      if (!response.ok) {
        throw new Error('Failed to load forms');
      }

      const result = await response.json();
      const forms = result.data.forms || [];
      const filtered = forms.filter((f: Form) => f.id !== currentFormId);
      setAvailableForms(filtered);
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to load forms';
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const loadCurrentLink = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`/api/forms/${currentFormId}/next-form`, {
        headers: {
          Authorization: `Bearer ${token}`
        }
      });

      if (!response.ok) {
        return;
      }

      const result = await response.json();
      if (result.data.nextForm) {
        setLinkedForm(result.data.nextForm);
      }
    } catch (err) {
      console.error('Error loading current link:', err);
    }
  };

  const handleLinkForm = async () => {
    if (!selectedFormId) {
      setError('Please select a form');
      return;
    }

    setLinking(true);
    setError(null);

    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`/api/forms/${currentFormId}/link-next-form`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({ nextFormId: selectedFormId })
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || 'Failed to link form');
      }

      const selectedForm = availableForms.find(f => f.id === selectedFormId);
      setLinkedForm(selectedForm || null);
      setSuccess('Form linked successfully!');
      setShowSelector(false);
      setSelectedFormId('');

      if (onFormLinked && selectedFormId) {
        onFormLinked(selectedFormId);
      }

      setTimeout(() => setSuccess(null), 3000);
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to link form';
      setError(errorMessage);
    } finally {
      setLinking(false);
    }
  };

  const handleUnlinkForm = async () => {
    setLinking(true);
    setError(null);

    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`/api/forms/${currentFormId}/link-next-form`, {
        method: 'DELETE',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        }
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || 'Failed to unlink form');
      }

      setLinkedForm(null);
      setSuccess('Form unlinked successfully!');

      setTimeout(() => setSuccess(null), 3000);
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to unlink form';
      setError(errorMessage);
    } finally {
      setLinking(false);
    }
  };

  const filteredForms = availableForms.filter(
    form =>
      form.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      form.description.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="w-full max-w-2xl mx-auto p-6 bg-white rounded-lg border border-gray-200">
      <div className="mb-6">
        <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2">
          <Link2 className="h-5 w-5 text-blue-600" />
          Form Chaining
        </h3>
        <p className="text-gray-600 text-sm mt-2">
          Link this form to another form. After submission, customers will automatically see the linked form.
        </p>
      </div>

      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg flex items-center">
          <AlertCircle className="h-5 w-5 text-red-500 mr-2" />
          <span className="text-red-700">{error}</span>
        </div>
      )}

      {success && (
        <div className="mb-6 p-4 bg-green-50 border border-green-200 rounded-lg flex items-center">
          <CheckCircle className="h-5 w-5 text-green-500 mr-2" />
          <span className="text-green-700">{success}</span>
        </div>
      )}

      {loading ? (
        <div className="flex items-center justify-center py-8">
          <Loader className="animate-spin h-6 w-6 text-blue-500" />
        </div>
      ) : linkedForm ? (
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-6">
          <div className="flex items-start justify-between">
            <div className="flex-1">
              <p className="text-sm text-blue-600 font-medium mb-2">Linked to:</p>
              <h4 className="text-xl font-semibold text-gray-800">{linkedForm.title}</h4>
              <p className="text-gray-600 text-sm mt-2">{linkedForm.description}</p>
            </div>
            <button
              onClick={handleUnlinkForm}
              disabled={linking}
              className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-50"
              title="Unlink form"
            >
              <Trash2 className="h-5 w-5" />
            </button>
          </div>

          <div className="mt-4 pt-4 border-t border-blue-200">
            <button
              onClick={() => setShowSelector(true)}
              className="text-blue-600 hover:text-blue-700 font-medium text-sm"
            >
              Change linked form
            </button>
          </div>
        </div>
      ) : (
        <div className="bg-gray-50 border border-gray-200 rounded-lg p-6 text-center">
          <p className="text-gray-600 mb-4">No form linked yet</p>
          <button
            onClick={() => setShowSelector(true)}
            className="inline-flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            <Link2 className="h-4 w-4" />
            Link a Form
          </button>
        </div>
      )}

      {showSelector && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-xl max-w-2xl w-full max-h-96 flex flex-col">
            <div className="flex items-center justify-between p-6 border-b border-gray-200">
              <h4 className="text-lg font-semibold text-gray-800">Select Form to Link</h4>
              <button
                onClick={() => {
                  setShowSelector(false);
                  setSearchQuery('');
                  setSelectedFormId('');
                }}
                className="p-1 hover:bg-gray-100 rounded-lg transition-colors"
              >
                <X className="h-5 w-5 text-gray-600" />
              </button>
            </div>

            <div className="p-4 border-b border-gray-200">
              <input
                type="text"
                placeholder="Search forms..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>

            <div className="flex-1 overflow-y-auto">
              {filteredForms.length === 0 ? (
                <div className="p-6 text-center text-gray-600">
                  No forms available
                </div>
              ) : (
                <div className="divide-y divide-gray-200">
                  {filteredForms.map(form => (
                    <button
                      key={form.id}
                      onClick={() => setSelectedFormId(form.id)}
                      className={`w-full text-left p-4 hover:bg-blue-50 transition-colors ${
                        selectedFormId === form.id ? 'bg-blue-50 border-l-4 border-blue-600' : ''
                      }`}
                    >
                      <h5 className="font-semibold text-gray-800">{form.title}</h5>
                      <p className="text-sm text-gray-600 mt-1">{form.description}</p>
                    </button>
                  ))}
                </div>
              )}
            </div>

            <div className="flex gap-3 p-6 border-t border-gray-200">
              <button
                onClick={() => {
                  setShowSelector(false);
                  setSearchQuery('');
                  setSelectedFormId('');
                }}
                className="flex-1 px-4 py-2 border border-gray-300 text-gray-800 rounded-lg hover:bg-gray-50 transition-colors font-medium"
              >
                Cancel
              </button>
              <button
                onClick={handleLinkForm}
                disabled={!selectedFormId || linking}
                className="flex-1 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium disabled:bg-blue-400"
              >
                {linking ? 'Linking...' : 'Link Form'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { PlusCircle, Eye, Edit2, FileText, MessageSquarePlus, Trash2 } from 'lucide-react';
import { Link } from 'react-router-dom';
import type { Question, Response } from '../../types';

interface FormHierarchyProps {
  form: Question;
  allForms: Question[];
  responses: Response[];
  onCreateChild: (parentId: string) => void;
  onEdit: (id: string) => void;
  onViewResponses: (id: string) => void;
  onRespond: (id: string) => void;
  onDelete: (id: string) => void;
  level?: number;
}

export default function FormHierarchy({
  form,
  allForms,
  responses,
  onCreateChild,
  onEdit,
  onViewResponses,
  onRespond,
  onDelete,
  level = 0,
}: FormHierarchyProps) {
  const getResponseCount = (formId: string) => {
    return responses.filter(r => r.questionId === formId).length;
  };

  // Get all child forms for this form
  const childForms = allForms.filter(f => f.parentFormId === form.id);

  return (
    <div className="relative">
      <div className={`bg-white dark:bg-gray-800 rounded-lg shadow p-4 ${level > 0 ? 'ml-8 border-l-2 border-blue-200 dark:border-blue-800' : ''}`}>
        <div className="flex items-center justify-between">
          <div>
            <div className="flex items-center space-x-2">
              {level > 0 && (
                <div className="text-sm text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/20 px-2 py-1 rounded-md">
                  Follow-up Form
                </div>
              )}
              <h3 className="text-lg font-medium text-gray-900 dark:text-white">
                {form.title}
              </h3>
            </div>
            <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
              {form.description}
            </p>
            <p className="text-sm text-blue-600 dark:text-blue-400 mt-1">
              {getResponseCount(form.id)} responses
            </p>
          </div>
          <div className="flex items-center space-x-3">
            <button
              onClick={() => onRespond(form.id)}
              className="flex items-center px-3 py-1.5 text-green-600 hover:text-green-800 dark:text-green-400 dark:hover:text-green-300"
            >
              <Eye className="w-4 h-4 mr-1" />
              Respond
            </button>
            <button
              onClick={() => onViewResponses(form.id)}
              className="flex items-center px-3 py-1.5 text-blue-600 hover:text-blue-800 dark:text-blue-400 dark:hover:text-blue-300"
            >
              <FileText className="w-4 h-4 mr-1" />
              View Responses
            </button>
            <button
              onClick={() => onEdit(form.id)}
              className="flex items-center px-3 py-1.5 text-purple-600 hover:text-purple-800 dark:text-purple-400 dark:hover:text-purple-300"
            >
              <Edit2 className="w-4 h-4 mr-1" />
              Edit
            </button>
            <button
              onClick={() => onCreateChild(form.id)}
              className="flex items-center px-3 py-1.5 text-indigo-600 hover:text-indigo-800 dark:text-indigo-400 dark:hover:text-indigo-300"
            >
              <MessageSquarePlus className="w-4 h-4 mr-1" />
              Add Follow-up
            </button>
            <button
              onClick={() => onDelete(form.id)}
              className="flex items-center px-3 py-1.5 text-red-600 hover:text-red-800 dark:text-red-400 dark:hover:text-red-300"
            >
              <Trash2 className="w-4 h-4 mr-1" />
              Delete
            </button>
          </div>
        </div>
      </div>

      {/* Recursively render child forms */}
      {childForms.length > 0 && (
        <div className="mt-4 space-y-4">
          {childForms.map(childForm => (
            <FormHierarchy
              key={childForm.id}
              form={childForm}
              allForms={allForms}
              responses={responses}
              onCreateChild={onCreateChild}
              onEdit={onEdit}
              onViewResponses={onViewResponses}
              onRespond={onRespond}
              onDelete={onDelete}
              level={level + 1}
            />
          ))}
        </div>
      )}
    </div>
  );
}

import React, { useState } from "react";
import { ExternalLink, X } from "lucide-react";

interface FormRoutingRule {
  optionLabel: string;
  linkedFormId: string;
}

interface FormRoutingConfigProps {
  questionId: string;
  sectionId: string;
  options: string[];
  availableForms: { id: string; title: string }[];
  existingConfig?: Record<string, { linkedFormId?: string }>;
  onSave: (config: Record<string, { linkedFormId: string }>) => void;
  onClose: () => void;
}

export const FormRoutingConfig: React.FC<FormRoutingConfigProps> = ({
  questionId,
  sectionId,
  options,
  availableForms,
  existingConfig = {},
  onSave,
  onClose,
}) => {
  const [formLinks, setFormLinks] = useState<Record<string, string>>(() => {
    const initial: Record<string, string> = {};
    Object.entries(existingConfig).forEach(([option, config]) => {
      if (config.linkedFormId) {
        initial[option] = config.linkedFormId;
      }
    });
    return initial;
  });

  const handleOptionChange = (optionLabel: string, linkedFormId: string) => {
    setFormLinks((prev) => {
      if (!linkedFormId) {
        const updated = { ...prev };
        delete updated[optionLabel];
        return updated;
      }
      return { ...prev, [optionLabel]: linkedFormId };
    });
  };

  const handleRemoveLink = (optionLabel: string) => {
    setFormLinks((prev) => {
      const updated = { ...prev };
      delete updated[optionLabel];
      return updated;
    });
  };

  const handleSave = () => {
    const config: Record<string, { linkedFormId: string }> = {};
    Object.entries(formLinks).forEach(([option, formId]) => {
      if (formId) {
        config[option] = { linkedFormId: formId };
      }
    });
    onSave(config);
  };

  const getFormTitle = (formId: string) => {
    const form = availableForms.find((f) => f.id === formId);
    return form ? form.title : "Select Form";
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg shadow-xl max-w-2xl w-full mx-4 max-h-96 overflow-y-auto">
        <div className="sticky top-0 bg-gradient-to-r from-green-50 to-blue-50 border-b border-green-200 px-6 py-4 flex justify-between items-center">
          <div>
            <h3 className="text-lg font-semibold text-gray-900">
              🔗 Configure Follow-up Form Routing
            </h3>
            <p className="text-xs text-gray-600 mt-1">
              Link answers to different forms
            </p>
          </div>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-gray-600"
          >
            <X className="h-5 w-5" />
          </button>
        </div>

        <div className="p-6 space-y-6">
          <div className="bg-green-50 border border-green-200 rounded-lg p-4">
            <p className="text-sm text-green-900">
              <strong>How it works:</strong> When a user selects an option and
              submits the form, they will be automatically redirected to the
              linked follow-up form.
            </p>
            <p className="text-xs text-green-700 mt-2">
              ⚠️ Note: Only ONE form can be linked per submission (first match
              found will be used)
            </p>
          </div>

          <div className="space-y-4">
            <h4 className="text-md font-medium text-gray-900">
              Option → Form Linking
            </h4>
            {options.map((option) => {
              const linkedFormId = formLinks[option] || "";
              return (
                <div
                  key={option}
                  className="flex items-center gap-4 p-4 bg-gradient-to-r from-gray-50 to-green-50 rounded-lg border border-gray-200"
                >
                  <div className="flex-1">
                    <p className="text-sm font-medium text-gray-700">
                      {option}
                    </p>
                  </div>
                  <select
                    value={linkedFormId}
                    onChange={(e) => handleOptionChange(option, e.target.value)}
                    className="px-3 py-2 border border-gray-300 rounded-md text-sm focus:ring-green-500 focus:border-green-500 min-w-[250px]"
                  >
                    <option value="">No follow-up form</option>
                    {availableForms.map((form) => (
                      <option key={form.id} value={form.id}>
                        📋 {form.title}
                      </option>
                    ))}
                  </select>
                  {linkedFormId && (
                    <button
                      onClick={() => handleRemoveLink(option)}
                      className="text-gray-400 hover:text-red-600"
                      title="Remove link"
                    >
                      <X className="h-4 w-4" />
                    </button>
                  )}
                </div>
              );
            })}
          </div>

          {Object.keys(formLinks).length > 0 && (
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
              <h4 className="text-sm font-semibold text-blue-900 mb-2">
                ✅ Active Form Links: {Object.keys(formLinks).length}
              </h4>
              <ul className="text-xs text-blue-800 space-y-1">
                {Object.entries(formLinks).map(([option, formId]) => (
                  <li key={option}>
                    <strong>{option}</strong> → {getFormTitle(formId)}
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>

        <div className="sticky bottom-0 bg-gray-50 border-t border-gray-200 px-6 py-4 flex justify-end gap-3">
          <button
            onClick={onClose}
            className="px-4 py-2 text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50"
          >
            Cancel
          </button>
          <button
            onClick={handleSave}
            className="px-4 py-2 text-white bg-green-600 rounded-lg hover:bg-green-700 flex items-center gap-2"
          >
            <ExternalLink className="h-4 w-4" />
            Save Form Routing
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import {
  ArrowLeft,
  AlertCircle,
  Loader,
  Link2,
  Eye,
  Settings,
} from "lucide-react";
import { apiClient } from "../../api/client";
import { SectionLinkManager } from "../management/sections/SectionLinkManager";
import { FormFlowVisualizer } from "../management/sections/FormFlowVisualizer";
import type { SectionFlowConfig } from "../../types/forms";

interface Section {
  id: string;
  title: string;
  description?: string;
  questions?: any[];
}

interface FormData {
  id: string;
  title: string;
  description: string;
  sections: Section[];
  sectionFlowConfig?: SectionFlowConfig;
}

export const FormSectionLinkingPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();

  const [form, setForm] = useState<FormData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<"manage" | "visualize">("manage");
  const [config, setConfig] = useState<SectionFlowConfig | null>(null);

  useEffect(() => {
    loadForm();
  }, [id]);

  const loadForm = async () => {
    try {
      setLoading(true);
      if (!id) throw new Error("Form ID is required");

      const data = await apiClient.getFormById(id);
      setForm(data.form);
      setConfig(data.form.sectionFlowConfig);
      setError(null);
    } catch (err) {
      console.error("Error loading form:", err);
      setError(
        err instanceof Error ? err.message : "Failed to load form"
      );
    } finally {
      setLoading(false);
    }
  };

  const handleConfigSaved = (newConfig: SectionFlowConfig) => {
    setConfig(newConfig);
