            <ArrowLeft className="h-5 w-5" />
          </button>
          <h1 className="text-2xl font-bold text-gray-900">
            Section Linking
          </h1>
        </div>

        <div className="bg-red-50 border border-red-200 rounded-lg p-6 flex gap-3">
          <AlertCircle className="h-6 w-6 text-red-600 flex-shrink-0" />
          <div>
            <h2 className="font-semibold text-red-800 mb-1">Error</h2>
            <p className="text-red-700">
              {error || "Failed to load form"}
            </p>
            <button
              onClick={() => navigate("/forms/management")}
              className="mt-3 text-sm text-red-600 hover:text-red-800 font-medium"
            >
              ← Back to Forms
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-6 py-6">
          <div className="flex items-center gap-3 mb-4">
            <button
              onClick={() => navigate("/forms/management")}
              className="p-2 hover:bg-gray-100 rounded-lg transition"
              title="Back to forms"
            >
              <ArrowLeft className="h-5 w-5 text-gray-600" />
            </button>
            <div>
              <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
                <Link2 className="h-7 w-7 text-blue-600" />
                Section Linking
              </h1>
              <p className="text-gray-600 mt-1">{form.title}</p>
            </div>
          </div>

          {/* Tabs */}
          <div className="flex gap-2 border-t border-gray-200 pt-4">
            <button
              onClick={() => setActiveTab("manage")}
              className={`flex items-center gap-2 px-4 py-2 font-medium rounded-t-lg transition-colors ${
                activeTab === "manage"
                  ? "bg-blue-600 text-white"
                  : "text-gray-600 hover:text-gray-900"
              }`}
            >
              <Settings className="h-4 w-4" />
              Manage Links
            </button>
            <button
              onClick={() => setActiveTab("visualize")}
              className={`flex items-center gap-2 px-4 py-2 font-medium rounded-t-lg transition-colors ${
                activeTab === "visualize"
                  ? "bg-blue-600 text-white"
