              </div>
            )}

            <div className="space-y-3">
              <p className="font-medium text-gray-800">
                Please select one option:
              </p>
              {formData.options.map((option, index) => (
                <label
                  key={option}
                  className="flex items-center p-3 border border-gray-200 rounded-lg hover:bg-gray-50 cursor-pointer"
                >
                  <input
                    type="radio"
                    name="preview-option"
                    value={option}
                    checked={selectedOption === option}
                    onChange={(e) => setSelectedOption(e.target.value)}
                    className="mr-3 h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300"
                  />
                  <span className="flex-1">{option}</span>
                  {formData.followUpConfig[option]?.hasFollowUp && (
                    <span
                      className={`text-xs px-2 py-1 rounded-full ${
                        formData.followUpConfig[option]?.required
                          ? "bg-red-100 text-red-700"
                          : "bg-blue-100 text-blue-700"
                      }`}
                    >
                      {formData.followUpConfig[option]?.required
                        ? "Required Follow-up"
                        : "Optional Follow-up"}
                    </span>
                  )}
                </label>
              ))}
            </div>

            {showFollowUp && (
              <div className="mt-6 p-4 bg-blue-50 border border-blue-200 rounded-lg">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Please provide additional details for {selectedOption}:
                  {selectedConfig?.required && (
                    <span className="text-red-500 ml-1">*</span>
                  )}
                </label>
                <textarea
                  value={followUpAnswer}
                  onChange={(e) => setFollowUpAnswer(e.target.value)}
                  rows={3}
                  className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  placeholder="Enter your response here..."
                  required={selectedConfig?.required}
                />
                <p className="text-xs text-gray-500 mt-1">
                  This follow-up question is{" "}
                  {selectedConfig?.required ? "mandatory" : "optional"} for{" "}
                  {selectedOption}
                </p>
              </div>
            )}

            <div className="mt-6">
              <button className="w-full px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors">
                Submit Response
              </button>
            </div>
          </div>

          <div className="mt-4 text-center">
            <button
              onClick={onClose}
              className="px-6 py-2 bg-gray-600 text-white rounded-lg hover:bg-gray-700 transition-colors"
            >
              Close Preview
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

