    it("should add multiple choice options dynamically", async () => {
      const user = userEvent.setup();
      renderComponent();

      // Find the multiple choice question in section 2 (it's already configured)
      const questionInputs = screen.getAllByLabelText("Question Text");
      const section2Question = questionInputs[questionInputs.length - 1]; // Last question (in section 2)

      await user.type(section2Question, "Car model?");

      // The question is already set to multiple choice, so check options are displayed
      expect(
        screen.getByDisplayValue("RECENTLY PURCHASED")
      ).toBeInTheDocument();

      // Find and click the add option button (plus button)
      const addOptionButton = screen.getByRole("button", {
        name: /add option/i,
      });
      await user.click(addOptionButton);

      // Verify new option field appears
      const optionInputs = screen.getAllByLabelText(/option \d+/i);
      expect(optionInputs).toHaveLength(5); // 4 default + 1 new

      // Add another option
      await user.click(addOptionButton);

      const updatedOptionInputs = screen.getAllByLabelText(/option \d+/i);
      expect(updatedOptionInputs).toHaveLength(6); // 4 default + 2 new
    });

    it("should remove options with minus button", async () => {
      const user = userEvent.setup();
      renderComponent();

      // Add extra option first so we have more than minimum (section 2 already has multiple choice)
      const addOptionButton = screen.getByRole("button", {
        name: /add option/i,
      });
      await user.click(addOptionButton);

      // Find remove buttons (minus buttons)
      const removeButtons = screen.getAllByRole("button", {
        name: /remove option/i,
      });
      expect(removeButtons).toHaveLength(3); // Can remove when more than 2 options

      // Remove an option
      await user.click(removeButtons[0]);

      // Verify option was removed
      const remainingOptionInputs = screen.getAllByLabelText(/option \d+/i);
      expect(remainingOptionInputs).toHaveLength(4); // Back to 4 options
    });

    it("should display default four option fields", async () => {
      const user = userEvent.setup();
      renderComponent();

      // Section 2 already has multiple choice configured, verify default 4 option fields are displayed
      const optionInputs = screen.getAllByLabelText(/option \d+/i);
      expect(optionInputs).toHaveLength(4);

      // Verify default values
      expect(
        screen.getByDisplayValue("RECENTLY PURCHASED")
      ).toBeInTheDocument();
      expect(optionInputs[1]).toHaveValue("Option 2");
      expect(optionInputs[2]).toHaveValue("Option 3");
      expect(optionInputs[3]).toHaveValue("Option 4");
    });
  });

  describe("Input Verification Tests", () => {
    it("should validate minimum two mandatory options", async () => {
      const user = userEvent.setup();
      renderComponent();

      // Try to remove options to get below minimum (section 2 already has multiple choice)
      const removeButtons = screen.getAllByRole("button", {
        name: /remove option/i,
      });

      // Remove options until only 2 remain
      await user.click(removeButtons[0]); // Remove option 1
      await user.click(removeButtons[0]); // Remove option 2 (index shifts)

      // Verify minimum 2 options remain
      const remainingOptions = screen.getAllByLabelText(/option \d+/i);
      expect(remainingOptions).toHaveLength(2);

      // Remove buttons should be disabled or not present when at minimum
      const currentRemoveButtons = screen.queryAllByRole("button", {
        name: /remove option/i,
      });
      expect(currentRemoveButtons).toHaveLength(0);
    });

    it("should prevent duplicate option values", async () => {
      const user = userEvent.setup();
      renderComponent();

      // Set duplicate values in existing options (section 2 already has multiple choice)
      const optionInputs = screen.getAllByLabelText(/option \d+/i);
      await user.clear(optionInputs[0]);
      await user.type(optionInputs[0], "Duplicate Option");

      await user.clear(optionInputs[1]);
      await user.type(optionInputs[1], "Duplicate Option");

      // Try to save/validate
      const saveButton = screen.getByRole("button", { name: /save/i });
      await user.click(saveButton);

      await waitFor(() => {
        expect(screen.getByText(/options must be unique/i)).toBeInTheDocument();
      });
    });

    it("should handle empty option text fields", async () => {
      const user = userEvent.setup();
      renderComponent();

      // Clear an option field (section 2 already has multiple choice)
      const optionInputs = screen.getAllByLabelText(/option \d+/i);
      await user.clear(optionInputs[0]);

      // Try to save
      const saveButton = screen.getByRole("button", { name: /save/i });
      await user.click(saveButton);

      await waitFor(() => {
        expect(
          screen.getByText(/all options must have text/i)
        ).toBeInTheDocument();
      });
    });
  });

  describe("Exception Handling Tests", () => {
    it("should show error when removing below minimum", async () => {
      const user = userEvent.setup();
      renderComponent();

      // Set up multiple choice question
      const carModelQuestion = screen.getByLabelText(/car model/i);
      await user.type(carModelQuestion, "Car model?");

      const questionTypeSelect = screen.getByLabelText(/question type/i);
      await user.selectOptions(questionTypeSelect, "multipleChoice");

      // Remove options until we reach minimum
      const removeButtons = screen.getAllByRole("button", {
        name: /remove option/i,
      });

      // Remove two options (leaving 2, which is minimum)
      await user.click(removeButtons[0]);
      await user.click(removeButtons[0]);

      // Try to remove another - should show error
      const remainingRemoveButtons = screen.queryAllByRole("button", {
        name: /remove option/i,
      });

      if (remainingRemoveButtons.length > 0) {
        await user.click(remainingRemoveButtons[0]);

        await waitFor(() => {
          expect(screen.getByText(/minimum.*2.*options/i)).toBeInTheDocument();
        });
      } else {
        // If no remove buttons are visible, that's also correct behavior
        expect(remainingRemoveButtons).toHaveLength(0);
      }
    });
  });

  describe("Form Structure Tests", () => {
    it("should handle multiple sections correctly", async () => {
      const user = userEvent.setup();
      renderComponent();

      // Fill Section 1
      const section1Title = screen.getByLabelText(/section 1.*title/i);
      await user.type(section1Title, "Personal Information");

      // Fill Section 2
      const section2Title = screen.getByLabelText(/section 2.*title/i);
      await user.type(section2Title, "Service Details");

      expect(
        screen.getByDisplayValue("Personal Information")
      ).toBeInTheDocument();
      expect(screen.getByDisplayValue("Service Details")).toBeInTheDocument();
    });

    it("should validate required form fields", async () => {
      const user = userEvent.setup();
      renderComponent();

      // Try to save without filling required fields
      const saveButton = screen.getByRole("button", { name: /save/i });
      await user.click(saveButton);

      await waitFor(() => {
        expect(screen.getByText(/form title.*required/i)).toBeInTheDocument();
      });
    });

    it("should handle question type changes", async () => {
      const user = userEvent.setup();
      renderComponent();

      const questionTypeSelect = screen.getByLabelText(/question type/i);

      // Change from default to multiple choice
      await user.selectOptions(questionTypeSelect, "multipleChoice");

      // Verify options appear
      const optionInputs = screen.getAllByLabelText(/option \d+/i);
      expect(optionInputs).toHaveLength(4);

      // Change back to short text
      await user.selectOptions(questionTypeSelect, "shortText");

      // Verify options disappear
      const updatedOptionInputs = screen.queryAllByLabelText(/option \d+/i);
      expect(updatedOptionInputs).toHaveLength(0);
    });

    it("should support follow-up questions configuration", async () => {
      const user = userEvent.setup();
      renderComponent();

      // Set up multiple choice question
      const carModelQuestion = screen.getByLabelText(/car model/i);
      await user.type(carModelQuestion, "Car model?");

      const questionTypeSelect = screen.getByLabelText(/question type/i);
      await user.selectOptions(questionTypeSelect, "multipleChoice");

      // Configure follow-up for "RECENTLY PURCHASED" option
      const followUpButton = screen.getByRole("button", {
        name: /add follow.*recently purchased/i,
      });
      await user.click(followUpButton);

      // Verify follow-up configuration appears
      expect(
        screen.getByText(/follow.*up.*recently purchased/i)
      ).toBeInTheDocument();
    });
  });
});

import React, { useState, useEffect } from "react";
import {
  Save,
  Eye,
  Plus,
  Minus,
  Trash2,
  AlertCircle,
  CheckCircle,
  MoreVertical,
} from "lucide-react";

interface FormSection {
  id: string;
  title: string;
  description: string;
  questions: FormQuestion[];
}

interface FollowUpQuestion {
  id: string;
  text: string;
  type: string;
  required: boolean;
  options?: string[];
  parentId: string;
  showWhen?: {
    questionId: string;
    value: string;
  };
}

interface FormQuestion {
  id: string;
  text: string;
  type: "shortText" | "multipleChoice" | "longText" | "checkboxes" | "dropdown";
  required: boolean;
  options?: string[];
  followUpQuestions?: FollowUpQuestion[];
  followUpConfig?: Record<
    string,
    {
      hasFollowUp: boolean;
      required: boolean;
      linkedFormId?: string;
      goToSection?: string;
    }
  >;
}

interface FormData {
  title: string;
  description: string;
  isPublic: boolean;
  sections: FormSection[];
}

interface MultipleChoiceFormBuilderProps {
  onFormCreated?: (form: FormData) => void;
  onPreview?: (form: FormData) => void;
  initialData?: Partial<FormData>;
}

const DEFAULT_FORM_DATA: FormData = {
  title: "",
  description: "",
  isPublic: false,
  sections: [
    {
      id: "section1",
      title: "",
      description: "",
      questions: [
        {
          id: "q1",
          text: "",
          type: "shortText",
          required: false,
        },
        {
          id: "q2",
          text: "",
          type: "shortText",
          required: false,
        },
        {
          id: "q3",
          text: "",
          type: "shortText",
          required: false,
        },
      ],
    },
    {
      id: "section2",
      title: "",
      description: "",
      questions: [
        {
          id: "q4",
          text: "",
          type: "multipleChoice",
          required: false,
          options: ["RECENTLY PURCHASED", "Option 2", "Option 3", "Option 4"],
          followUpConfig: {},
        },
      ],
    },
  ],
};

export const MultipleChoiceFormBuilder: React.FC<
  MultipleChoiceFormBuilderProps
> = ({ onFormCreated, onPreview, initialData }) => {
  const [formData, setFormData] = useState<FormData>(() => ({
    ...DEFAULT_FORM_DATA,
    ...initialData,
  }));
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [sectionModal, setSectionModal] = useState<{
    isOpen: boolean;
    sectionIndex: number;
    questionIndex: number;
    option: string;
  } | null>(null);
  const [openOptionMenu, setOpenOptionMenu] = useState<string | null>(null);

  const handleFormFieldChange = (field: keyof FormData, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    setError(null);
  };

  const handleSectionChange = (
    sectionIndex: number,
    field: keyof FormSection,
    value: any
  ) => {
    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((section, index) =>
        index === sectionIndex ? { ...section, [field]: value } : section
      ),
    }));
  };

  const handleQuestionChange = (
    sectionIndex: number,
    questionIndex: number,
    field: keyof FormQuestion,
    value: any
  ) => {
    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((section, sIndex) =>
        sIndex === sectionIndex
          ? {
              ...section,
              questions: section.questions.map((question, qIndex) =>
                qIndex === questionIndex
                  ? { ...question, [field]: value }
                  : question
              ),
            }
          : section
      ),
    }));
  };

  const addSection = () => {
    const newSectionId = `section${formData.sections.length + 1}`;
    const newSection: FormSection = {
      id: newSectionId,
      title: "",
      description: "",
      questions: [
        {
          id: `q${Date.now()}`,
          text: "",
          type: "shortText",
          required: false,
        },
      ],
    };

    setFormData((prev) => ({
      ...prev,
      sections: [...prev.sections, newSection],
    }));
  };

  const removeSection = (sectionIndex: number) => {
    if (formData.sections.length <= 1) {
      setError("At least one section is required");
      return;
    }

    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.filter((_, index) => index !== sectionIndex),
    }));
  };

  const addQuestion = (sectionIndex: number) => {
    const newQuestion: FormQuestion = {
      id: `q${Date.now()}`,
      text: "",
      type: "shortText",
      required: false,
    };

    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((section, index) =>
        index === sectionIndex
          ? {
              ...section,
              questions: [...section.questions, newQuestion],
            }
          : section
      ),
    }));
  };

  const removeQuestion = (sectionIndex: number, questionIndex: number) => {
    const section = formData.sections[sectionIndex];
    if (section.questions.length <= 1) {
      setError("At least one question is required per section");
      return;
    }

    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((sec, sIndex) =>
        sIndex === sectionIndex
          ? {
              ...sec,
              questions: sec.questions.filter(
                (_, qIndex) => qIndex !== questionIndex
              ),
            }
          : sec
      ),
    }));
  };

  const addOption = (sectionIndex: number, questionIndex: number) => {
    const question = formData.sections[sectionIndex].questions[questionIndex];
    if (!question.options) return;

    const newOption = `Option ${question.options.length + 1}`;

    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((section, sIndex) =>
        sIndex === sectionIndex
          ? {
              ...section,
              questions: section.questions.map((q, qIndex) =>
                qIndex === questionIndex
                  ? {
                      ...q,
                      options: [...(q.options || []), newOption],
                      followUpConfig: {
                        ...(q.followUpConfig || {}),
                        [newOption]: { hasFollowUp: false, required: false },
                      },
                    }
                  : q
              ),
            }
          : section
      ),
    }));
  };

  const removeOption = (
    sectionIndex: number,
    questionIndex: number,
    optionIndex: number
  ) => {
    const question = formData.sections[sectionIndex].questions[questionIndex];
    if (!question.options || question.options.length <= 2) {
      setError("Minimum 2 options required");
      return;
    }

    const optionToRemove = question.options[optionIndex];
    const newOptions = question.options.filter(
      (_, index) => index !== optionIndex
    );
    const newFollowUpConfig = { ...question.followUpConfig };
    delete newFollowUpConfig[optionToRemove];

    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((section, sIndex) =>
        sIndex === sectionIndex
          ? {
              ...section,
              questions: section.questions.map((q, qIndex) =>
                qIndex === questionIndex
                  ? {
                      ...q,
                      options: newOptions,
                      followUpConfig: newFollowUpConfig,
                    }
                  : q
              ),
            }
          : section
      ),
    }));
  };

  const updateOption = (
    sectionIndex: number,
    questionIndex: number,
    optionIndex: number,
    newValue: string
  ) => {
    const question = formData.sections[sectionIndex].questions[questionIndex];
    if (!question.options) return;

    const oldValue = question.options[optionIndex];
    const newOptions = question.options.map((option, index) =>
      index === optionIndex ? newValue : option
    );

    // Update follow-up config keys
    const newFollowUpConfig = { ...question.followUpConfig };
    if (oldValue in newFollowUpConfig && oldValue !== newValue) {
      newFollowUpConfig[newValue] = newFollowUpConfig[oldValue];
      delete newFollowUpConfig[oldValue];
    }

    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((section, sIndex) =>
        sIndex === sectionIndex
          ? {
              ...section,
              questions: section.questions.map((q, qIndex) =>
                qIndex === questionIndex
                  ? {
                      ...q,
                      options: newOptions,
                      followUpConfig: newFollowUpConfig,
                    }
                  : q
              ),
            }
          : section
      ),
    }));
  };

  const addFollowUp = (
    sectionIndex: number,
    questionIndex: number,
    option: string
  ) => {
    const question = formData.sections[sectionIndex].questions[questionIndex];

    // Create a new follow-up question
    const newFollowUp: FollowUpQuestion = {
      id: `followup-${Date.now()}`,
      text: `Follow-up for "${option}"`,
      type: "shortText",
      required: false,
      parentId: question.id,
      showWhen: {
        questionId: question.id,
        value: option,
      },
    };

    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((section, sIndex) =>
        sIndex === sectionIndex
          ? {
              ...section,
              questions: section.questions.map((q, qIndex) =>
                qIndex === questionIndex
                  ? {
                      ...q,
                      followUpQuestions: [
                        ...(q.followUpQuestions || []),
                        newFollowUp,
                      ],
                      followUpConfig: {
                        ...(q.followUpConfig || {}),
                        [option]: { hasFollowUp: true, required: false },
                      },
                    }
                  : q
              ),
            }
          : section
      ),
    }));
  };

  const linkFollowUpSection = (
    sectionIndex: number,
    questionIndex: number,
    option: string
  ) => {
    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((section, sIndex) =>
        sIndex === sectionIndex
          ? {
              ...section,
              questions: section.questions.map((q, qIndex) =>
                qIndex === questionIndex
                  ? {
                      ...q,
                      followUpConfig: {
                        ...Object.keys(q.followUpConfig || {}).reduce(
                          (acc, key) => ({
                            ...acc,
                            [key]: {
                              hasFollowUp: false,
                              required: false,
                              linkedFormId: undefined,
                            },
                          }),
                          {}
                        ),
                        [option]: {
                          hasFollowUp: true,
                          required: false,
                          linkedFormId: undefined,
                        },
                      },
                    }
                  : q
              ),
            }
          : section
      ),
    }));
  };

  const linkFollowUpForm = (
    sectionIndex: number,
    questionIndex: number,
    option: string,
    linkedFormId: string
  ) => {
    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((section, sIndex) =>
        sIndex === sectionIndex
          ? {
              ...section,
              questions: section.questions.map((q, qIndex) =>
                qIndex === questionIndex
                  ? {
                      ...q,
                      followUpConfig: {
                        ...q.followUpConfig,
                        [option]: {
                          ...(q.followUpConfig?.[option] || {
                            hasFollowUp: false,
                            required: false,
                          }),
                          linkedFormId: linkedFormId || undefined,
                        },
                      },
                    }
                  : q
              ),
            }
          : section
      ),
    }));
  };

  const updateGoToSection = (
    sectionIndex: number,
    questionIndex: number,
    option: string,
    targetSectionId: string
  ) => {
    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((section, sIndex) =>
        sIndex === sectionIndex
          ? {
              ...section,
              questions: section.questions.map((q, qIndex) =>
                qIndex === questionIndex
                  ? {
                      ...q,
                      followUpConfig: {
                        ...q.followUpConfig,
                        [option]: {
                          ...(q.followUpConfig?.[option] || {
                            hasFollowUp: false,
                            required: false,
                          }),
                          goToSection: targetSectionId || undefined,
                        },
                      },
                    }
                  : q
              ),
            }
          : section
      ),
    }));
  };

  const updateFollowUp = (
    sectionIndex: number,
    questionIndex: number,
    followUpIndex: number,
    field: keyof FollowUpQuestion,
    value: any
  ) => {
    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((section, sIndex) =>
        sIndex === sectionIndex
          ? {
              ...section,
              questions: section.questions.map((q, qIndex) =>
                qIndex === questionIndex
                  ? {
                      ...q,
                      followUpQuestions: q.followUpQuestions?.map(
                        (fq, fqIndex) =>
                          fqIndex === followUpIndex
                            ? { ...fq, [field]: value }
                            : fq
                      ),
                    }
                  : q
              ),
            }
          : section
      ),
    }));
  };

  const removeFollowUp = (
    sectionIndex: number,
    questionIndex: number,
    followUpIndex: number
  ) => {
    const question = formData.sections[sectionIndex].questions[questionIndex];
    const followUpToRemove = question.followUpQuestions?.[followUpIndex];

    if (!followUpToRemove) return;

    const option = followUpToRemove.showWhen?.value as string;
    const newFollowUpConfig = { ...question.followUpConfig };
    if (option) {
      delete newFollowUpConfig[option];
    }

    setFormData((prev) => ({
      ...prev,
      sections: prev.sections.map((section, sIndex) =>
        sIndex === sectionIndex
          ? {
              ...section,
              questions: section.questions.map((q, qIndex) =>
                qIndex === questionIndex
                  ? {
                      ...q,
                      followUpQuestions: q.followUpQuestions?.filter(
                        (_, fqIndex) => fqIndex !== followUpIndex
                      ),
                      followUpConfig: newFollowUpConfig,
                    }
                  : q
              ),
            }
          : section
      ),
    }));
  };

  const validateForm = (): boolean => {
    if (!formData.title.trim()) {
      setError("Form title is required");
      return false;
    }

    if (!formData.description.trim()) {
      setError("Form description is required");
      return false;
    }

    // Validate each section and question
    for (const section of formData.sections) {
      for (const question of section.questions) {
        if (
          question.type === "multipleChoice" ||
          question.type === "checkboxes" ||
          question.type === "dropdown"
        ) {
          if (!question.options || question.options.length < 2) {
            setError(
              `${
                question.type === "checkboxes"
                  ? "Checkbox"
                  : question.type === "dropdown"
                  ? "Dropdown"
                  : "Multiple choice"
              } questions must have at least 2 options`
            );
            return false;
          }

          if (question.options.some((option) => !option.trim())) {
            setError("All options must have text");
            return false;
          }

          // Check for duplicates
          const optionSet = new Set(
            question.options.map((opt) => opt.trim().toLowerCase())
          );
          if (optionSet.size !== question.options.length) {
            setError("All options must be unique");
            return false;
          }
        }
      }
    }

    return true;
  };

  const handleSave = async () => {
    if (!validateForm()) return;

    setLoading(true);
    setError(null);

    try {
      // Simulate API call
      await new Promise((resolve) => setTimeout(resolve, 1000));

      setSuccess("Form saved successfully!");
      if (onFormCreated) {
        onFormCreated(formData);
      }

      setTimeout(() => setSuccess(null), 3000);
    } catch (error) {
      setError("Failed to save form");
    } finally {
      setLoading(false);
    }
  };

  const handlePreview = () => {
    if (!validateForm()) return;
    if (onPreview) {
      onPreview(formData);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6 bg-white rounded-lg shadow-lg">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-gray-800 mb-2">
          Customer Service Request Form Builder
        </h2>
        <p className="text-gray-600">
          Create a comprehensive form with sections and multiple choice
          questions
        </p>
      </div>

      {error && (
        <div className="mb-4 p-4 bg-red-50 border border-red-200 rounded-lg flex items-center">
          <AlertCircle className="h-5 w-5 text-red-500 mr-2" />
          <span className="text-red-700">{error}</span>
        </div>
      )}

      {success && (
        <div className="mb-4 p-4 bg-green-50 border border-green-200 rounded-lg flex items-center">
          <CheckCircle className="h-5 w-5 text-green-500 mr-2" />
          <span className="text-green-700">{success}</span>
        </div>
      )}

      <div className="space-y-8">
        {/* Form Details */}
        <div className="bg-gray-50 p-6 rounded-lg">
          <h3 className="text-lg font-semibold text-gray-800 mb-4">
            Form Details
          </h3>

          <div className="space-y-4">
            <div>
              <label
                htmlFor="form-title"
                className="block text-sm font-medium text-gray-700 mb-2"
              >
                Form Title *
              </label>
              <input
                id="form-title"
                type="text"
                value={formData.title}
                onChange={(e) => handleFormFieldChange("title", e.target.value)}
                placeholder="Enter form title (e.g., 'Customer Service Request')"
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>

            <div>
              <label
                htmlFor="form-description"
                className="block text-sm font-medium text-gray-700 mb-2"
              >
                Description
              </label>
              <textarea
                id="form-description"
                value={formData.description}
                onChange={(e) =>
                  handleFormFieldChange("description", e.target.value)
                }
                placeholder="Describe your form purpose (e.g., 'Collect customer feedback and service requests')"
                rows={3}
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
            </div>

            <div className="flex items-center">
              <input
                id="public-visibility"
                type="checkbox"
                checked={formData.isPublic}
                onChange={(e) =>
                  handleFormFieldChange("isPublic", e.target.checked)
                }
                className="h-4 w-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500"
              />
              <label
                htmlFor="public-visibility"
                className="ml-2 block text-sm text-gray-700"
              >
                Make form publicly visible
              </label>
            </div>
          </div>
        </div>

        {/* Sections */}
        {formData.sections.map((section, sectionIndex) => (
          <div key={section.id} className="bg-gray-50 p-6 rounded-lg">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold text-gray-800">
                Section {sectionIndex + 1}
              </h3>
              {formData.sections.length > 1 && (
                <button
                  type="button"
                  onClick={() => removeSection(sectionIndex)}
                  className="flex items-center px-3 py-1.5 text-sm text-red-600 hover:text-red-800 hover:bg-red-50 rounded-lg transition-colors"
                >
                  <Trash2 className="h-4 w-4 mr-1" />
                  Delete Section
                </button>
              )}
            </div>

            <div className="space-y-4">
              <div>
                <label
                  htmlFor={`section-${sectionIndex}-title`}
                  className="block text-sm font-medium text-gray-700 mb-2"
                >
                  Section Title
                </label>
                <input
                  id={`section-${sectionIndex}-title`}
                  type="text"
                  value={section.title}
                  onChange={(e) =>
                    handleSectionChange(sectionIndex, "title", e.target.value)
                  }
                  placeholder={`Section title (e.g., "Personal Information", "Service Details")`}
                  className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>

              <div>
                <label
                  htmlFor={`section-${sectionIndex}-description`}
                  className="block text-sm font-medium text-gray-700 mb-2"
                >
                  Section Description
                </label>
                <input
                  id={`section-${sectionIndex}-description`}
                  type="text"
                  value={section.description}
                  onChange={(e) =>
                    handleSectionChange(
                      sectionIndex,
                      "description",
                      e.target.value
                    )
                  }
                  placeholder="Brief description of this section's purpose"
                  className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>

              {/* Questions */}
              <div className="mt-6">
                <h4 className="text-md font-medium text-gray-800 mb-3">
                  Questions
                </h4>

                {section.questions.map((question, questionIndex) => (
                  <div
                    key={question.id}
                    className="border border-gray-200 p-4 rounded-lg mb-4 bg-white"
                  >
                    <div className="flex items-center justify-between mb-4">
                      <span className="text-sm font-medium text-gray-600">
                        Question {questionIndex + 1}
                      </span>
                      {section.questions.length > 1 && (
                        <button
                          type="button"
                          onClick={() =>
                            removeQuestion(sectionIndex, questionIndex)
                          }
                          className="flex items-center px-2 py-1 text-xs text-red-600 hover:text-red-800 hover:bg-red-50 rounded transition-colors"
                        >
                          <Trash2 className="h-3 w-3 mr-1" />
                          Delete
                        </button>
                      )}
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                      <div>
                        <label
                          htmlFor={`question-${sectionIndex}-${questionIndex}-text`}
                          className="block text-sm font-medium text-gray-700 mb-2"
                        >
                          Question Text
                        </label>
                        <input
                          id={`question-${sectionIndex}-${questionIndex}-text`}
                          type="text"
                          value={question.text}
                          onChange={(e) =>
                            handleQuestionChange(
                              sectionIndex,
                              questionIndex,
                              "text",
                              e.target.value
                            )
                          }
                          placeholder="What would you like to ask?"
                          className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        />
                      </div>

                      <div>
                        <label
                          htmlFor={`question-${sectionIndex}-${questionIndex}-type`}
                          className="block text-sm font-medium text-gray-700 mb-2"
                        >
                          Question Type
                        </label>
                        <select
                          id={`question-${sectionIndex}-${questionIndex}-type`}
                          value={question.type}
                          onChange={(e) => {
                            const newType = e.target.value as
                              | "shortText"
                              | "multipleChoice"
                              | "longText"
                              | "checkboxes"
                              | "dropdown";
                            const updatedQuestion = {
                              ...question,
                              type: newType,
                            };

                            const needsOptions = [
                              "multipleChoice",
                              "checkboxes",
                              "dropdown",
                            ].includes(newType);

                            if (needsOptions && !question.options) {
                              updatedQuestion.options = [
                                "Option 1",
                                "Option 2",
                                "Option 3",
                                "Option 4",
                              ];
                              updatedQuestion.followUpConfig = {};
                            } else if (!needsOptions) {
                              delete updatedQuestion.options;
                              delete updatedQuestion.followUpConfig;
                            }

                            handleQuestionChange(
                              sectionIndex,
                              questionIndex,
                              "type",
                              newType
                            );
                            if (needsOptions && !question.options) {
                              handleQuestionChange(
                                sectionIndex,
                                questionIndex,
                                "options",
                                ["Option 1", "Option 2", "Option 3", "Option 4"]
                              );
                              handleQuestionChange(
                                sectionIndex,
                                questionIndex,
                                "followUpConfig",
                                {}
                              );
                            }
                          }}
                          className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        >
                          <option value="shortText">
                            Short Text - Single line text input
                          </option>
                          <option value="multipleChoice">
                            Multiple Choice - Select one option from many
                          </option>
                          <option value="checkboxes">
                            Checkboxes - Select multiple options
                          </option>
                          <option value="dropdown">
                            Dropdown - Select from searchable list
                          </option>
                          <option value="longText">
                            Long Text - Multi-line text input
                          </option>
                        </select>
                      </div>
                    </div>

                    <div className="flex items-center mb-4">
                      <input
                        id={`question-${sectionIndex}-${questionIndex}-required`}
                        type="checkbox"
                        checked={question.required}
                        onChange={(e) =>
                          handleQuestionChange(
                            sectionIndex,
                            questionIndex,
                            "required",
                            e.target.checked
                          )
                        }
                        className="h-4 w-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500"
                      />
                      <label
                        htmlFor={`question-${sectionIndex}-${questionIndex}-required`}
                        className="ml-2 block text-sm text-gray-700"
                      >
                        Required
                      </label>
                    </div>

                    {/* Multiple Choice/Checkboxes/Dropdown Options */}
                    {(question.type === "multipleChoice" ||
                      question.type === "checkboxes" ||
                      question.type === "dropdown") &&
                      question.options && (
                        <div className="mt-4">
                          <label className="block text-sm font-medium text-gray-700 mb-2">
                            Options (one per line)
                          </label>

                          <div className="space-y-3">
                            {question.options.map((option, optionIndex) => {
                              const currentGoToSection =
                                question.followUpConfig?.[option]?.goToSection;

                              return (
                                <div key={optionIndex} className="space-y-2">
                                  <div className="flex items-center space-x-2">
                                    <input
                                      aria-label={`Option ${optionIndex + 1}`}
                                      type="text"
                                      value={option}
                                      onChange={(e) =>
                                        updateOption(
                                          sectionIndex,
                                          questionIndex,
                                          optionIndex,
                                          e.target.value
                                        )
                                      }
                                      placeholder={`Option ${optionIndex + 1}`}
                                      className="flex-1 p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                                    />

                                    {question.options &&
                                      question.options.length > 2 && (
                                        <button
                                          type="button"
                                          onClick={() =>
                                            removeOption(
                                              sectionIndex,
                                              questionIndex,
                                              optionIndex
                                            )
                                          }
                                          className="p-2 text-red-600 hover:text-red-800 hover:bg-red-50 rounded-lg transition-colors"
                                          aria-label="Remove option"
                                        >
                                          <Minus className="h-4 w-4" />
                                        </button>
                                      )}
                                  </div>

                                  {/* Follow-up Action Menu */}
                                  <div className="ml-8 flex items-center gap-2 mt-2 relative">
                                    <button
                                      type="button"
                                      onClick={() => {
                                        const menuId = `${sectionIndex}-${questionIndex}-${optionIndex}`;
                                        setOpenOptionMenu(openOptionMenu === menuId ? null : menuId);
                                      }}
                                      className="p-1 text-gray-600 hover:text-gray-800 hover:bg-gray-100 rounded-lg transition-colors relative"
                                      title="More actions"
                                    >
                                      <MoreVertical className="w-4 h-4" />
                                    </button>

                                    {openOptionMenu === `${sectionIndex}-${questionIndex}-${optionIndex}` && (
                                      <div className="absolute left-0 top-full mt-1 bg-white border border-gray-200 rounded-lg shadow-lg z-10 min-w-max">
                                        <button
                                          type="button"
                                          onClick={() => {
                                            addFollowUp(
                                              sectionIndex,
                                              questionIndex,
                                              option
                                            );
                                            setOpenOptionMenu(null);
                                          }}
                                          className="w-full text-left px-4 py-2 text-sm text-blue-600 hover:bg-blue-50 transition-colors"
                                        >
                                          Add a question for this option
                                        </button>
                                        <button
                                          type="button"
                                          onClick={() => {
                                            console.log(
                                              "Opening section modal for option:",
                                              option
                                            );
                                            console.log(
                                              "Available sections:",
                                              formData.sections.length
                                            );
                                            setSectionModal({
                                              isOpen: true,
                                              sectionIndex,
                                              questionIndex,
                                              option,
                                            });
                                            setOpenOptionMenu(null);
                                          }}
                                          className="w-full text-left px-4 py-2 text-sm text-green-600 hover:bg-green-50 transition-colors"
                                        >
                                          Add a section for this option
                                        </button>
                                        <button
                                          type="button"
                                          onClick={() => {
                                            const isLinked =
                                              section.questions[questionIndex]
                                                .followUpConfig?.[option]
                                                ?.hasFollowUp;
                                            if (!isLinked) {
                                              alert(
                                                "Please link a follow-up section first before linking a form"
                                              );
                                              return;
                                            }
                                            const formId =
                                              (window as any).formId ||
                                              "current-form";
                                            const forms =
                                              (window as any).availableForms || [];
                                            if (forms.length === 0) {
                                              alert(
                                                "No other forms available to link"
                                              );
                                              return;
                                            }
                                            const selectedFormId = prompt(
                                              "Enter the ID of the form to link (or paste form ID)"
                                            );
                                            if (selectedFormId) {
                                              linkFollowUpForm(
                                                sectionIndex,
                                                questionIndex,
                                                option,
                                                selectedFormId
                                              );
                                              alert("Form linked successfully!");
                                            }
                                            setOpenOptionMenu(null);
                                          }}
                                          className="w-full text-left px-4 py-2 text-sm text-blue-600 hover:bg-blue-50 transition-colors"
                                        >
                                          Link a form for this option
                                        </button>
                                      </div>
                                    )}
                                  </div>

                                  {/* Go to Section Display */}
                                  <div className="ml-8 flex items-center space-x-2">
                                    <div className="flex-1 text-xs text-gray-600 bg-gray-50 p-2 rounded-lg border border-gray-200">
                                      {currentGoToSection ? (
                                        currentGoToSection === "submit" ? (
                                          <span className="text-purple-600 font-medium">
                                            ✅ Submit form
                                          </span>
                                        ) : (
                                          <span className="text-green-600 font-medium">
                                            ➡️ Jump to{" "}
                                            {formData.sections.findIndex(
                                              (s) => s.id === currentGoToSection
                                            ) !== -1
                                              ? `Section ${
                                                  formData.sections.findIndex(
                                                    (s) =>
                                                      s.id ===
                                                      currentGoToSection
                                                  ) + 1
                                                }${
                                                  formData.sections.find(
                                                    (s) =>
                                                      s.id ===
                                                      currentGoToSection
                                                  )?.title
                                                    ? `: ${
                                                        formData.sections.find(
                                                          (s) =>
                                                            s.id ===
                                                            currentGoToSection
                                                        )?.title
                                                      }`
                                                    : ""
                                                }`
                                              : "Unknown section"}
                                          </span>
                                        )
                                      ) : (
                                        <span className="text-gray-500">
                                          ➡️ Continue to next section
                                        </span>
                                      )}
                                    </div>
                                    <button
                                      type="button"
                                      onClick={() => {
                                        setSectionModal({
                                          isOpen: true,
                                          sectionIndex,
                                          questionIndex,
                                          option,
                                        });
                                      }}
                                      className="px-3 py-1.5 text-xs bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors whitespace-nowrap"
                                    >
                                      {currentGoToSection ? "Change" : "Set"}
                                    </button>
                                  </div>
                                </div>
                              );
                            })}
                          </div>

                          <button
                            type="button"
                            onClick={() =>
                              addOption(sectionIndex, questionIndex)
                            }
                            className="mt-3 flex items-center px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                          >
                            <Plus className="h-4 w-4 mr-1" />
                            Add Option
                          </button>

                          <div className="mt-2 text-xs text-gray-500">
                            💡 Tip: Each line becomes a selectable option for
                            your users
                          </div>

                          {/* Follow-up Questions */}
                          {question.followUpQuestions &&
                            question.followUpQuestions.length > 0 && (
