        {/* Footer - Sign Out */}
        {isAuthenticated && (
          <div className="absolute bottom-0 left-0 right-0 p-3">
            <button
              onClick={handleLogout}
              className={`
                group relative flex items-center w-full px-3 py-3 rounded-lg transition-all duration-200
