        )}
      </aside>
    </>
  );
}

import React, { useState, useEffect } from "react";
import {
  Eye,
  EyeOff,
  AlertCircle,
  CheckCircle,
  RefreshCw,
  Zap,
  ArrowRight,
} from "lucide-react";
import { apiClient } from "../../../api/client";
import type { SectionFlowConfig } from "../../../types/forms";

interface Section {
  id: string;
  title: string;
  questions?: any[];
}

interface FormFlowData {
  formId: string;
  title: string;
  allSections: Section[];
  visibleSections: Section[];
  sectionOrder: string[];
  config: SectionFlowConfig;
  linkedOnlyMode: boolean;
}

interface FormFlowVisualizerProps {
  formId: string;
  sections: Section[];
  config?: SectionFlowConfig;
  onConfigUpdate?: (config: SectionFlowConfig) => void;
}

export const FormFlowVisualizer: React.FC<FormFlowVisualizerProps> = ({
  formId,
  sections,
  config,
  onConfigUpdate,
}) => {
  const [flowData, setFlowData] = useState<FormFlowData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  useEffect(() => {
    loadFormFlow();
  }, [formId]);

  const loadFormFlow = async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await apiClient.calculateFormFlow(formId);
      setFlowData(data);
    } catch (err) {
      console.error("Error loading form flow:", err);
      setError("Failed to load form flow data");
    } finally {
      setLoading(false);
    }
  };

  const toggleLinkedOnlyMode = async () => {
    if (!flowData) return;

    try {
      setLoading(true);
      const newConfig = {
        ...flowData.config,
        linkedOnlyMode: !flowData.linkedOnlyMode,
      };

      await apiClient.setSectionFlowConfig(formId, newConfig);

      setFlowData((prev) => {
        if (!prev) return prev;
        return {
          ...prev,
          linkedOnlyMode: !prev.linkedOnlyMode,
          config: newConfig,
        };
      });

      setSuccess(
        `Linked only mode ${!flowData.linkedOnlyMode ? "enabled" : "disabled"}`
      );
      setTimeout(() => setSuccess(null), 3000);

      if (onConfigUpdate) {
        onConfigUpdate(newConfig);
      }
    } catch (err) {
      console.error("Error toggling linked only mode:", err);
      setError("Failed to update linked only mode");
    } finally {
      setLoading(false);
    }
  };

  if (loading && !flowData) {
    return (
      <div className="bg-white rounded-lg border border-gray-200 p-6 text-center">
        <div className="animate-spin inline-block h-8 w-8 text-blue-600 rounded-full border-4 border-gray-300 border-t-blue-600"></div>
        <p className="mt-2 text-gray-600">Loading form flow...</p>
      </div>
    );
  }

  if (!flowData) {
    return (
      <div className="bg-white rounded-lg border border-gray-200 p-6">
        <p className="text-gray-600">No form flow data available</p>
      </div>
    );
  }

  const allSectionIds = new Set(flowData.allSections.map((s) => s.id));
  const visibleSectionIds = new Set(flowData.visibleSections.map((s) => s.id));
  const hiddenSections = flowData.allSections.filter(
    (s) => !visibleSectionIds.has(s.id)
  );

  return (
    <div className="bg-white rounded-lg border border-gray-200 p-6">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-gray-900 mb-2 flex items-center gap-2">
          <Zap className="h-6 w-6 text-amber-500" />
          Form Flow Visualization
        </h2>
        <p className="text-gray-600">
          Preview which sections will be displayed to users based on your
          configuration.
        </p>
      </div>

      {error && (
        <div className="mb-4 p-4 bg-red-50 border border-red-200 rounded-lg flex gap-2">
          <AlertCircle className="h-5 w-5 text-red-600 flex-shrink-0" />
          <p className="text-red-700">{error}</p>
        </div>
      )}

      {success && (
        <div className="mb-4 p-4 bg-green-50 border border-green-200 rounded-lg flex gap-2">
          <CheckCircle className="h-5 w-5 text-green-600 flex-shrink-0" />
          <p className="text-green-700">{success}</p>
        </div>
      )}

      <div className="mb-8 p-4 bg-amber-50 border border-amber-200 rounded-lg">
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-2">
            {flowData.linkedOnlyMode ? (
              <Eye className="h-5 w-5 text-amber-600" />
            ) : (
              <EyeOff className="h-5 w-5 text-gray-400" />
            )}
            <span className="font-semibold text-gray-900">
              Linked Only Mode: {flowData.linkedOnlyMode ? "ON" : "OFF"}
            </span>
          </div>
          <button
            onClick={toggleLinkedOnlyMode}
            disabled={loading}
            className={`px-4 py-2 rounded-lg font-medium transition-colors disabled:opacity-50 ${
              flowData.linkedOnlyMode
                ? "bg-amber-600 text-white hover:bg-amber-700"
                : "bg-gray-300 text-gray-800 hover:bg-gray-400"
            }`}
          >
            {flowData.linkedOnlyMode ? "Disable" : "Enable"}
          </button>
        </div>
        <p className="text-sm text-gray-700">
          {flowData.linkedOnlyMode
            ? "Only linked sections are shown to users. Unlinked sections are hidden."
            : "All sections are shown to users in order. Links define optional branching paths."}
        </p>
      </div>

      <div className="mb-8">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">
          📊 Form Structure
        </h3>
        <div className="space-y-4">
          {flowData.allSections.map((section, index) => {
            const isVisible = visibleSectionIds.has(section.id);
            const isLinked = flowData.config.sectionLinks?.some(
              link => link.sourceSectionId === section.id || link.targetSectionId === section.id
            ) || false;

            return (
              <div key={section.id} className="flex items-start gap-4">
                {/* Section Number */}
                <div className={`flex-shrink-0 w-10 h-10 rounded-full flex items-center justify-center font-semibold ${
                  isVisible 
                    ? isLinked ? 'bg-blue-100 text-blue-700' : 'bg-green-100 text-green-700'
                    : 'bg-gray-200 text-gray-600'
                }`}>
                  {index + 1}
                </div>

                {/* Section Info */}
                <div className={`flex-1 p-3 rounded-lg border ${
                  isVisible
                    ? isLinked ? 'bg-blue-50 border-blue-200' : 'bg-green-50 border-green-200'
                    : 'bg-gray-100 border-gray-300 opacity-50'
                }`}>
                  <div className="flex items-center justify-between">
                    <div>
                      <p className={`font-medium ${isVisible ? 'text-gray-900' : 'text-gray-600'}`}>
                        {section.title}
                      </p>
                      <p className="text-xs text-gray-600">
                        {section.questions?.length || 0} questions
                      </p>
                    </div>
                    <div className="flex items-center gap-2">
                      {isVisible && (
                        <span className="text-xs font-medium px-2 py-1 rounded-full bg-green-100 text-green-700">
                          ✓ Visible
                        </span>
                      )}
                      {isLinked && flowData.linkedOnlyMode && (
                        <span className="text-xs font-medium px-2 py-1 rounded-full bg-blue-100 text-blue-700">
                          🔗 Linked
                        </span>
                      )}
                      {!isVisible && (
                        <span className="text-xs font-medium px-2 py-1 rounded-full bg-gray-200 text-gray-600">
                          ✗ Hidden
                        </span>
                      )}
                    </div>
                  </div>
                </div>

                {/* Arrow */}
                {index < flowData.allSections.length - 1 && isVisible && (
                  <div className="flex-shrink-0 flex items-center h-10">
                    <ArrowRight className="h-4 w-4 text-green-500" />
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {flowData.config.sectionLinks && flowData.config.sectionLinks.length > 0 && (
        <div className="mb-8">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">
            Active Section Links ({flowData.config.sectionLinks.length})
          </h3>
          <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 space-y-3">
            {flowData.config.sectionLinks.map((link, index) => {
              const sourceSection = flowData.allSections.find(
                (s) => s.id === link.sourceSectionId
              );
              const targetSection = flowData.allSections.find(
                (s) => s.id === link.targetSectionId
              );

              return (
                <div key={index} className="flex items-center gap-2 text-sm">
                  <span className="font-medium text-gray-900">
                    {sourceSection?.title}
                  </span>
                  <ArrowRight className="h-4 w-4 text-blue-600" />
                  <span className="font-medium text-gray-900">
                    {targetSection?.title}
                  </span>
                  {link.linkedByOptionId && (
                    <span className="ml-auto text-xs bg-blue-100 text-blue-800 px-2 py-1 rounded">
                      if: {link.linkedByOptionId}
                    </span>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}

      <div className="flex gap-3">
        <button
          onClick={loadFormFlow}
          disabled={loading}
          className="flex items-center justify-center gap-2 px-6 py-2 bg-gray-300 text-gray-800 rounded-lg hover:bg-gray-400 font-medium disabled:opacity-50"
        >
          <RefreshCw className="h-4 w-4" />
          Refresh Flow
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from "react";
import {
  ChevronDown,
  ChevronUp,
  Link2,
  Eye,
  AlertCircle,
  CheckCircle,
  Loader,
} from "lucide-react";
import { apiClient } from "../../../api/client";
import { SectionLinkManager } from "./SectionLinkManager";
import { FormFlowVisualizer } from "./FormFlowVisualizer";
import type { SectionFlowConfig } from "../../../types/forms";

interface Section {
  id: string;
  title: string;
  questions?: any[];
}

interface FormSectionLinkingSettingsProps {
  formId: string;
  formTitle?: string;
  sections?: Section[];
}

export const FormSectionLinkingSettings: React.FC<
  FormSectionLinkingSettingsProps
> = ({ formId, formTitle, sections: initialSections }) => {
  const [sections, setSections] = useState<Section[]>(initialSections || []);
  const [config, setConfig] = useState<SectionFlowConfig | null>(null);
  const [activeTab, setActiveTab] = useState<"manage" | "preview">("manage");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [expandedSection, setExpandedSection] = useState<string | null>("manage");

  useEffect(() => {
    loadFormData();
  }, [formId]);

  const loadFormData = async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await apiClient.getFormById(formId);
      if (data.form) {
        setSections(data.form.sections || []);
      }
    } catch (err) {
      console.error("Error loading form data:", err);
      setError("Failed to load form data");
    } finally {
      setLoading(false);
    }
  };

  const handleConfigSaved = (newConfig: SectionFlowConfig) => {
    setConfig(newConfig);
    setError(null);
  };

  const toggleSection = (section: string) => {
    setExpandedSection(expandedSection === section ? null : section);
  };

  if (loading) {
    return (
      <div className="bg-white rounded-lg border border-gray-200 p-8 text-center">
        <Loader className="animate-spin h-8 w-8 text-blue-600 mx-auto" />
        <p className="mt-3 text-gray-600">Loading section linking settings...</p>
      </div>
    );
  }

  if (!sections || sections.length === 0) {
    return (
      <div className="bg-white rounded-lg border border-gray-200 p-6">
        <div className="text-center py-8">
          <AlertCircle className="h-12 w-12 text-gray-300 mx-auto mb-4" />
          <p className="text-gray-600">
            No sections found in this form. Create sections first before setting up links.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {error && (
        <div className="p-4 bg-red-50 border border-red-200 rounded-lg flex gap-2">
          <AlertCircle className="h-5 w-5 text-red-600 flex-shrink-0" />
          <p className="text-red-700">{error}</p>
        </div>
      )}

      <div className="bg-white rounded-lg border border-gray-200">
        <button
          onClick={() => toggleSection("info")}
          className="w-full px-6 py-4 flex items-center justify-between hover:bg-gray-50 border-b border-gray-200"
        >
          <h3 className="text-lg font-semibold text-gray-900">
            Section Linking Configuration
          </h3>
          {expandedSection === "info" ? (
            <ChevronUp className="h-5 w-5 text-gray-600" />
          ) : (
            <ChevronDown className="h-5 w-5 text-gray-600" />
          )}
        </button>

        {expandedSection === "info" && (
          <div className="p-6 bg-blue-50 border-t border-gray-200">
            <p className="text-sm text-blue-800">
              <strong>Form:</strong> {formTitle || formId}
            </p>
            <p className="text-sm text-blue-800 mt-2">
              <strong>Sections:</strong> {sections.length} section
              {sections.length !== 1 ? "s" : ""} available
            </p>
            <p className="text-sm text-blue-700 mt-3">
              Use section linking to create conditional form flows where specific questions
              and answers determine which sections users see next. Enable "Linked Only Mode"
              to show only sections that are part of links.
            </p>
          </div>
        )}
      </div>

      <div className="bg-white rounded-lg border border-gray-200">
        <div className="flex border-b border-gray-200">
          <button
            onClick={() => setActiveTab("manage")}
            className={`flex-1 px-6 py-4 text-center font-medium transition-colors ${
              activeTab === "manage"
                ? "text-blue-600 border-b-2 border-blue-600"
                : "text-gray-600 hover:text-gray-900"
            }`}
          >
            <div className="flex items-center justify-center gap-2">
              <Link2 className="h-4 w-4" />
              Manage Links
            </div>
          </button>
          <button
            onClick={() => setActiveTab("preview")}
            className={`flex-1 px-6 py-4 text-center font-medium transition-colors ${
              activeTab === "preview"
                ? "text-blue-600 border-b-2 border-blue-600"
                : "text-gray-600 hover:text-gray-900"
            }`}
          >
            <div className="flex items-center justify-center gap-2">
              <Eye className="h-4 w-4" />
              Preview Flow
            </div>
          </button>
        </div>

        <div className="p-6">
          {activeTab === "manage" ? (
            <SectionLinkManager
              formId={formId}
              sections={sections}
              onConfigSaved={handleConfigSaved}
            />
          ) : (
            <FormFlowVisualizer
              formId={formId}
              sections={sections}
              config={config}
              onConfigUpdate={handleConfigSaved}
            />
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from "react";
import type { Role } from "../../../types";
import RoleList from "./roles/RoleList";
import RoleForm from "./roles/RoleForm";
import { rolesApi } from "../../../api/roles";
import { useNotification } from "../../../context/NotificationContext";

export default function RoleManagement() {
  const [roles, setRoles] = useState<Role[]>([]);
  const [editingRole, setEditingRole] = useState<Role | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const { showSuccess, showError, showConfirm } = useNotification();

  // Load roles on component mount
  useEffect(() => {
    loadRoles();
  }, []);

  const loadRoles = async () => {
    try {
      setLoading(true);
      setError(null);
      const rolesData = await rolesApi.getAll();
      setRoles(rolesData);
    } catch (err) {
      console.error("Failed to load roles:", err);
      setError("Failed to load roles. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleAddRole = async (roleData: Omit<Role, "id">) => {
    try {
      setError(null);
      const newRole = await rolesApi.save(roleData as Role);
      setRoles([...roles, newRole]);
      showSuccess("Role created successfully", "Success");
    } catch (err: any) {
      console.error("Failed to create role:", err);
      const errorMsg =
        err.message || "Failed to create role. Please try again.";
      setError(errorMsg);
      showError(errorMsg, "Error");
    }
  };

  const handleUpdateRole = async (updatedRole: Role) => {
    try {
      setError(null);
      const savedRole = await rolesApi.save(updatedRole);
      setRoles(
        roles.map((role) => (role.id === updatedRole.id ? savedRole : role))
      );
      setEditingRole(null);
      showSuccess("Role updated successfully", "Success");
    } catch (err: any) {
      console.error("Failed to update role:", err);
      const errorMsg =
        err.message || "Failed to update role. Please try again.";
      setError(errorMsg);
      showError(errorMsg, "Error");
    }
  };

  const handleDeleteRole = async (id: string) => {
    showConfirm(
      "Are you sure you want to delete this role? This action cannot be undone.",
      async () => {
        try {
          setError(null);
          await rolesApi.delete(id);
          setRoles(roles.filter((role) => role.id !== id));
          showSuccess("Role deleted successfully", "Success");
        } catch (err: any) {
          console.error("Failed to delete role:", err);
          const errorMsg =
            err.message || "Failed to delete role. Please try again.";
          setError(errorMsg);
          showError(errorMsg, "Error");
        }
      },
      "Delete Role",
      "Delete",
      "Cancel"
    );
  };

  return (
    <div className="space-y-6">
      <div className="border-b border-gray-200 pb-4">
        <h3 className="text-lg font-medium text-gray-900">Role Management</h3>
        <p className="text-sm text-gray-500 mt-1">
          Create and manage roles to control access to system features
        </p>
      </div>

      {error && (
        <div className="bg-red-50 border border-red-200 rounded-md p-4">
          <div className="flex">
            <div className="ml-3">
              <h3 className="text-sm font-medium text-red-800">Error</h3>
              <div className="mt-2 text-sm text-red-700">
                <p>{error}</p>
              </div>
              <div className="mt-3">
                <button
                  type="button"
                  onClick={loadRoles}
                  className="bg-red-100 px-3 py-1 text-sm font-medium text-red-800 rounded-md hover:bg-red-200"
                >
                  Retry
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-6">
        <div>
          <h4 className="text-md font-medium text-gray-900 mb-4">
            {editingRole ? "Edit Role" : "Create New Role"}
          </h4>
          {editingRole ? (
            <RoleForm
              initialData={editingRole}
              onSubmit={(roleData) =>
                handleUpdateRole({ ...roleData, id: editingRole.id })
              }
            />
          ) : (
            <RoleForm onSubmit={handleAddRole} />
          )}
        </div>

        <div>
          <h4 className="text-md font-medium text-gray-900 mb-4">
            Existing Roles
          </h4>
          {loading ? (
            <div className="flex justify-center py-8">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-600"></div>
            </div>
          ) : (
            <RoleList
              roles={roles}
              onDeleteRole={handleDeleteRole}
              onEditRole={setEditingRole}
            />
          )}
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from "react";
import {
  Plus,
  Trash2,
  Link2,
  AlertCircle,
  CheckCircle,
  X,
  ChevronDown,
  ChevronUp,
  Save,
  RefreshCw,
} from "lucide-react";
import { apiClient } from "../../../api/client";
import type { SectionLink, OptionToSectionMapping, SectionFlowConfig } from "../../../types/forms";

interface SectionQuestion {
  id: string;
  text: string;
  type: string;
  options?: string[];
}

interface FormSection {
  id: string;
  title: string;
  questions: SectionQuestion[];
}

interface SectionLinkManagerProps {
  formId: string;
  sections: FormSection[];
  onConfigSaved?: (config: SectionFlowConfig) => void;
}

export const SectionLinkManager: React.FC<SectionLinkManagerProps> = ({
  formId,
  sections,
  onConfigSaved,
}) => {
  const [config, setConfig] = useState<SectionFlowConfig>({
    linkedOnlyMode: false,
    sectionLinks: [],
    optionToSectionMap: [],
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [expandedLinks, setExpandedLinks] = useState<Set<number>>(new Set());
  const [newLinkSourceSection, setNewLinkSourceSection] = useState<string>("");
  const [newLinkSourceQuestion, setNewLinkSourceQuestion] = useState<string>("");
  const [newLinkOption, setNewLinkOption] = useState<string>("");
  const [newLinkTargetSection, setNewLinkTargetSection] = useState<string>("");

  useEffect(() => {
    loadConfig();
  }, [formId]);

  const loadConfig = async () => {
    try {
      setLoading(true);
      const data = await apiClient.getSectionFlowConfig(formId);
      if (data.sectionFlowConfig) {
        setConfig(data.sectionFlowConfig);
      }
    } catch (err) {
      console.error("Error loading section flow config:", err);
      setError("Failed to load section configuration");
    } finally {
      setLoading(false);
    }
  };

  const saveConfig = async () => {
    try {
      setLoading(true);
      setError(null);
      await apiClient.setSectionFlowConfig(formId, config);
      setSuccess("Section flow configuration saved successfully!");
      setTimeout(() => setSuccess(null), 3000);
      if (onConfigSaved) {
        onConfigSaved(config);
      }
    } catch (err) {
      console.error("Error saving section flow config:", err);
      setError("Failed to save configuration");
    } finally {
      setLoading(false);
    }
  };

  const addLink = () => {
    if (!newLinkSourceSection || !newLinkTargetSection) {
      setError("Please select source and target sections");
      return;
    }

    const newLink: SectionLink = {
      sourceSectionId: newLinkSourceSection,
      sourceQuestionId: newLinkSourceQuestion,
      targetSectionId: newLinkTargetSection,
      linkedByOptionId: newLinkOption || undefined,
    };

    setConfig((prev) => ({
      ...prev,
      sectionLinks: [...(prev.sectionLinks || []), newLink],
    }));

    if (newLinkSourceQuestion && newLinkOption) {
      const optionMapping: OptionToSectionMapping = {
        questionId: newLinkSourceQuestion,
        optionId: newLinkOption,
        targetSectionId: newLinkTargetSection,
      };
      setConfig((prev) => ({
        ...prev,
        optionToSectionMap: [...(prev.optionToSectionMap || []), optionMapping],
      }));
    }

    setNewLinkSourceSection("");
    setNewLinkSourceQuestion("");
    setNewLinkOption("");
    setNewLinkTargetSection("");
    setError(null);
  };

  const removeLink = (index: number) => {
    setConfig((prev) => ({
      ...prev,
      sectionLinks: prev.sectionLinks?.filter((_, i) => i !== index) || [],
    }));
  };

  const toggleLinkExpanded = (index: number) => {
    setExpandedLinks((prev) => {
      const next = new Set(prev);
      if (next.has(index)) {
        next.delete(index);
      } else {
        next.add(index);
      }
      return next;
    });
  };

  const getSourceSection = (sectionId: string) =>
    sections.find((s) => s.id === sectionId);
  const getTargetSection = (sectionId: string) =>
    sections.find((s) => s.id === sectionId);
  const getQuestion = (sectionId: string, questionId: string) => {
    const section = sections.find((s) => s.id === sectionId);
    return section?.questions.find((q) => q.id === questionId);
  };

  const getSourceSectionQuestions = () => {
    if (!newLinkSourceSection) return [];
    const section = sections.find((s) => s.id === newLinkSourceSection);
    return section?.questions || [];
  };

  const getQuestionOptions = () => {
    if (!newLinkSourceQuestion) return [];
    const questions = getSourceSectionQuestions();
    const question = questions.find((q) => q.id === newLinkSourceQuestion);
    return question?.options || [];
  };

  return (
    <div className="bg-white rounded-lg border border-gray-200 p-6">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-gray-900 mb-2 flex items-center gap-2">
          <Link2 className="h-6 w-6 text-blue-600" />
          Section Linking Configuration
        </h2>
        <p className="text-gray-600">
          Link sections together to create conditional form flows based on user responses.
        </p>
      </div>

      {error && (
        <div className="mb-4 p-4 bg-red-50 border border-red-200 rounded-lg flex gap-2">
          <AlertCircle className="h-5 w-5 text-red-600 flex-shrink-0" />
          <p className="text-red-700">{error}</p>
        </div>
      )}

      {success && (
        <div className="mb-4 p-4 bg-green-50 border border-green-200 rounded-lg flex gap-2">
          <CheckCircle className="h-5 w-5 text-green-600 flex-shrink-0" />
          <p className="text-green-700">{success}</p>
        </div>
      )}

      <div className="mb-8 p-4 bg-blue-50 border border-blue-200 rounded-lg">
        <label className="flex items-center gap-3 cursor-pointer">
          <input
            type="checkbox"
            checked={config.linkedOnlyMode || false}
            onChange={(e) =>
              setConfig((prev) => ({
                ...prev,
                linkedOnlyMode: e.target.checked,
              }))
            }
            className="w-4 h-4 text-blue-600 rounded"
          />
          <span className="font-semibold text-gray-900">
            Linked Only Mode
          </span>
        </label>
        <p className="text-sm text-gray-600 ml-7 mt-2">
          When enabled, only sections that are part of links will be shown to users. This is useful for creating branching paths where only relevant sections appear.
        </p>
      </div>

      <div className="mb-8">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Add New Link</h3>
        <div className="bg-gray-50 p-4 rounded-lg space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Source Section
              </label>
              <select
                value={newLinkSourceSection}
                onChange={(e) => {
                  setNewLinkSourceSection(e.target.value);
                  setNewLinkSourceQuestion("");
                  setNewLinkOption("");
                }}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="">Select section...</option>
                {sections.map((section) => (
                  <option key={section.id} value={section.id}>
                    {section.title}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Target Section
              </label>
              <select
                value={newLinkTargetSection}
                onChange={(e) => setNewLinkTargetSection(e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="">Select section...</option>
                {sections
                  .filter((s) => s.id !== newLinkSourceSection)
                  .map((section) => (
                    <option key={section.id} value={section.id}>
                      {section.title}
                    </option>
                  ))}
              </select>
            </div>
          </div>

          {newLinkSourceSection && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Trigger Question (Optional)
                </label>
                <select
                  value={newLinkSourceQuestion}
                  onChange={(e) => {
                    setNewLinkSourceQuestion(e.target.value);
                    setNewLinkOption("");
                  }}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                >
                  <option value="">Any question in section</option>
                  {getSourceSectionQuestions().map((question) => (
                    <option key={question.id} value={question.id}>
                      {question.text.substring(0, 50)}...
                    </option>
                  ))}
                </select>
              </div>

              {newLinkSourceQuestion && (
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Trigger Option (Optional)
                  </label>
                  <select
                    value={newLinkOption}
                    onChange={(e) => setNewLinkOption(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  >
                    <option value="">Any answer</option>
                    {getQuestionOptions().map((option) => (
                      <option key={option} value={option}>
                        {option}
                      </option>
                    ))}
                  </select>
                </div>
              )}
            </div>
          )}

          <button
            onClick={addLink}
            className="w-full flex items-center justify-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 font-medium"
          >
            <Plus className="h-4 w-4" />
            Add Link
          </button>
        </div>
      </div>

      <div className="mb-8">
        <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
          🔗 Active Links ({config.sectionLinks?.length || 0})
        </h3>
        <div className="space-y-4">
          {config.sectionLinks && config.sectionLinks.length > 0 ? (
            config.sectionLinks.map((link, index) => {
              const sourceSection = getSourceSection(link.sourceSectionId);
              const targetSection = getTargetSection(link.targetSectionId);
              const question = link.sourceQuestionId
                ? getQuestion(link.sourceSectionId, link.sourceQuestionId)
                : null;

              return (
                <div
                  key={index}
                  className="border-2 border-blue-200 rounded-lg overflow-hidden bg-gradient-to-r from-blue-50 to-white"
                >
                  <button
                    onClick={() => toggleLinkExpanded(index)}
                    className="w-full px-4 py-4 hover:from-blue-100 flex items-center justify-between transition-colors"
                  >
                    <div className="text-left flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="font-semibold text-blue-900">
                          {sourceSection?.title}
                        </span>
                        <span className="text-blue-600 font-bold">→</span>
                        <span className="font-semibold text-blue-900">
                          {targetSection?.title}
                        </span>
                      </div>
                      {question && (
                        <p className="text-sm text-blue-700 ml-0">
                          📌 <span className="font-medium">Trigger:</span> {question.text.substring(0, 50)}
                          {question.text.length > 50 ? "..." : ""}
                        </p>
                      )}
                      {link.linkedByOptionId && (
                        <p className="text-xs text-blue-600 mt-1">
                          📍 When answer = <span className="font-semibold">"{link.linkedByOptionId}"</span>
                        </p>
                      )}
                    </div>
                    <div className="flex items-center gap-2 flex-shrink-0">
                      {expandedLinks.has(index) ? (
                        <ChevronUp className="h-5 w-5 text-blue-600" />
                      ) : (
                        <ChevronDown className="h-5 w-5 text-blue-600" />
                      )}
                    </div>
                  </button>

                  {expandedLinks.has(index) && (
                    <div className="px-4 py-4 bg-blue-50 border-t border-blue-200">
                      <div className="grid grid-cols-2 gap-4 text-sm mb-4">
                        <div className="bg-white p-3 rounded border border-blue-100">
                          <p className="text-xs font-semibold text-blue-600 mb-1">SOURCE</p>
                          <p className="font-medium text-gray-900">{sourceSection?.title}</p>
                          <p className="text-xs text-gray-600">ID: {link.sourceSectionId}</p>
                        </div>
                        <div className="bg-white p-3 rounded border border-blue-100">
                          <p className="text-xs font-semibold text-blue-600 mb-1">TARGET</p>
                          <p className="font-medium text-gray-900">{targetSection?.title}</p>
                          <p className="text-xs text-gray-600">ID: {link.targetSectionId}</p>
                        </div>
                      </div>

                      {link.sourceQuestionId && (
                        <div className="bg-white p-3 rounded border border-blue-100 mb-3">
                          <p className="text-xs font-semibold text-blue-600 mb-1">TRIGGER CONDITION</p>
                          <p className="text-sm text-gray-900">
                            Question: <span className="font-medium">{question?.text}</span>
                          </p>
                          <p className="text-xs text-gray-600 mt-1">ID: {link.sourceQuestionId}</p>
                          {link.linkedByOptionId && (
                            <p className="text-sm text-blue-700 mt-2 font-medium">
                              ✓ Answer must equal: <span className="text-blue-900">"{link.linkedByOptionId}"</span>
                            </p>
                          )}
                        </div>
                      )}

                      <button
                        onClick={() => removeLink(index)}
                        className="mt-3 flex items-center gap-2 px-3 py-2 text-red-600 hover:bg-red-50 rounded font-medium text-sm"
                      >
                        <Trash2 className="h-4 w-4" />
                        Remove Link
                      </button>
                    </div>
                  )}
                </div>
              );
            })
          ) : (
            <p className="text-gray-600 text-center py-6">
              No links created yet. Add links to create conditional section flows.
            </p>
          )}
        </div>
      </div>

      <div className="flex gap-3">
        <button
          onClick={saveConfig}
          disabled={loading}
          className="flex items-center justify-center gap-2 px-6 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 font-medium disabled:opacity-50"
        >
          <Save className="h-4 w-4" />
          {loading ? "Saving..." : "Save Configuration"}
        </button>

        <button
          onClick={loadConfig}
          disabled={loading}
          className="flex items-center justify-center gap-2 px-6 py-2 bg-gray-300 text-gray-800 rounded-lg hover:bg-gray-400 font-medium disabled:opacity-50"
        >
          <RefreshCw className="h-4 w-4" />
          Refresh
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from "react";
import {
  Plus,
  Search,
  UserCircle,
  Mail,
  Eye,
  Edit2,
  Trash2,
} from "lucide-react";
import type { StaffMember } from "../../../types";
import { staffApi } from "../../../api/storage";
import StaffForm from "./staff/StaffForm";
import { useNotification } from "../../../context/NotificationContext";

export default function StaffManagement() {
  const [staff, setStaff] = useState<StaffMember[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [showAddForm, setShowAddForm] = useState(false);
  const [selectedStaff, setSelectedStaff] = useState<StaffMember | null>(null);
  const { showSuccess, showError, showConfirm } = useNotification();

  useEffect(() => {
    const staffMembers = staffApi.getAll();
    setStaff(staffMembers);
  }, []);

  const handleAddStaff = (newStaff: Omit<StaffMember, "id">) => {
    try {
      const staffMember: StaffMember = {
        id: crypto.randomUUID(),
        ...newStaff,
      };
      staffApi.save(staffMember);
      setStaff([...staff, staffMember]);
      setShowAddForm(false);
      showSuccess("Staff member added successfully", "Success");
    } catch (error: any) {
      showError(error.message || "Failed to add staff member", "Error");
    }
  };

  const handleEditStaff = (member: StaffMember) => {
    setSelectedStaff(member);
  };

  const handleUpdateStaff = (updatedStaff: Omit<StaffMember, "id">) => {
    try {
      const updated = { ...updatedStaff, id: selectedStaff!.id };
      staffApi.save(updated);
      setStaff(staff.map((s) => (s.id === updated.id ? updated : s)));
      setSelectedStaff(null);
      showSuccess("Staff member updated successfully", "Success");
    } catch (error: any) {
      showError(error.message || "Failed to update staff member", "Error");
    }
  };

  const handleRemoveStaff = (id: string) => {
    showConfirm(
      "Are you sure you want to remove this staff member?",
      () => {
        try {
          staffApi.delete(id);
          setStaff(staff.filter((member) => member.id !== id));
          showSuccess("Staff member removed successfully", "Success");
        } catch (error: any) {
          showError(error.message || "Failed to remove staff member", "Error");
        }
      },
      "Remove Staff Member",
      "Remove",
      "Cancel"
    );
  };

  const filteredStaff = staff.filter(
    (member) =>
      member.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      member.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="border-b border-gray-200 pb-4">
        <h3 className="text-lg font-medium text-gray-900">Staff Management</h3>
        <p className="text-sm text-gray-500 mt-1">
          Manage staff members and their information
        </p>
      </div>

      {/* Search and Add Button */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="relative flex-1 w-full sm:max-w-xs">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
          <input
            type="text"
            placeholder="Search staff members..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 text-sm"
          />
        </div>
        <button
          onClick={() => setShowAddForm(true)}
          className="inline-flex items-center px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 transition-colors"
        >
          <Plus className="w-4 h-4 mr-2" />
          Add Staff Member
        </button>
      </div>

      {/* Staff Table */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Staff Member
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Contact Info
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Role
                </th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredStaff.map((member) => (
                <tr
                  key={member.id}
                  className="hover:bg-gray-50 transition-colors"
                >
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center">
                      {member.profilePic ? (
