export async function parseFormWorkbook(file: File) {
  const buffer = await file.arrayBuffer();
  const workbook = read(buffer, { type: "array" });

  const sheetNames = workbook.SheetNames;
  const firstSheet = workbook.Sheets[sheetNames[0]];

  if (!firstSheet) {
    throw new Error("Workbook must have at least one sheet");
  }

  const rawData = utils.sheet_to_json<Record<string, any>>(firstSheet, {
    defval: "",
  });

  if (rawData.length === 0) {
    throw new Error("Sheet is empty");
  }

  // Skip the first 3 rows (header, descriptions, separator)
  // Only process data starting from row 4
  const dataRows = rawData.slice(3);

  if (dataRows.length === 0) {
    throw new Error(
      "No data rows found. Please add content starting from row 4 (after the example header and descriptions)."
    );
  }

  return parseNewTemplateFormat(dataRows);
}

function parseNewTemplateFormat(
  rows: Record<string, any>[]
): Partial<Question> & { sections: Section[] } {
  const sectionsMap = new Map<string, Section>();
  const formTitle = rows[0]["Form Title"]?.toString().trim() || "Imported Form";
  let currentSectionNo: string | null = null;
  const sectionLinkMap = new Map<
    string,
    { questionId: string; option: string }
  >();
  const questionMap = new Map<string, FollowUpQuestion>();

  rows.forEach((row) => {
    const sectionNo = row["Section Number"]?.toString().trim();
    const sectionTitle = row["Section Title"]?.toString().trim();
    const sectionDesc = row["Section Description"]?.toString().trim();
    const questionText = row["Question"]?.toString().trim();
    const parentQuestionText = row["Parent Question"]?.toString().trim();

    if (!questionText) {
      return;
    }

    if (sectionNo) {
      currentSectionNo = sectionNo;
      if (!sectionsMap.has(sectionNo)) {
        sectionsMap.set(sectionNo, {
          id: generateId(),
          title: sectionTitle || `Section ${sectionNo}`,
          description: sectionDesc || "Section description",
          questions: [],
        });
      }
    }

    if (!currentSectionNo) {
      return;
    }

    const section = sectionsMap.get(currentSectionNo);
    if (!section) return;

    const questionDesc = row["Question Description"]?.toString().trim();
    const questionType = row["Question Type"]?.toString().trim() || "text";
    const requiredStr = row["Required"]?.toString().trim().toLowerCase();
    const required =
      requiredStr === "true" || requiredStr === "yes" || requiredStr === "1";
    const optionsStr = row["Options"]?.toString().trim() || "";
    const optionsNotes = row["Option Notes"]?.toString().trim() || "";
    const linkedSection = row["Section Navigation"]?.toString().trim();
    const followUpOption = row["Follow up Option"]?.toString().trim() || "Yes";
    const triggerOption = row["Option Number"]?.toString().trim();
    const correctAnswer = row["Correct Answer"]?.toString().trim();
    const correctAnswersStr = row["Correct Answers"]?.toString().trim();
    const correctAnswers = correctAnswersStr
      ? correctAnswersStr
          .split("|")
          .map((ans) => ans.trim())
          .filter(Boolean)
      : undefined;

    const options = optionsStr
      ? optionsStr
          .split(",")
          .map((opt) => opt.trim())
          .filter(Boolean)
      : undefined;

    // Parse section branching for each option
    const branchingRules: Array<{
      optionLabel: string;
      targetSectionId: string;
    }> = [];

    if (options && options.length > 0) {
      options.forEach((option, index) => {
        const optionNumber = index + 1;
        const sectionColumn = `Option ${optionNumber} →`;
        const targetSection = row[sectionColumn]?.toString().trim();

        if (targetSection && targetSection !== "") {
          // Find the target section by title or number
          let targetSectionId = null;

          // First try to find by section number
          if (/^\d+$/.test(targetSection)) {
            const sectionNo = parseInt(targetSection);
            const targetSectionObj = Array.from(sectionsMap.values()).find(
              (s) =>
                s.title === `Section ${sectionNo}` ||
                s.title.includes(`Section ${sectionNo}`)
            );
            if (targetSectionObj) {
              targetSectionId = targetSectionObj.id;
            }
          }

          // If not found by number, try to find by title
          if (!targetSectionId) {
            const targetSectionObj = Array.from(sectionsMap.values()).find(
              (s) => s.title.toLowerCase() === targetSection.toLowerCase()
            );
            if (targetSectionObj) {
              targetSectionId = targetSectionObj.id;
            }
          }

          // If still not found, create a new section with the specified title
          if (!targetSectionId) {
            const newSectionId = generateId();
            sectionsMap.set(sectionsMap.size + 1, {
              id: newSectionId,
              title: targetSection,
              description: `Auto-created section for branching`,
              questions: [],
            });
            targetSectionId = newSectionId;
          }

          if (targetSectionId) {
            branchingRules.push({
              optionLabel: option,
              targetSectionId: targetSectionId,
            });
          }
        }
      });
    }

    const questionId = generateId();
    const question: FollowUpQuestion = {
      id: questionId,
      text: questionText,
      type: questionType as FollowUpQuestion["type"],
      required: required,
      options: options || undefined,
      description: questionDesc || optionsNotes || undefined,
      followUpQuestions: [],
      sectionId: section.id,
      branchingRules: branchingRules.length > 0 ? branchingRules : undefined,
      correctAnswer: correctAnswer || undefined,
      correctAnswers: correctAnswers,
    };

    // If this is a followup question
    if (parentQuestionText) {
      const parentQuestion = questionMap.get(parentQuestionText);
      if (parentQuestion && triggerOption) {
        question.showWhen = {
          questionId: parentQuestion.id,
          value: triggerOption,
        };
        parentQuestion.followUpQuestions.push(question);
      }
    } else {
      // Regular question
      section.questions.push(question);
      questionMap.set(questionText, question);
    }

    if (linkedSection) {
      const links = linkedSection.split(",").map((s) => s.trim());
      links.forEach((link) => {
        const [sectionNo, option] = link.split(":").map((s) => s.trim());
        sectionLinkMap.set(sectionNo, {
          questionId,
          option: option || followUpOption,
        });
      });
    }
  });

  const sections = Array.from(sectionsMap.values());

  sectionLinkMap.forEach((linkInfo, targetSectionNo) => {
    const targetSectionIdx = parseInt(targetSectionNo) - 1;
    if (targetSectionIdx >= 0 && targetSectionIdx < sections.length) {
      const targetSection = sections[targetSectionIdx];
      if ((targetSection as any).linkedToQuestionId === undefined) {
        (targetSection as any).linkedToQuestionId = linkInfo.questionId;
        (targetSection as any).linkedToOption = linkInfo.option;
      }
    }
  });

  const formPayload: Partial<Question> & { sections: Section[] } = {
    id: generateId(),
    title: formTitle,
    description: "Imported form from Excel template",
    isVisible: true,
    sections,
    followUpQuestions: [],
  };

  return formPayload;
}

/**
 * Utility to migrate legacy question types in localStorage
 * This should be run once when the app loads to fix any cached forms
 */

interface Question {
  id: string;
  type: string;
  [key: string]: any;
}

interface Form {
  id: string;
  sections?: Array<{
    questions?: Question[];
  }>;
  questions?: Question[];
  followUpQuestions?: Question[];
  [key: string]: any;
}

const LEGACY_TYPE_MAP: Record<string, string> = {
  select: "search-select",
  textarea: "paragraph",
};

/**
 * Recursively migrate question types in a question object
 */
function migrateQuestion(question: Question): boolean {
  let changed = false;

  // Migrate the question type if it's a legacy type
  if (question.type && LEGACY_TYPE_MAP[question.type]) {
    console.log(
      `Migrating question "${question.id}": ${question.type} -> ${
        LEGACY_TYPE_MAP[question.type]
      }`
    );
    question.type = LEGACY_TYPE_MAP[question.type];
    changed = true;
  }

  // Recursively migrate follow-up questions
  if (question.followUpQuestions && Array.isArray(question.followUpQuestions)) {
    for (const followUp of question.followUpQuestions) {
      if (migrateQuestion(followUp)) {
        changed = true;
      }
    }
  }

  return changed;
}

/**
 * Migrate a single form object
 */
function migrateForm(form: Form): boolean {
  let changed = false;

  // Migrate questions in sections
  if (form.sections && Array.isArray(form.sections)) {
    for (const section of form.sections) {
      if (section.questions && Array.isArray(section.questions)) {
        for (const question of section.questions) {
          if (migrateQuestion(question)) {
            changed = true;
          }
        }
      }
    }
  }

  // Migrate top-level questions (legacy structure)
  if (form.questions && Array.isArray(form.questions)) {
    for (const question of form.questions) {
      if (migrateQuestion(question)) {
        changed = true;
      }
    }
  }

  // Migrate top-level follow-up questions
  if (form.followUpQuestions && Array.isArray(form.followUpQuestions)) {
    for (const question of form.followUpQuestions) {
      if (migrateQuestion(question)) {
        changed = true;
      }
    }
  }

  return changed;
}

/**
 * Migrate all forms in localStorage
 */
export function migrateLocalStorageForms(): void {
  try {
    console.log("🔄 Checking localStorage for legacy question types...");

    let totalMigrated = 0;

    // Migrate 'form_questions' key
    const questionsData = localStorage.getItem("form_questions");
    if (questionsData) {
      try {
        const questions = JSON.parse(questionsData);
        if (Array.isArray(questions)) {
          let changed = false;
          for (const form of questions) {
            if (migrateForm(form)) {
              changed = true;
              totalMigrated++;
            }
          }
          if (changed) {
            localStorage.setItem("form_questions", JSON.stringify(questions));
            console.log(
              `✅ Migrated ${totalMigrated} forms in 'form_questions'`
            );
          }
        }
      } catch (e) {
        console.error("Error migrating form_questions:", e);
      }
    }

    // Migrate 'forms' key
    const formsData = localStorage.getItem("forms");
    if (formsData) {
      try {
        const forms = JSON.parse(formsData);
        if (Array.isArray(forms)) {
          let changed = false;
          for (const form of forms) {
            if (migrateForm(form)) {
              changed = true;
              totalMigrated++;
            }
          }
          if (changed) {
            localStorage.setItem("forms", JSON.stringify(forms));
            console.log(`✅ Migrated ${totalMigrated} forms in 'forms'`);
          }
        }
      } catch (e) {
        console.error("Error migrating forms:", e);
      }
    }

    if (totalMigrated > 0) {
      console.log(`✅ Migration complete! ${totalMigrated} forms updated.`);
    } else {
      console.log("✅ No legacy question types found in localStorage.");
    }
  } catch (error) {
    console.error("❌ Error during localStorage migration:", error);
  }
}

/**
 * Clear all form-related data from localStorage
 * Use this as a last resort if migration fails
 */
export function clearFormCache(): void {
  console.log("🗑️ Clearing form cache from localStorage...");
  localStorage.removeItem("form_questions");
  localStorage.removeItem("forms");
  console.log("✅ Form cache cleared!");
}

import generator from 'generate-password';

export function generateUserId(): string {
  const prefix = 'USER';
  const randomNum = Math.floor(10000 + Math.random() * 90000);
  return `${prefix}${randomNum}`;
}

export function generateSecurePassword(): string {
  try {
    return generator.generate({
      length: 12,
      numbers: true,
      symbols: true,
      uppercase: true,
      lowercase: true,
      strict: true,
      excludeSimilarCharacters: true,
    });
  } catch (error) {
    // Fallback password generation if the package fails
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789!@#$%^&*';
    let password = '';
    for (let i = 0; i < 12; i++) {
      password += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return password;
  }
}
